"use strict";
module.exports = JSON.parse('[{"id":0,"name":"Barbell Curl","equipment":"Barbell","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["Underhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-curl-front.mp4#t=0.1","howTo":"While holding the upper arms stationary, curl the weights forward while contracting the biceps as you breathe out. Continue the movement until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a second and squeeze the biceps hard. Slowly bring the weight back down to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":8},{"id":1,"name":"Dumbbell Curl","equipment":"Dumbbell","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["Underhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-curl-front.mp4#t=0.1","howTo":"Stand up straight with a dumbbell in each hand at arm\'s length. Raise one dumbbell and twist your forearm until it is vertical and your palm faces the shoulder. Lower to original position and repeat with opposite arm","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":2},{"id":2,"name":"Dumbbell Hammer Curl","equipment":"Dumbbell","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-hammer-curl-front.mp4#t=0.1","howTo":"Hold the dumbbells with a neutral grip (thumbs facing the ceiling). Slowly lift the dumbbell up to chest height Return to starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":3},{"id":3,"name":"Kettlebell Goblet Curl","equipment":"Kettlebell","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-goblet-curl-front.mp4#t=0.1","howTo":"Stand up straight with a kettlebell in both hands in front of your pelvis. Raise the kettlebell bending your arms at the elbow until the kettlebell is level with your chest. Lower to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":4,"name":"Kettlebell Concentration Curl","equipment":"Kettlebell","primaryMuscles":["Biceps"],"difficulty":"Intermediate","grips":["Underhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-concentration-curl-front.mp4#t=0.1","howTo":"Sitting on a chair with your legs apart, rest your arm against your thigh and hold the kettlebell with your arm extended towards the floor. Bending your arm at the elbow, lift the kettlebell until your palm faces your shoulder. Lower to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":5,"name":"Kettlebell Preacher Curl","equipment":"Kettlebell","primaryMuscles":["Biceps"],"difficulty":"Intermediate","grips":["Underhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-preacher-curl-front.mp4#t=0.1","howTo":"Stand behind a bench, with your chest leaning over the edge of the bench. With one arm resting on the bench, hold the kettlebell, bending the arm at the elbow. Lower your arm using the bench as a guide, keeping your forearm straight. Return to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":6,"name":"Kettlebell Single Arm Curl","equipment":"Kettlebell","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":"Underhand","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-single-arm-curl-front.mp4#t=0.1","howTo":"Stand up straight with a kettlebell in one hand with your forearm facing out. Raise the kettlebell, bending your arm at the elbow and keeping your forearm vertical until your palm faces the shoulder. Lower to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":7,"name":"Biceps Stretch Variation Five","equipment":"Stretch","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-biceps-stretch-variation-5-front.mp4#t=0.1","howTo":"Stand upright with your feet shoulder width apart. Raise your arms out to your sides, bringing them up to shoulder level. Rotate your palms so they are facing the ceiling. Then, change direction and rotate the arms as much as you can.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":8,"name":"Biceps Stretch Variation Four","equipment":"Stretch","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-biceps-stretch-variation-4-front.mp4#t=0.1","howTo":"Stand an arms width away from the wall. Raise your arms out behind you, and place them on the wall with your fingers pointing up. Bend your knees whilst keeping your hands in the same position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":9,"name":"Biceps Stretch Variation Three","equipment":"Stretch","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-biceps-stretch-variation-3-front.mp4#t=0.1","howTo":"Bend your arm at the elbow, raising your hand to your shoulder. Using your other hand, stretch the arm down to its full extent.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":10,"name":"Biceps Stretch Variation Two","equipment":"Stretch","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-biceps-stretch-variation-2-front.mp4#t=0.1","howTo":"Stand facing the wall, an arm\'s width away. Place your hand on the wall with your fingers pointing down. Lean slightly into the wall to feel the stretch in your bicep.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":11,"name":"Biceps Stretch Variation One","equipment":"Stretch","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-biceps-stretch-variation-1-front.mp4#t=0.1","howTo":"Stand one foot in front of the other with the wall to your right, an arms width away. Place your hand on the wall, fingers pointing away from you. Gently lean forward, keeping your hand stationary. Repeat with the other arm.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":12,"name":"Cable Twisting Curl","equipment":"Cable","primaryMuscles":["Biceps"],"difficulty":"Advanced","grips":"Underhand","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-twisting-curl-front.mp4#t=0.1","howTo":"Use a handle attachment. The cable should be set all the way to the bottom of the machine. Face away from the cable machine. Stagger your stance so you have a better base of support. Start with a neutral grip. Flex at the elbow. While flexing twist your palm. When you hit the top of the movement your palm should be facing upward.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":13,"name":"Cable Bayesian Curl","equipment":"Cable","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["Underhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-bayesian-curl-front.mp4#t=0.1","howTo":"Use a handle attachment. The cable should be set all the way to the bottom of the machine. Face away from the cable machine. Stagger your stance so you have a better base of support. Face your palm forward. Flex at the elbow and extend.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":14,"name":"Cable Reverse Curl","equipment":"Cable","primaryMuscles":["Biceps"],"difficulty":"Intermediate","grips":"Overhand","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-reverse-curl-front.mp4#t=0.1","howTo":"Use a handle attachment. The cable should be set all the way to the bottom of the machine. Face away from the cable machine. Stagger your stance so you have a better base of support. Face your palm downwards. Flex at the elbow and extend.","secondaryMuscles":["Forearms"],"tertiaryMuscles":null,"popularity":1},{"id":15,"name":"Cable Hammer Curl","equipment":"Cable","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-hammer-curl-front.mp4#t=0.1","howTo":"Use a handle attachment. The cable should be set all the way to the bottom of the machine. Face away from the cable machine. Stagger your stance so you have a better base of support. Use a neutral grip thumb facing up pinky-facing down). Flex at the elbow and extend.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":16,"name":"Band Bayesian Curl","equipment":"Band","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":"Underhand","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-curl-front.mp4#t=0.1","howTo":"Attach band to a low anchor point. Point your palms straight forward. Flex your elbow until you feel your biceps contract. Then fully extend elbows.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":17,"name":"Band Bayesian Hammer Curl","equipment":"Band","primaryMuscles":["Biceps"],"difficulty":"Intermediate","grips":"Neutral","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-hammer-curl-front.mp4#t=0.1","howTo":"Attach band to a low anchor point. Use a neutral grip. Flex your elbow until you feel your biceps contract. Then fully extend elbows.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":18,"name":"Band Bayesian Reverse Curl","equipment":"Band","primaryMuscles":["Biceps"],"difficulty":"Intermediate","grips":"Overhand","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-reverse-curl-front.mp4#t=0.1","howTo":"Attach band to a low anchor point. . Point your palms toward your thighs. Flex your elbow until you feel your biceps contract. Then fully extend elbows.","secondaryMuscles":["Forearms"],"tertiaryMuscles":null,"popularity":0},{"id":19,"name":"Dumbbell Reverse Curl","equipment":"Dumbbell","primaryMuscles":["Biceps"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-reverse-curl-front.mp4#t=0.1","howTo":"Grab the dumbbells with a pronated (overhand) grip. You can do this exercise thumbless if it\'s more comfortable on your wrists. Flex at the elbows until your biceps touch your forearms. Try not to let your elbows flair outward.","secondaryMuscles":["Forearms"],"tertiaryMuscles":null,"popularity":1},{"id":20,"name":"Barbell Reverse Curl","equipment":"Barbell","primaryMuscles":["Biceps"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-reverse-curl-front.mp4#t=0.1","howTo":"Take a double overhand grip that\'s about shoulder width. Flex your elbows while keeping your elbows tucked in. Try not to let them flare out. Curl until your forearm presses into your bicep. Then fully extend your elbows at the bottom of each rep.","secondaryMuscles":["Forearms"],"tertiaryMuscles":null,"popularity":1},{"id":21,"name":"Dumbbell Incline Hammer Curl","equipment":"Dumbbell","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-incline-hammer-curl-front.mp4#t=0.1","howTo":"Hold the dumbbells with a neutral grip (thumbs facing the ceiling). Seated on an incline bench. Slowly lift the dumbbell up to chest height Return to starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":22,"name":"Dumbbell Incline Reverse Curl","equipment":"Dumbbell","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-incline-reverse-curl-front.mp4#t=0.1","howTo":"Lay on an incline bench. Grab the dumbbells with a pronated (overhand) grip. You can do this exercise thumbless if it\'s more comfortable on your wrists. Flex at the elbows until your biceps touch your forearms. Try not to let your elbows flair outward.","secondaryMuscles":["Forearms"],"tertiaryMuscles":null,"popularity":0},{"id":23,"name":"Dumbbell Incline Zottman Curl","equipment":"Dumbbell","primaryMuscles":["Biceps"],"difficulty":"Intermediate","grips":["Rotating"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-incline-zottman-curl-front.mp4#t=0.1","howTo":"Lay on an incline bench with your palms facing forward. Flex at the elbows until your forearms touch your biceps. When you hit the top of the movement, rotate your palms and then lower the dumbbells slowly.","secondaryMuscles":["Forearms"],"tertiaryMuscles":null,"popularity":0},{"id":24,"name":"Dumbbell Single Arm Preacher Curl","equipment":"Dumbbell","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["Underhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-single-arm-preacher-curl-front.mp4#t=0.1","howTo":"Start with a with a dumbbell in one hand and your elbow resting on the bench. From this starting position, curl the dumbbell up towards your shoulder, keeping your upper arm stationary on the bench.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":25,"name":"Dumbbell Single Arm Spider Curl","equipment":"Dumbbell","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["Underhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-single-arm-spider-curl-front.mp4#t=0.1","howTo":"Lay on an incline or preacher curl bench. Let your arms hang freely off the edge of the bench. Fully flex your elbow and fully extend your elbow on each rep.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":26,"name":"Dumbbell Spider Curl","equipment":"Dumbbell","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["Underhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-spider-curl-front.mp4#t=0.1","howTo":"Start by placing your forearms on a flat bench and holding a dumbbell in each hand. From this starting position, curl the dumbbells up towards your shoulders, keeping your elbows close to your body and your core engaged. Slowly lower the dumbbells back down to the starting position, and repeat for the desired number of repetitions.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":27,"name":"Dumbbell Twisting Curl","equipment":"Dumbbell","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["Rotating"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-twisting-curl-front.mp4#t=0.1","howTo":"Start by standing with your feet shoulder-width apart and holding a dumbbell in each hand. Bring the dumbbells to your sides, with your palms facing inward and your elbows bent. From this starting position, curl the dumbbells up towards your shoulders while rotating your wrists so that your palms face your shoulders at the top of the movement.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":28,"name":"Plate Bicep Curl","equipment":"Plate","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-bicep-curl-front.mp4#t=0.1","howTo":"Slowly curl the plate towards your shoulders, keeping your elbows close to your body. Hold for a moment at the top of the curl before lowering the plate back to chest height.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":29,"name":"Plate Curl To Overhead Press","equipment":"Plate","primaryMuscles":["Biceps","Shoulders"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-curl-to-overhead-press-front_kQDPle2.mp4#t=0.1","howTo":"Stand with feet shoulder-width apart and the plate in front of the torso, palms facing forward. Curl the plate up to the front of the shoulder while keeping the elbows close to the body. Rotate the palms to face forward and press the plate overhead, locking out the arms. Lower the plate back to the starting position, keeping control of it, and repeat for desired reps.","secondaryMuscles":["Shoulders"],"tertiaryMuscles":null,"popularity":0},{"id":30,"name":"Plate Squat Hold Curl","equipment":"Plate","primaryMuscles":["Biceps","Quads"],"difficulty":"Intermediate","grips":"Neutral","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-squat-hold-curl-front.mp4#t=0.1","howTo":"Lower into a squat position, keeping the plate at chest height. Slowly curl the plate towards your shoulders, keeping your elbows close to your body. Hold for a moment at the top of the curl before lowering the plate back to chest height. Repeat the curls as you hold the squat position.","secondaryMuscles":["Quads","Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":31,"name":"Band High Curl","equipment":"Band","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["Underhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-high-curl-front.mp4#t=0.1","howTo":"Anchor a band to a high point. Start with your feet staggered and your elbows high. Flex your elbows while keeping your arms high. Curl the band to your forehead.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":32,"name":"Band High Hammer Curl","equipment":"Band","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-high-hammer-curl-front.mp4#t=0.1","howTo":"Start with the band anchored to something high with your feet staggered and a neutral grip. Keep your elbows high. Curl until your fists are at your forehead.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":33,"name":"Band High Reverse Curl","equipment":"Band","primaryMuscles":["Biceps"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-high-reverse-curl-front.mp4#t=0.1","howTo":"Start with a band attached to a high point, your feet staggered, and an overhand grip. Flex your elbows pulling your forearms to your biceps. Your fists should land by your forehead.","secondaryMuscles":["Forearms"],"tertiaryMuscles":null,"popularity":0},{"id":34,"name":"Band Curl","equipment":"Band","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["Underhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-curl-front_1YwVVEx.mp4#t=0.1","howTo":"Stand with your feet shoulder-width apart, with the band under both feet. Grasp the handles of the band with both hands, keeping your arms straight and extended in front of you. Keep your back straight, abs engaged, and shoulders relaxed as you curl your hands towards your shoulders, bending at the elbows.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":35,"name":"Band Reverse Curl","equipment":"Band","primaryMuscles":["Biceps"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-reverse-curl-front_iQSuy66.mp4#t=0.1","howTo":"Start by standing on the center of the band with both feet, shoulder-width apart. Hold the band with both hands, palms facing down, arms extended straight in front of you. Slowly curl your hands towards your shoulders, pulling the band tight, then lower your arms back to the starting position, keeping tension on the band throughout the exercise.","secondaryMuscles":["Forearms"],"tertiaryMuscles":null,"popularity":0},{"id":36,"name":"Dumbbell Concentration Curl","equipment":"Dumbbell","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["Underhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-concentration-curl-front.mp4#t=0.1","howTo":"Sit on a flat bench with your feet flat on the floor and your back straight. Lean forward and place your elbow on the inside of your leg. Curl the dumbbell while keeping your elbow against your leg. Make sure to fully extend your elbow on each rep.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":37,"name":"TRX Curl","equipment":"TRX","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":["Underhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-curl-front.mp4#t=0.1","howTo":"Hold the TRX straps with an underhand grip and lean back and away from the anchor point. Keep your elbows high as you flex your elbows. Pull your fists toward your forehead.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":38,"name":"TRX Hammer Curl","equipment":"TRX","primaryMuscles":["Biceps"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-hammer-curl-side.mp4#t=0.1","howTo":"Grab the TRX straps and lean away from the anchor point. Maintain a neutral grip. Flex your elbows and pull your fists to either sides of your temples.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":39,"name":"TRX Reverse Curl","equipment":"TRX","primaryMuscles":["Biceps"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-reverse-curl-front.mp4#t=0.1","howTo":"Stand facing the TRX straps and grasp the handles with both hands, palms facing away from your body. Walk back until the straps are taut, keeping your arms straight. Slowly curl your hands towards your shoulders, keeping your elbows close to your body.","secondaryMuscles":["Forearms"],"tertiaryMuscles":null,"popularity":0},{"id":40,"name":"Barbell Bench Press","equipment":"Barbell","primaryMuscles":["Chest"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-bench-press-front.mp4#t=0.1","howTo":"Lay flat on the bench with your feet on the ground. With straight arms unrack the bar. Lower the bar to your mid chest Raise the bar until you\'ve locked your elbows.","secondaryMuscles":["Triceps"],"tertiaryMuscles":["Shoulders"],"popularity":4},{"id":41,"name":"Dips","equipment":"Bodyweight","primaryMuscles":["Chest","Triceps"],"difficulty":"Intermediate","grips":"Overhand","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-dips-front.mp4#t=0.1","howTo":"Hold your body with arms locked above the equipment Lower your body slowly while leaning forward, flare out your elbows Raise your body above the bars until your arms are locked.","secondaryMuscles":["Triceps"],"tertiaryMuscles":["Shoulders"],"popularity":25},{"id":42,"name":"Dumbbell Incline Chest Flys","equipment":"Dumbbell","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-incline-chest-flys-front.mp4#t=0.1","howTo":"Lay flat on the bench and place your feet on the ground. Begin the exercise with the dumbbells held together above your chest, elbows slightly bent. Simultaneously lower the weights to either side. Pause when the weights are parallel to the bench, then raise your arms to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":43,"name":"Barbell Incline Bench Press","equipment":"Barbell","primaryMuscles":["Chest"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-incline-bench-press-front_dogC7vG.mp4#t=0.1","howTo":"Position the bench between 30 and 45 degrees. Lay flat on the bench with your feet on the ground. With straight arms unrack the bar. Lower the bar to your mid chest Raise the bar (slowly and controlled) until you\'ve locked your elbows.","secondaryMuscles":["Triceps","Shoulders"],"tertiaryMuscles":null,"popularity":1},{"id":44,"name":"Kettlebell Chest Press","equipment":"Kettlebell","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-chest-press-front.mp4#t=0.1","howTo":"Laying on the floor with your knees bent and feet firmly on the floor, hold the kettlebell at your chest with both hands. Fully extend your arms, raising the kettlebell until your elbows are locked. Lower the kettlebell to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":45,"name":"Kettlebell Single Arm Chest Fly","equipment":"Kettlebell","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":"Underhand","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-single-arm-chest-fly-front.mp4#t=0.1","howTo":"Lie on the floor with your knees bent and feet firmly on the floor, with your arms to the side of your body. Holding a kettlebell in one hand, keeping your arm fully extended with a slight bend in the elbow and your forearms facing upwards, lift the kettlebell above your chest. Lower the kettlebell to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":46,"name":"Kettlebell Single Arm Press","equipment":"Kettlebell","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":"Underhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-single-arm-chest-press-front.mp4#t=0.1","howTo":"Laying on the floor with your knees bent and feet firmly on the floor, leave one arm resting to the side of the body. Using the other arm, hold the kettlebell at arms length directly upwards of your shoulder. Lower your arm until your upper arm to elbow is resting on the floor. Return to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":47,"name":"Kettlebell Walkover Pushup","equipment":"Kettlebell","primaryMuscles":["Chest"],"difficulty":"Intermediate","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-walkover-pushup-front.mp4#t=0.1","howTo":"Starting in a press up position with feet wide and one hand resting on the kettlebell, complete a full press up, lowering your chest towards the ground while keeping your body straight and returning to the starting position. Swap hands on the kettlebell, placing the hand originally on the kettlebell underneath your shoulder, complete another press up. Repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":48,"name":"Chest Stretch Variation Four","equipment":"Stretch","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-chest-stretch-variation-4-front.mp4#t=0.1","howTo":"Raise your arms to shoulder height, fully extended in front of you. Slowly bring your arms behind your back still at shoulder height. Pause for a few seconds and then return to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":49,"name":"Chest Stretch Variation Three","equipment":"Stretch","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-chest-stretch-variation-3-front.mp4#t=0.1","howTo":"Place your arms behind your back and clasp your hands together. Slowly extend your elbows until they are locked then lift them away from you. Pause in this position for a few seconds and then return them to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":50,"name":"Chest Stretch Variation Two","equipment":"Stretch","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-chest-stretch-variation-2-front.mp4#t=0.1","howTo":"Lay on your side with one hand just in front of you. With a slight bend in your arm, rotate your arm around your body as slowly as possible. Return to the starting position and then repeat on the other side.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":51,"name":"Chest Stretch Variation One","equipment":"Stretch","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-chest-stretch-variation-1-front.mp4#t=0.1","howTo":"Using a raised wall, place your arm at a 90 degree angle against it. With a staggered stance, lean into the wall extending your chest. Pause for a few seconds and then return to starting position and repeat on opposite side.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":52,"name":"Push Up","equipment":"Bodyweight","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-pushup-front.mp4#t=0.1","howTo":"Place your hands firmly on the ground, directly under shoulders. Flatten your back so your entire body is straight and slowly lower your body Draw shoulder blades back and down, keeping elbows tucked close to your body Exhale as you push back to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":11},{"id":53,"name":"Incline Push Up","equipment":"Bodyweight","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-incline-pushup-front.mp4#t=0.1","howTo":"Stand facing bench or sturdy elevated platform. Place hands on edge of bench or platform, slightly wider than shoulder width. Slowly lower your body until your chest almost touches the bench. Push body up until arms are extended.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":54,"name":"Decline Push Up","equipment":"Bodyweight","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-decline-pushup-front.mp4#t=0.1","howTo":"Use a bench to elevate your feet. Put your hands slightly wider than shoulder-width. Slowly lower your body until your chest almost touches the ground Raise your body until you almost lock your elbows.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":3},{"id":55,"name":"Cable Pec Fly","equipment":"Cable","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-pec-fly-front.mp4#t=0.1","howTo":"Use a handle attachment set all the way to the bottom of the machine. Bring both of the handles to your chest and make sure you are in the center of the cable crossover. Walk a few steps forward. Then press the weight forward. From there, your shoulders should horizontally abduct and adduct while your elbows stay in a fixed position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":56,"name":"Cable Chest Press","equipment":"Cable","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-chestpress-front.mp4#t=0.1","howTo":"Use a handle attachment. The cables should be set to shoulder height. Bring both of the handles to your chest and make sure you are in the center of the cable crossover. Walk a few steps forward. Then press the weight forward. From there, you should flex and extend at both the shoulders and elbows simultaneously.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":1},{"id":57,"name":"Band Single Arm Pec Fly","equipment":"Band","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":"Underhand","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-chest-fly-front.mp4#t=0.1","howTo":"Attach the band to an anchor point that is about shoulder height. Take a few steps away until the band is taut. Extend your shoulder joint and bring your arm across your body until you feel a contraction in your pecs.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":58,"name":"Band Single Arm Chest Press","equipment":"Band","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":"Underhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-chest-press-front.mp4#t=0.1","howTo":"Attach the band to an anchor point that is about shoulder height. Take a few steps away until the band is taut. Extend your shoulder joint and elbow across your body until your arm is fully extended.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":59,"name":"Band Pushup","equipment":"Band","primaryMuscles":["Chest","Triceps"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-pushup-front.mp4#t=0.1","howTo":"Loop the band around your mid-back. The ends of the bands should be around your hands between your thumb and pointer finger. This exercise can be done from the knees or the toes depending on experience level. Begin by breaking at the elbows until your upper arm is by your side. Then extend at the elbows back into the top position.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":60,"name":"Barbell Floor Press","equipment":"Barbell","primaryMuscles":["Chest","Triceps"],"difficulty":"Advanced","grips":"Overhand","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-floor-press-front.mp4#t=0.1","howTo":"Un-rack the bar and break at the elbows and shoulders. Bring your elbows to the floor, rest for a second to remove all the momentum from the rep, then press to a lockout.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":1},{"id":61,"name":"Barbell Hooklying Bench Press","equipment":"Barbell","primaryMuscles":["Chest","Triceps"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-hooklying-bench-press-front.mp4#t=0.1","howTo":"Start in a bench press position with your feet planted on the bench and knees bent. Grasp the barbell with an overhand grip, positioning your hands slightly wider than shoulder-width apart. Lift the barbell off the rack and lower it to your chest, keeping your elbows close to your sides. Push the barbell back up to the starting position, fully extending your arms.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":62,"name":"Barbell Larsen Bench Press","equipment":"Barbell","primaryMuscles":["Chest","Triceps"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-larsen-bench-press-front.mp4#t=0.1","howTo":"Start in a bench press position with your legs elevated. Try to keep your knees with a slight bend in them. Unrack the bar then initiate the rep. Bring the bar to your torso and tap your ribcage before pressing back to the ceiling.","secondaryMuscles":["Triceps"],"tertiaryMuscles":["Abdominals"],"popularity":0},{"id":63,"name":"Barbell Spoto Press","equipment":"Barbell","primaryMuscles":["Chest","Triceps"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-spoto-press-front.mp4#t=0.1","howTo":"Start on the bench with your shoulder blades pulled back. As you initiate the first rep, tuck your elbows slightly until the bar is a few inches off your chest. Pause just off your chest for 1-3 seconds. Then press explosively.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":64,"name":"Dumbbell Bench Press","equipment":"Dumbbell","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":"Overhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-bench-press-front.mp4#t=0.1","howTo":"Lay flat on the bench with your feet on the ground. Raise the dumbbells until you have straight arms. Lower the dumbbells to your mid chest Raise the dumbbells until you\'ve locked your elbows.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":11},{"id":65,"name":"Dumbbell Chest Fly","equipment":"Dumbbell","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-chest-fly-front.mp4#t=0.1","howTo":"Lay on a bench with two dumbbells extended in front of you. You should have a slight bend in your elbows and maintain that bend. Your shoulder joint should do all the movement. Bring the dumbbells out to your side. Stop the dumbbells before going behind your body. Bring the dumbbells back together at the top.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":2},{"id":66,"name":"Dumbbell Decline Alternating Single Arm Press","equipment":"Dumbbell","primaryMuscles":["Chest","Triceps"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-decline-alternating-single-arm-press-front.mp4#t=0.1","howTo":"Lay on a decline bench with both arms extended in front of you. Break at one of your arms first bringing that arm to your side while keeping the other arm extended. Press the dumbbell back to the ceiling. Fully extend that arm before initiating on the other side.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":67,"name":"Dumbbell Decline Bench Press","equipment":"Dumbbell","primaryMuscles":["Chest","Triceps"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-decline-bench-press-front.mp4#t=0.1","howTo":"Lay on a decline bench with both arms extended in front of you. Break at the elbows and bring your upper arms to your side. Once your upper arms have reached your side, press the dumbbells back to the ceiling.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":1},{"id":68,"name":"Dumbbell Decline Chest Fly","equipment":"Dumbbell","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-decline-chest-fly-front.mp4#t=0.1","howTo":"Lay flat on a decline bench press with the dumbbells pointed toward the ceiling. Maintain a slight bend in your elbows. Bring the dumbbells out to the side, stopping the dumbbells before they pass your torso. Bring the dumbbells together to finish the rep.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":69,"name":"Dumbbell Decline Guillotine Bench Press","equipment":"Dumbbell","primaryMuscles":["Chest","Triceps"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-decline-guillotine-bench-press-front.mp4#t=0.1","howTo":"Lie on the decline bench, grasp a pair of dumbbells and hold them at shoulder level with your palms facing forward. Slowly lower the dumbbells to your chest, keeping your elbows flared out. As you lower the dumbbells, exhale deeply. Once your elbows reach your chest, pause for a moment and then press them back up to the starting position","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":70,"name":"Dumbbell Decline Neutral Bench Press","equipment":"Dumbbell","primaryMuscles":["Chest","Triceps"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-decline-neutral-bench-press-front.mp4#t=0.1","howTo":"Lie on the decline bench, grasp a pair of dumbbells and hold them at shoulder level with your palms facing each other. Keep your elbows bent and close to your body. Slowly lower the dumbbells to your chest, keeping your elbows bent and close to your body. Once the dumbbells reach your chest, pause for a moment and then press them back up to the starting position. This variation is much easier on the shoulder joints.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":71,"name":"Dumbbell Decline Single Arm Bench Press","equipment":"Dumbbell","primaryMuscles":["Chest","Triceps"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-decline-single-arm-press-front.mp4#t=0.1","howTo":"Start by laying on a decline bench with two dumbbells. Position the dumbbell above your chest with your elbow bent and shoulder level. Slowly lower the dumbbell towards your chest, keeping your elbow close to your body and your core engaged while the other dumbbell remains pointed toward the ceiling. Once the dumbbell reaches your side, pause for a moment and then press the weight back up to the starting position. Repeat for the desired number of repetitions before switching to your other arm.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":72,"name":"Dumbbell Decline Squeeze Press","equipment":"Dumbbell","primaryMuscles":["Chest","Triceps","Shoulders"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-decline-squeeze-press-front.mp4#t=0.1","howTo":"Lay flat on a decline bench with two dumbbells pressed to one another. Break at the elbows and keep your elbows tucked as you bring the dumbbells to your chest. Continue to press the dumbbells into one another throughout the rep. Once the dumbbells reach your chest, press back toward the ceiling.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":73,"name":"Dumbbell Guillotine Bench Press","equipment":"Dumbbell","primaryMuscles":["Chest","Triceps"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-guillotine-bench-press-front.mp4#t=0.1","howTo":"Lie on the flat bench, grasp a pair of dumbbells and hold them at shoulder level with your palms facing forward. Slowly lower the dumbbells to your chest, keeping your elbows flared out. As you lower the dumbbells, exhale deeply. Once your elbows reach your chest, pause for a moment and then press them back up to the starting position","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":74,"name":"Dumbbell Guillotine Incline Bench Press","equipment":"Dumbbell","primaryMuscles":["Chest","Triceps"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-guillotine-incline-bench-press-front.mp4#t=0.1","howTo":"Lie on the incline bench, grasp a pair of dumbbells and hold them at shoulder level with your palms facing forward. Slowly lower the dumbbells to your chest, keeping your elbows flared out. As you lower the dumbbells, exhale deeply. Once your elbows reach your chest, pause for a moment and then press them back up to the starting position","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":75,"name":"Dumbbell Incline Bench Press","equipment":"Dumbbell","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-incline-bench-press-front.mp4#t=0.1","howTo":"Raise the bench to a 30 - 45 degree angle Lay on the bench and set your feet on the ground. Raise the dumbbells with straight arms then slowly lower them to about shoulder width. Raise them again until your arms are locked and at the starting position again.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":76,"name":"Dumbbell Incline Chest Fly","equipment":"Dumbbell","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-incline-chest-fly-front.mp4#t=0.1","howTo":"Lay on an incline bench with two dumbbells extended in front of you. You should have a slight bend in your elbows and maintain that bend. Your shoulder joint should do all the movement. Bring the dumbbells out to your side. Stop the dumbbells before going behind your body. Bring the dumbbells back together at the top.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":77,"name":"Dumbbell Internally Rotated Chest Fly","equipment":"Dumbbell","primaryMuscles":["Chest"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-internally-rotated-chest-fly-front.mp4#t=0.1","howTo":"Lay on a bench with two dumbbells extended in front of you in an overhand grip. You should have a slight bend in your elbows and maintain that bend. Your shoulder joint should do all the movement. Bring the dumbbells out to your side. Stop the dumbbells before going behind your body. Bring the dumbbells back together at the top.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":78,"name":"Dumbbell Internally Rotated Incline Chest Fly","equipment":"Dumbbell","primaryMuscles":["Chest"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-internally-rotated-incline-chest-fly-front.mp4#t=0.1","howTo":"Lay on an incline bench with two dumbbells extended in front of you. You should have a slight bend in your elbows and maintain that bend. Your shoulder joint should do all the movement. You should have an overhand grip. Bring the dumbbells out to your side. Stop the dumbbells before going behind your body. Bring the dumbbells back together at the top.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":79,"name":"Dumbbell Neutral Bench Press","equipment":"Dumbbell","primaryMuscles":["Chest","Triceps"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-neutral-bench-press-front.mp4#t=0.1","howTo":"Lie on a flat bench, grasp a pair of dumbbells and hold them at shoulder level with your palms facing each other. Keep your elbows bent and close to your body. Slowly lower the dumbbells to your chest, keeping your elbows bent and close to your body. Once the dumbbells reach your chest, pause for a moment and then press them back up to the starting position. This variation is much easier on the shoulder joints.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":80,"name":"Dumbbell Neutral Incline Bench Press","equipment":"Dumbbell","primaryMuscles":["Chest","Triceps"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-neutral-incline-bench-press-front.mp4#t=0.1","howTo":"Lie on an incline bench, grasp a pair of dumbbells and hold them at shoulder level with your palms facing each other. Keep your elbows bent and close to your body. Slowly lower the dumbbells to your chest, keeping your elbows bent and close to your body. Once the dumbbells reach your chest, pause for a moment and then press them back up to the starting position. This variation is much easier on the shoulder joints.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":81,"name":"Dumbbell Squeeze Press","equipment":"Dumbbell","primaryMuscles":["Chest","Triceps"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-squeeze-press-front.mp4#t=0.1","howTo":"Lay flat on a bench with two dumbbells pressed to one another. Break at the elbows and keep your elbows tucked as you bring the dumbbells to your chest. Continue to press the dumbbells into one another throughout the rep. Once the dumbbells reach your chest, press back toward the ceiling.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":1},{"id":82,"name":"Dumbbell Single Arm Press","equipment":"Dumbbell","primaryMuscles":["Chest","Triceps"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-single-arm-press-front.gif#t=0.1","howTo":"Start by laying on a bench with two dumbbells. Position the dumbbell above your chest with your elbow bent and shoulder level. Slowly lower the dumbbell towards your chest, keeping your elbow close to your body and your core engaged while the other dumbbell remains pointed toward the ceiling. Once the dumbbell reaches your side, pause for a moment and then press the weight back up to the starting position. Repeat for the desired number of repetitions before switching to your other arm.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":83,"name":"Burpee","equipment":"Bodyweight","primaryMuscles":["Chest","Quads","Glutes"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-burpee-front.mp4#t=0.1","howTo":"Start standing with your feet hip-width apart. Lower your body into a squat position, placing your hands on the ground in front of you. Quickly jump your feet back into a plank position, keeping your body in a straight line from your head to your toes. Perform a push-up, keeping your core tight and your elbows close to your body. Jump your feet back towards your hands, and then jump up into the air, reaching your arms overhead. Land softly and immediately lower your body back into the squat position to repeat the movement.","secondaryMuscles":["Quads"],"tertiaryMuscles":["Glutes"],"popularity":100},{"id":84,"name":"Band Chest Fly","equipment":"Band","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-chest-fly-front_EjlOhyB.mp4#t=0.1","howTo":"Secure two resistance bands to a sturdy anchor point (e.g. a door anchor, a post, etc.) at chest height. Stand facing away from the anchor point with feet shoulder-width apart and hold each end of the band in each hand. Start with arms fully extended and parallel to the floor. Keeping arms straight, slowly bring your arms together in front of your chest.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":85,"name":"Band Chest Press","equipment":"Band","primaryMuscles":["Chest"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-chest-press-front_XYmSX4f.mp4#t=0.1","howTo":"Stand in the middle of the two bands with feet shoulder-width apart. Step forward with one foot to create tension in the bands. Hold one band in each hand, palms facing forward.\\nStart the exercise with your arms extended in front of you, keeping a slight bend in your elbows. Lower your arms to the sides of your chest, maintaining control of the band. Push your arms back up to the starting position, keeping your core engaged and maintaining control of the band.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":86,"name":"Band Internally Rotated Chest Fly","equipment":"Band","primaryMuscles":["Chest"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-internally-rotated-chest-fly-front.mp4#t=0.1","howTo":"Start with both feet hip-width apart and step on the middle of the band with both feet. Hold the handles of the band in each hand and position the band above your chest, with your palms facing down. Keeping your elbows slightly bent, slowly raise your arms out to the sides until they are parallel with the floor. Make sure to internally rotate your shoulder joints by bringing your shoulder blades together and rotating your forearms inward towards your torso. Hold the position for a few seconds and then slowly lower your arms back to the starting position, keeping the internal rotation of your shoulder joints throughout the movement.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":87,"name":"Plate Deficit Pushup","equipment":"Plate","primaryMuscles":["Chest","Triceps"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-deficit-pushup-front.mp4#t=0.1","howTo":"Start in a pushup position with both hands on a plate. This will extend your range of motion. Break at the elbows and shoulders until your upper arm travels behind the body slightly. Then press back into the original position.","secondaryMuscles":["Triceps"],"tertiaryMuscles":["Shoulders"],"popularity":0},{"id":88,"name":"Plate Glute Bridge to Chest Press","equipment":"Plate","primaryMuscles":["Chest","Glutes"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-glute-bridge-chest-press-front.mp4#t=0.1","howTo":"Lay flat on the ground with a plate on your chest. Push your hips up toward the ceiling and maintain that extended position. With your hips up, press the plate toward the ceiling.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":89,"name":"Dumbbell Elevated Pushup","equipment":"Dumbbell","primaryMuscles":["Chest","Triceps"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-elevated-pushup-front.mp4#t=0.1","howTo":"Start by placing two dumbbells on the floor, about shoulder-width apart. Position yourself in a plank position with your hands on top of the dumbbells, keeping your arms straight. Keep your feet together, with your toes resting on the floor. Engage your core and lower your body towards the floor by bending your arms, until your chest nearly touches the dumbbells. Push your body back up to the starting position, straightening your arms and engaging your chest, triceps and shoulders.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":90,"name":"Pushup to Renegade Row","equipment":"Bodyweight","primaryMuscles":["Chest","Lats"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-pushup-renegade-row-front.mp4#t=0.1","howTo":"Start in a high plank position with a pair of dumbbells positioned under your shoulders. Your hands should grip the dumbbells, palms facing each other. Keep your core engaged and your back straight as you row one dumbbell up towards your hip, keeping your elbow close to your body. Lower the dumbbell back down to the starting position and repeat on the other side.","secondaryMuscles":["Lats"],"tertiaryMuscles":["Abdominals"],"popularity":0},{"id":91,"name":"TRX Pec Fly","equipment":"TRX","primaryMuscles":["Chest"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-chest-fly-front.mp4#t=0.1","howTo":"Start by adjusting the TRX straps to chest height. Stand facing the TRX with your feet shoulder-width apart. Grasp the TRX handles with both hands, keeping your arms extended and your shoulders away from your ears. Lean forward, keeping your arms extended and your core engaged. Your body should form a slight diagonal line from your ankles to your head. Slowly bring your arms towards each other, in front of your chest, while keeping your core engaged and your body in a stable position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":92,"name":"TRX Pushup","equipment":"TRX","primaryMuscles":["Chest","Triceps","Shoulders"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-pushup-front.mp4#t=0.1","howTo":"Start by setting up the TRX straps to a secure anchor point and adjust the straps so that they hang about waist height when you stand under them. Stand facing the TRX straps, grab the handles with both hands, and step forward so that your body is in a plank position with your hands directly beneath your shoulders. Lower your body down by bending your elbows until your chest nearly touches the handles. Keep your core tight and your body in a straight line. Push your body back up to the starting position, straightening your arms as you do so. Make sure to engage your chest, triceps, and core throughout the movement.","secondaryMuscles":["Triceps"],"tertiaryMuscles":["Shoulders"],"popularity":1},{"id":93,"name":"Dumbbell Alternating Single Arm Press","equipment":"Dumbbell","primaryMuscles":["Chest","Triceps","Shoulders"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-alternating-single-arm-press-front..mp4#t=0.1","howTo":"Start in a bench press position with two dumbbells. Break at one of your elbows first while keeping the other elbow extended. Your working arm should reach your side before pressing back to the ceiling. Then alternate to the other arm.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":94,"name":"Barbell Squat","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-highbar-squat-front.mp4#t=0.1","howTo":"Stand with your feet shoulder-width apart. Maintain the natural arch in your back, squeezing your shoulder blades and raising your chest. Grip the bar across your shoulders and support it on your upper back. Unwrack the bar by straightening your legs, and take a step back. Bend your knees as you lower the weight without altering the form of your back until your hips are below your knees. Raise the bar back to starting position, lift with your legs and exhale at the top.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":8},{"id":95,"name":"Machine Leg Press","equipment":"Machine","primaryMuscles":["Quads"],"difficulty":"Intermediate","grips":["None"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-machine-leg-press-front.mp4#t=0.1","howTo":"Place your legs on the platform with your feet at shoulder width. Release the weight and extend your legs fully, without locking your knees. Lower the weight until your legs are at a 90° angle (but DO NOT allow your butt and lower back to rise off of the pad. This will put your lower back in a rounded position, which is very dangerous.) Raise the weight back to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":96,"name":"Machine Leg Extension","equipment":"Machine","primaryMuscles":["Quads"],"difficulty":"Intermediate","grips":["None"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-machine-leg-extension-front.mp4#t=0.1","howTo":"Sit on the machine with your back against the cushion and adjust the machine you are using so that your knees are at a 90 degree angle at the starting position. Raise the weight by extending your knees outward, then lower your leg to the starting position. Both movements should be done in a slow, controlled motion.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":97,"name":"Dumbbell Goblet Squat","equipment":"Dumbbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-goblet-squat-front.mp4#t=0.1","howTo":"Hold the weight tucked into your upper chest area, keeping your elbows in. Your feet should be slightly wider than shoulder width. Sink down into the squat, keeping your elbows inside the track of your knees. Push through your heels while keeping your chest up and return to starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":1},{"id":98,"name":"Kettlebell Step Up","equipment":"Kettlebell","primaryMuscles":["Quads"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-step-up-front.mp4#t=0.1","howTo":"Standing up straight, using a bench as a step, raise one foot onto the bench and hold the kettlebell in the same arm as the straight leg. Stand and bring both feet onto the bench. Slowly lower your leg back down to the starting position. Repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":99,"name":"Kettlebell Goblet Squat","equipment":"Kettlebell","primaryMuscles":["Quads"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-goblet-squat-front.mp4#t=0.1","howTo":"Hold the weight tucked into your upper chest area, keeping your elbows in. Your feet should be slightly wider than your shoulders. Sink down into the squat, keeping your elbows inside the track of your knees. Push through your heels while keeping your chest up and return to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":100,"name":"Kettlebell Heels Up Goblet Squat","equipment":"Kettlebell","primaryMuscles":["Quads"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-heels-up-goblet-squat-front.mp4#t=0.1","howTo":"Hold the weight tucked into your upper chest area, keeping your elbows in. Your feet should be slightly wider than your shoulders and the heels slightly raised on a surface. Sink down into the squat, keeping your elbows inside the track of your knees. Push through your heels while keeping your chest up and return to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":101,"name":"Kettlebell Reverse Lunge","equipment":"Kettlebell","primaryMuscles":["Quads"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-reverse-lunge-front.mp4#t=0.1","howTo":"Stand straight with your feet slightly apart and hold a kettlebell in one hand. Bring the same leg as the arm holding the kettlebell behind you, squat down until your back knee touches the ground, keeping your back straight. Return to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":102,"name":"Kettlebell Forward Lunge","equipment":"Kettlebell","primaryMuscles":["Quads"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-forward-lunge-front.mp4#t=0.1","howTo":"Stand straight with your feet slightly apart and hold a kettlebell in one hand. Bring the same leg as the arm holding the kettlebell in front of you, squat down until your thigh is parallel to the ground, keeping your back straight. Return to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":103,"name":"Kettlebell Lateral Lunge","equipment":"Kettlebell","primaryMuscles":["Quads"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-lateral-lunge-front.mp4#t=0.1","howTo":"Stand straight with your feet shoulder width apart. Keep your back straight and hold the kettlebell in front of your pelvis. Take a large step to one side, holding the kettlebell low and lunge into the bent leg. Return to the starting position and repeat","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":104,"name":"Quads Stretch Variation Four","equipment":"Stretch","primaryMuscles":["Quads"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-quads-stretch-variation-4-front.mp4#t=0.1","howTo":"Lay flat on your belly. Extend one arm out in front of you, placing your palm on the floor. With your other arm, grab the top of your foot. Keeping your upper leg flat on the floor, pull your foot towards your buttocks to engage the stretch. Pause for a few seconds, and then repeat the stretch with your other leg.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":105,"name":"Quads Stretch Variation Three","equipment":"Stretch","primaryMuscles":["Quads"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-quads-stretch-variation-3-front.mp4#t=0.1","howTo":"Lay flat on your belly, with both hands reach back and grab the tops of your feet. Keeping your upper legs flat on the ground, pull both of your feet towards your buttocks. Pause at the apex of the stretch, then return to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":106,"name":"Quads Stretch Variation Two","equipment":"Stretch","primaryMuscles":["Quads"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-quads-stretch-variation-2-front.mp4#t=0.1","howTo":"Place one foot flat on the ground in front of you at a 90 degree angle. With your other leg, balance upon your knee, placing the tip of your foot against the wall behind you for balance. Place your hands on your knee in front of you, and lean forward so that your knee extends over your foot. Pause at the apex of the stretch, and slowly return to starting position. Repeat with your other leg.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":107,"name":"Quads Stretch Variation One","equipment":"Stretch","primaryMuscles":["Quads"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-quads-stretch-variation-1-front.mp4#t=0.1","howTo":"Stand perpendicular to a wall, using one arm against the wall for balance. With your other arm, grab the top of your foot. Pull your leg upwards and back to engage your quads, pausing at the apex of the stretch for a few seconds. Return to starting position and repeat with your other leg.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":108,"name":"Side Lunges","equipment":"Bodyweight","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-side-lunge-front.mp4#t=0.1","howTo":"Take a slow, lateral step to the right. Extend the left knee, and drive your weight into your right side. Flex your knee and lower your body. Push back to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":17},{"id":109,"name":"Forward Lunges","equipment":"Bodyweight","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":["None"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-forward-lunge-front.mp4#t=0.1","howTo":"Step forward with one leg. Lower your body until your rear knee nearly touches the ground. Ensure you remain upright, and your front knee stay above the front foot. Push off the floor with your front foot until you return to the starting position. Switch legs.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":1},{"id":110,"name":"Jump Squats","equipment":"Bodyweight","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-jump-squat-front.mp4#t=0.1","howTo":"Stand with your feet shoulder-width apart. Start by doing a regular squat, then engage your core and jump up explosively. When you land, lower your body back into the squat position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":11},{"id":111,"name":"Bodyweight Squat","equipment":"Bodyweight","primaryMuscles":["Quads"],"difficulty":"Beginner","grips":["None"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-squat-front.mp4#t=0.1","howTo":"Stand with your feet shoulder width apart. flex your knees and hips and sit back into the squat while lowering your body Continue down to full depth Return to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":112,"name":"Cable Goblet Squat","equipment":"Cable","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-goblet-squat-side.mp4#t=0.1","howTo":"Start with a straight bar or easy bar attachment . Get your elbows directly underneath the bar, squat straight up and then walk back a few steps. Break at your knees and hips to initiate the squat. Make sure you maintain a flat back. Squat all the way back to a standing position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":113,"name":"Cable Split Squat","equipment":"Cable","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-split-squat-side.mp4#t=0.1","howTo":"You can use any attachment on this exercise. Cable should be set all to the bottom. Grab the attachment and walk back a few steps. Take a split stance. One leg in front and one behind. Break at the knees and hips to initiate the split squat. Make sure your back knee touches the floor. Squat back up into a standing position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":1},{"id":114,"name":"Cable Standing Leg Extension","equipment":"Cable","primaryMuscles":["Quads"],"difficulty":"Advanced","grips":["None"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-standing-leg-extension-front.mp4#t=0.1","howTo":"Stand upright facing away from the cable crossover with the cable set to the height of your hips. Use an ankle/wrist attachment. Extend at the knee against the cable.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":115,"name":"Band Spanish Squat","equipment":"Band","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":"Neutral","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-spanish-squat-front.mp4#t=0.1","howTo":"Attach a band to a sturdy object. Place the band around your upper calves or behind the knees. Step back until the band is taut. Lower yourself into a squat in which your back and shins are vertical. As you squat up, drive up through the heels to maintain balance.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":116,"name":"Band Leg Press","equipment":"Band","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":"Neutral","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-leg-press-front.mp4#t=0.1","howTo":"Lay flat on the ground with your head by the anchor point of the band, which should be 6 to 12 inches above your head Place the band around your midfoot and extend at the knees and hip.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":117,"name":"Band Squat","equipment":"Band","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":"Underhand","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-squat-front.mp4#t=0.1","howTo":"Stand with a shoulder width grip. Both feet should be on the band with the band loops in each of your hand. Push your butt back and also break at the knees. Try to hit parallel depth (bottom of your leg should be parallel with the ground). If you can\'t tell your squat depth, then try squatting in front of a mirror and watch your form.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":118,"name":"Barbell Bulgarian Split Squat","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":"Underhand","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-bulgarian-split-squat-front.mp4#t=0.1","howTo":"Find a box or bench that is roughly knee height or a few inches lower. (The lower the box is the lower the mobility requirement). You can either place your toes or the top of your foot on the box. Point your front foot forward or slightly turned outwards and break at the knees and hips simultaneously. Aim to get your front leg to hit parallel depth (hamstring parallel with the ground) or lower. The further forward your front foot is, the longer the Range of Motion is at your hips. The further back your front foot is, the longer the ROM at your knees.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":119,"name":"Barbell Front Squat Olympic","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":"Underhand","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-front-squat-olympic-front.mp4#t=0.1","howTo":"Measure your hands by the markings on the bar to make sure you\'re even. Then throw your elbows underneath the bar. The bar should be set so high on your shoulders it digs into your neck a bit. Make sure to push your elbows up to the ceiling for the entire rep. To make sure you don\'t get too pitched forward. Use the squat stance you would use for a back or goblet squat. Push your hips back to initiate the squat. Break at the knees until you hit parallel depth. Squat back up to a standing position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Abdominals"],"popularity":0},{"id":120,"name":"Barbell Front Squat Bodybuilding","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":"Overhand","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-front-squat-bodybuilding-front.mp4#t=0.1","howTo":"Measure your shoulders against the bar to make sure you\'re even. Throw your shoulders under the bar. The bar should be digging into your neck slightly. Make sure to push your elbows up to the ceiling for the entire rep. To make sure you don\'t get too pitched forward. Use the squat stance you would use for a back or goblet squat. Push your hips back to initiate the squat. Break at the knees until you hit parallel depth. Squat back up to a standing position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Abdominals"],"popularity":0},{"id":121,"name":"Barbell High Bar Squat","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":"Overhand","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-highbar-squat-front_b7zW1qG.mp4#t=0.1","howTo":"Place the bar on top of your traps. Push your hips back and break at the knees. Push your elbows forward to keep yourself from getting pitched too far forward. Aim to get your hamstrings to parallel with the floor. Push your heels into the floor and squat back to a standing position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":122,"name":"Barbell Low Bar Squat","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":"Overhand","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-lowbar-squat-front.mp4#t=0.1","howTo":"Pull your shoulder blades back really hard and place the bar on your posterior delts. Push your hips back and break at the knees to initiate the squat. Aim to get your hamstrings to parallel with the ground. Push your heels into the floor and squat back up to a standing position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":123,"name":"Barbell Coan Deadlift","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["Overhand,","Mixed"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-coan-deadlift-front.mp4#t=0.1","howTo":"Stand with your feet hip-width apart and place a barbell on the floor in front of you. Bend at the hips and knees to grasp the barbell with an overhand grip, positioning your hands just outside of your hips. Keeping your back straight and your core engaged, lift the barbell off the floor by extending your hips and knees. As you lift the barbell, pull your shoulders back and squeeze your glutes to fully extend your hips at the top of the movement.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":124,"name":"Barbell Curtsy Lunge","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-curtsy-lunge-front.mp4#t=0.1","howTo":"Place the barbell on your back Step your foot back and around while simultaneously bringing the weight down. Return to start and repeat on other leg.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":125,"name":"Barbell Forward Lunge","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-forward-lunge-front.mp4#t=0.1","howTo":"Stand with your feet shoulder-width apart and hold a barbell at your shoulders with an overhand grip. Step forward with your right foot and bend both knees to lower your body until your right thigh is parallel to the ground. Push off your right foot to return to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":1},{"id":126,"name":"Barbell Front Rack Step Up","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":["None"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-front-rack-step-up-front.mp4#t=0.1","howTo":"Stand in front of a step or bench with your feet shoulder-width apart and hold a barbell at your shoulders with an overhand grip. Step up onto the bench with your right foot, pushing off your foot to raise your body up onto the bench. Bring your left foot up onto the bench and stand up straight, keeping the barbell at your shoulders. Step back down with your left foot, followed by your right foot, to return to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":127,"name":"Barbell Heels Up Back Squat","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-heels-up-back-squat-front.mp4#t=0.1","howTo":"Stand with your feet shoulder-width apart and your heels on a plate or low step. Bend your knees and lower your body into a squat position. Push through your heels to return to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":128,"name":"Barbell Heels Up Front Squat","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":["None"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-heels-up-front-squat-front.mp4#t=0.1","howTo":"Stand with your feet shoulder-width apart and feet on a plate. Place the bar in a front rack position. Bend your knees and lower your body into a squat position, keeping your heels raised off the ground. Push through your heels to return to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":129,"name":"Barbell Lateral Lunge","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-lateral-lunge-front.mp4#t=0.1","howTo":"Stand with your feet shoulder-width apart and hold a barbell at your shoulders with an overhand grip. Step out to the side with your right foot and bend your right knee to lower your body until your right thigh is parallel to the ground. Push off your right foot to return to the starting position. Repeat on the opposite side by stepping out with your left foot.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":130,"name":"Barbell Pause Box Squat","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-pause-box-squat-front.mp4#t=0.1","howTo":"Stand in front of a box or bench with your feet shoulder-width apart and a barbell resting on your upper back. Lower your body into a squat position, sitting back onto the box and pausing for a moment before standing back up. Push through your heels to return to the standing position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":131,"name":"Barbell Pause Squat","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-pause-box-squat-front_GEhqEjs.mp4#t=0.1","howTo":"Stand with your feet shoulder-width apart and a barbell resting on your upper back. Lower your body into a squat position, pausing for a moment at the bottom of the movement before standing back up. Push through your heels to return to the standing position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":132,"name":"Barbell Reverse Deadlift","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":["Overhand,","Underhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-reverse-deadlift-front.mp4#t=0.1","howTo":"Start by standing with your feet about hip-width apart, with your toes pointed slightly outward. Place a barbell on the floor behind you, with the weight plates on either side. Bend down and grab the barbell with an overhand grip, your hands slightly wider than shoulder-width apart. Keep your back straight and your shoulders down as you grip the bar. Stand up straight, lifting the barbell off the ground and pulling it toward your hips. Keep your elbows close to your body and your shoulders down as you do this.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":133,"name":"Barbell Reverse Lunge","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-reverse-lunge-front.mp4#t=0.1","howTo":"Start by standing with your feet about hip-width apart, with a barbell on your shoulders. Your feet should be slightly pointed outward, and your shoulders should be down and relaxed. Step backward with one foot, lowering your body until your front thigh is parallel to the ground and your back knee is hovering just above the ground. Push off your back foot, returning to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":1},{"id":134,"name":"Bodyweight Reverse Step Up","equipment":"Bodyweight","primaryMuscles":["Quads"],"difficulty":"Advanced","grips":["None"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-reverse-step-up-front.mp4#t=0.1","howTo":"Start with a box or bench behind you and one of your feet on the box/bench. The balls of your feet should be planted on the box/bench. Drive through the ball of your foot extending your knees until you\'re upright and standing on the box.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":135,"name":"Barbell Side Step Up","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-side-step-up-front.mp4#t=0.1","howTo":"Start by standing with your feet about hip-width apart, with a barbell on your shoulders. Your feet should be slightly pointed outward, and your shoulders should be down and relaxed. Place a step or box beside you, and step up onto it with one foot. Your other foot should remain on the ground. Push off your grounded foot, raising your body up onto the step. Step back down with the same foot, returning to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":136,"name":"Barbell Split Squat","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-split-squat-front.mp4#t=0.1","howTo":"Take a large step forward with one leg, and lower your body until your back knee nearly touches the ground. Your front knee should be bent at a 90-degree angle, and your back leg should be straight. Push through the heel of your front foot to raise your body back to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":1},{"id":137,"name":"Barbell Step Up Balance","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-step-up-balance-front.mp4#t=0.1","howTo":"Begin by standing in front of a sturdy box or bench that is about knee-height, holding a barbell across your upper back and shoulders, using an overhand grip. Place your right foot on the box and push through the heel to lift your body up and onto the box, keeping your left foot off the ground. Step back down with your right foot, lowering your left foot to the ground.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":138,"name":"Barbell Step Up","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-step-up-front.mp4#t=0.1","howTo":"Begin by standing in front of a sturdy box or bench that is about knee-height, holding a barbell across your upper back and shoulders, using an overhand grip. Place your right foot on the box and push through the heel to lift your body up and onto the box. Step back down with your right foot.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":1},{"id":139,"name":"Barbell Tap Pause Squat","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-tap-box-squat-front.mp4#t=0.1","howTo":"Begin by standing in front of a sturdy box or bench that is about knee-height, holding a barbell across your upper back and shoulders, using an overhand grip. Sit back and lower your body down until your glutes tap the top of the box, keeping your back straight and your core engaged. Push through your heels to extend your hips and stand up, bringing your body back to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":140,"name":"Barbell Zercher Squat","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":"Underhand","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-zercher-squat-front.mp4#t=0.1","howTo":"Begin by standing with your feet about hip-width apart and holding a barbell in the crook of your arms, near your belly. Your palms should be facing towards your body. Sit back and lower your body down until your thighs are parallel to the ground, keeping your back straight and your core engaged. Push through your heels to extend your hips and stand back up to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":141,"name":"Assisted Bulgarian Split Squat","equipment":"Bodyweight","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":["None"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-assisted-bulgarian-split-squat-front.mp4#t=0.1","howTo":"Grab a stick of some sort or hold onto something stable (rack, bench). Grab a box that is knee height or slightly lower. Hold the stick in your right arm and put your right leg on the box. Begin your squat by breaking at the knees. Get your knee close to the floor or all the way to the floor. Make sure to keep your chest tall.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":142,"name":"Bulgarian Split Squat","equipment":"Bodyweight","primaryMuscles":["Quads"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-bulgarian-split-squat-front.mp4#t=0.1","howTo":"Stand with your back to a bench (or raised surface) and place one of your feet on the bench. Squat down until your front leg is about parallel to the floor. Go back to the starting position. After completing the desired amount of reps, switch legs and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":25},{"id":143,"name":"Curtsy Lunge","equipment":"Bodyweight","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["None"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-curtsy-lunge-front.mp4#t=0.1","howTo":"Step your left foot diagonally behind your right leg, crossing it behind your body. Bend your knees and lower your hips until your left thigh is parallel to the floor and your right knee is hovering just above the ground. Push through your right foot to straighten your legs and return to the starting position. Repeat the movement with your other leg.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":5},{"id":144,"name":"Forward Lunge","equipment":"Bodyweight","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":["None"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-forward-lunge-front_zb4K50d.mp4#t=0.1","howTo":"Step forward with one leg and lower your body until your front thigh is parallel to the floor and your back knee almost touches the ground. Keep your chest up and your front foot flat on the floor. Push through your front foot to straighten your legs and return to the starting position. Repeat the movement with your other leg.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":1},{"id":145,"name":"Heels Up Squat","equipment":"Bodyweight","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["None"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-heels-up-squat-front.mp4#t=0.1","howTo":"Place your heels on a plate or very low step. Keep your chest tall and initiate the squat by pushing your hips back and breaking at the knees. You should notice yourself able to squat lower than normal.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":146,"name":"Lateral Lunge","equipment":"Bodyweight","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["None"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-lateral-lunge-front.mp4#t=0.1","howTo":"Engage your core by drawing your belly button towards your spine. This will help to stabilize your body. Take a large step to the side with your right foot, planting it firmly on the ground. As you step, bend your right knee and lower your hips until your right thigh is parallel to the ground. Your left leg should remain straight. Push through your right heel to return to the starting position. Repeat on the opposite side by stepping out with your left foot.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":3},{"id":147,"name":"Bodyweight Reverse Lunge","equipment":"Bodyweight","primaryMuscles":["Quads","Hamstrings"],"difficulty":"Beginner","grips":["None"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-reverse-lunge-front.mp4#t=0.1","howTo":"Push through your right heel to return to standing, bringing your left leg back to starting position. Repeat the movement on the other side, stepping backwards with your right leg and lowering your body until your right thigh is parallel to the ground and your left knee is bent at a 90-degree angle. Take a big step backwards with your left leg, lowering your body until your left thigh is parallel to the ground and your right knee is bent at a 90-degree angle.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":148,"name":"Split Squat","equipment":"Bodyweight","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":["None"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-split-squat-front.mp4#t=0.1","howTo":"Take a split stance. Make sure to keep your chest tall. Bring your rear knee to the floor or close to it. Drive through your front heel and your rear foot back to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":14},{"id":149,"name":"Dumbbell Bulgarian Split Squat","equipment":"Dumbbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-bulgarian-split-squat-front.mp4#t=0.1","howTo":"Find a box or bench that is roughly knee height or a few inches lower. (The lower the box is the lower the mobility requirement). You can either place your toes or the top of your foot on the box. Point your front foot forward or slightly turned outwards and break at the knees and hips simultaneously. Aim to get your front leg to hit parallel depth (hamstring parallel with the ground) or lower. The further forward your front foot is, the longer the Range of Motion is at your hips. The further back your front foot is, the longer the ROM at your knees.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":1},{"id":150,"name":"Dumbbell Forward Lunge","equipment":"Dumbbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-forward-lunge-front.mp4#t=0.1","howTo":"Stand with your feet hip-width apart and hold a dumbbell in each hand with your palms facing each other. Take a big step forward with your right foot, lowering your hips until your right thigh is parallel to the ground and your left knee is hovering just above the floor. Push through your right heel to straighten your right leg and return to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":151,"name":"Dumbbell Goblet Bulgarian Split Squat","equipment":"Dumbbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":"Neutral","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-goblet-bulgarian-split-squat-front.mp4#t=0.1","howTo":"Holding the dumbbell in a goblet squat place your foot on a bench or box. Break at the hips and knees. Try to go to the point where your hamstring is parallel with the ground. Or until your back knee taps the floor. Make sure to keep your back flat and your elbows directly under your fists.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":152,"name":"Dumbbell Goblet Curtsy Lunge","equipment":"Dumbbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-goblet-curtsy-lunge-front.mp4#t=0.1","howTo":"Stand with your feet hip-width apart and a dumbbell in a goblet position. Step your left foot behind and to the right of your right foot, crossing it behind your right leg. Bend your knees and lower your hips down and back, as if you were about to sit in a chair. Push through your right heel to straighten your right leg and return to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":153,"name":"Dumbbell Goblet Forward Lunge","equipment":"Dumbbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-goblet-forward-lunge-front.mp4#t=0.1","howTo":"Hold a dumbbell in a goblet position. Step forward with one of your legs while bending at your back leg. Bring your back knee to the floor or close to the floor. Push through your front leg explosively to get back to your starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":154,"name":"Dumbbell Goblet Lateral Lunge","equipment":"Dumbbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-goblet-lateral-lunge-front.mp4#t=0.1","howTo":"Engage your core by drawing your belly button towards your spine. This will help to stabilize your body. Hold a dumbbell in a goblet position. Take a large step to the side with your right foot, planting it firmly on the ground. As you step, bend your right knee and lower your hips until your right thigh is parallel to the ground. Your left leg should remain straight. Push through your right heel to return to the starting position. Repeat on the opposite side by stepping out with your left foot.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":155,"name":"Dumbbell Goblet Reverse Lunge","equipment":"Dumbbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-goblet-reverse-lunge-front.mp4#t=0.1","howTo":"Hold a dumbbell in a goblet position. Take a big step backwards with your left leg, lowering your body until your left thigh is parallel to the ground and your right knee is bent at a 90-degree angle. Push through your right heel to return to standing, bringing your left leg back to starting position. Repeat the movement on the other side, stepping backwards with your right leg and lowering your body until your right thigh is parallel to the ground and your left knee is bent at a 90-degree angle.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":156,"name":"Dumbbell Goblet Split Squat","equipment":"Dumbbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-goblet-split-squat-front.mp4#t=0.1","howTo":"Hold a dumbbell in a goblet position. Take a large step forward with one leg, and lower your body until your back knee nearly touches the ground. Your front knee should be bent at a 90-degree angle, and your back leg should be straight. Push through the heel of your front foot to raise your body back to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":157,"name":"Dumbbell Lateral Lunge Reach","equipment":"Dumbbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-lateral-lunge-reach-front.mp4#t=0.1","howTo":"Engage your core by drawing your belly button towards your spine. This will help to stabilize your body. Hold a dumbbell in a goblet position. Take a large step to the side with your right foot and reach toward the floor with your single dumbbell. As you step, bend your right knee and lower your hips until your right thigh is parallel to the ground. Your left leg should remain straight. Push through your right heel to return to the starting position. Repeat on the opposite side by stepping out with your left foot.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":158,"name":"Dumbbell Reverse Lunge","equipment":"Dumbbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-reverse-lunge-front.mp4#t=0.1","howTo":"Hold two dumbbells by your side. Take a big step backwards with your left leg, lowering your body until your left thigh is parallel to the ground and your right knee is bent at a 90-degree angle. Push through your right heel to return to standing, bringing your left leg back to starting position. Repeat the movement on the other side, stepping backwards with your right leg and lowering your body until your right thigh is parallel to the ground and your left knee is bent at a 90-degree angle.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":1},{"id":159,"name":"Dumbbell Split Squat","equipment":"Dumbbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-split-squat-front.mp4#t=0.1","howTo":"Hold a dumbbell in a goblet position. Take a large step forward with one leg, and lower your body until your back knee nearly touches the ground. Your front knee should be bent at a 90-degree angle, and your back leg should be straight. Push through the heel of your front foot to raise your body back to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":2},{"id":160,"name":"Dumbbell Front Rack Pause Squat","equipment":"Dumbbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-front-rack-pause-squat-front.mp4#t=0.1","howTo":"Place two dumbbells on your shoulders and make sure you force your elbows upward. Push your hips back and break at the knees. When you reach parallel (hamstrings parallel with the ground) pause for 1-3 seconds. Then push through your heels back to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":161,"name":"Dumbbell Front Rack Squat","equipment":"Dumbbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-front-rack-squat-front.mp4#t=0.1","howTo":"Place two dumbbells on your shoulders and push your elbows upward. Push your hips back and break at the knees. Hit parallel depth and then drive through your heels back to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":162,"name":"Dumbbell Goblet Pulse Squat","equipment":"Dumbbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-goblet-pulse-squat-front.mp4#t=0.1","howTo":"Hold a dumbbell in goblet position. Squat down to parallel depth and then halfway back up. Stay in this short range of motion for the duration of the set.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":163,"name":"Dumbbell Heels Up Goblet Squat","equipment":"Dumbbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-heels-up-goblet-squat-front.mp4#t=0.1","howTo":"Take a half kneeling stance. The dumbbell should start over your knee that is up. Rotate at the spine and point the dumbbell to the opposing side.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":164,"name":"Dumbbell Heels Up Narrow Goblet Squat","equipment":"Dumbbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-heels-up-narrow-goblet-squat-front.mp4#t=0.1","howTo":"Stand with your feet on a plate. Your feet should be very close to one another, but not touching. Begin your squat by pushing your hips back and breaking at the knees. Try to keep your chest tall while squatting.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":165,"name":"Dumbbell Leg Extension","equipment":"Dumbbell","primaryMuscles":["Quads"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-leg-extension-front.mp4#t=0.1","howTo":"Place a dumbbell between your feet. Lean back slightly and hold on to the bench. Extend your knees until you feel your quads contract hard.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":166,"name":"Dumbbell Offset Squat","equipment":"Dumbbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-offset-squat-front.mp4#t=0.1","howTo":"Hold a dumbbell over one shoulder. Initiate the squat by pushing your hips back. Avoid doing any twisting. Try to keep your shoulders even.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Obliques"],"popularity":0},{"id":167,"name":"Dumbbell Sumo Squat","equipment":"Dumbbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-sumo-squat-front.mp4#t=0.1","howTo":"Start by standing with your feet wider than shoulder-width apart and holding a dumbbell in each hand. Place the dumbbells on the ground between your feet. From this starting position, bend your knees and lower your body down into a squat. Make sure to keep your core engaged and your back straight throughout the movement.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":1},{"id":168,"name":"Dumbbell Thruster","equipment":"Dumbbell","primaryMuscles":["Quads","Shoulders","Glutes"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-thruster-front.mp4#t=0.1","howTo":"Start by standing with your feet shoulder-width apart and holding a dumbbell in each hand. Bring the dumbbells to your shoulders, with your palms facing inward and your elbows bent. From this starting position, dip your knees slightly and then quickly extend them as you press the dumbbells upwards. As you press the dumbbells upwards, also push your hips forward to help generate additional power. Slowly lower the dumbbells back down to the starting position, and repeat for the desired number of repetitions.","secondaryMuscles":["Shoulders"],"tertiaryMuscles":["Glutes"],"popularity":1},{"id":169,"name":"Plate Squat","equipment":"Plate","primaryMuscles":["Quads"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-squat-front.mp4#t=0.1","howTo":"Stand with feet shoulder-width apart and hold a weight plate in front of your chest with both hands. Keep your back straight, lower your body as if you were sitting back into a chair. Go as low as you can while keeping your heels flat on the ground, then push through your heels to return to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":170,"name":"Plate Squat Reach","equipment":"Plate","primaryMuscles":["Quads","Triceps"],"difficulty":"Advanced","grips":"Neutral","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-squat-reach-front.mp4#t=0.1","howTo":"Stand holding a weight plate at chest height with both hands. Lower into a squat, extending the plate in front of you at chest height As you stand back up, pull the plate back into your chest.","secondaryMuscles":["Shoulders"],"tertiaryMuscles":null,"popularity":0},{"id":171,"name":"Plate Curtsy Lunge","equipment":"Plate","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-curtsy-lunge-front.mp4#t=0.1","howTo":"Stand with feet shoulder-width apart and the plate in front of the torso. Step back and across the body with the right foot, bending both legs to lower into a lunge position. Push through the front foot to return to the starting position. Repeat on the other side by stepping back and across with the left foot. Continue alternating sides for desired reps.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":172,"name":"Plate Lateral Lunge","equipment":"Plate","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-lateral-lunge-front.mp4#t=0.1","howTo":"Stand with feet hip-width apart and the plate held in front of the torso. Take a step to the side with one foot, bending the knee and lowering the hips into a lunge. Push through the front foot to return to the starting position. Repeat on the other side by stepping to the other side with the other foot.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":173,"name":"Plate Forward Lunge","equipment":"Plate","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-forward-lunge-front.mp4#t=0.1","howTo":"Stand with feet hip-width apart and the plate held in front of the torso. Take a step forward with one foot, bending the front knee to lower the hips into a lunge. Push through the front foot to return to the starting position. Repeat on the other side by stepping forward with the other foot.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":174,"name":"Plate Reverse Lunge Twist","equipment":"Plate","primaryMuscles":["Quads","Triceps"],"difficulty":"Intermediate","grips":"Neutral","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-reverse-lunge-twist-front.mp4#t=0.1","howTo":"Step back with your right foot into a lunge position, both knees bent at 90 degrees. Twist your torso to the right, keeping the plate close to your chest. Push through your front foot to return to the starting position and repeat on the other side.","secondaryMuscles":["Glutes","Obliques"],"tertiaryMuscles":null,"popularity":0},{"id":175,"name":"Plate Reverse Lunge","equipment":"Plate","primaryMuscles":["Quads"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-reverse-lunge-front.mp4#t=0.1","howTo":"Hold the plate at chest height close to your body Take a big step backwards with your left leg, lowering your body until your left thigh is parallel to the ground and your right knee is bent at a 90-degree angle. Push through your right heel to return to standing, bringing your left leg back to starting position. Repeat the movement on the other side, stepping backwards with your right leg and lowering your body until your right thigh is parallel to the ground and your left knee is bent at a 90-degree angle.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":176,"name":"Band Leg Extension","equipment":"Band","primaryMuscles":["Quads"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-leg-extension-front.mp4#t=0.1","howTo":"Anchor a band to something stable and set up a bench. Run through the band underneath the bench and loop around your feet. Flex and extend your knees.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":177,"name":"Plate Overhead Squat","equipment":"Plate","primaryMuscles":["Quads"],"difficulty":"Intermediate","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-overhead-squat-front.mp4#t=0.1","howTo":"Hold a weight plate at arm\'s length overhead, with your arms fully extended. The plate should be directly above your head and your elbows should be locked. Begin to bend your knees, lowering your body as far as you can while keeping the weight plate overhead. Make sure to keep your back straight and your chest lifted. Once your thighs are parallel to the ground or as low as you can go, pause for a moment. Push through your heels to return to a standing position, keeping the weight plate overhead the entire time.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":178,"name":"Plate Deficit Lunge","equipment":"Plate","primaryMuscles":["Quads","Glutes"],"difficulty":"Advanced","grips":["None"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-deficit-lunge-front.mp4#t=0.1","howTo":"Stand on a plate with both feet. Step back with one foot to the floor and let your back knee get close to or tap the floor. Push through your front leg until both feet are back on the plate.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":179,"name":"Plate Overhead Walking Lunge","equipment":"Plate","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-overhead-walking-lunge-front.mp4#t=0.1","howTo":"Stand tall with a plate overhead. Step with one foot forward bringing your back knee to the floor. Gently tap your knee then drive through your front leg. Go back to a standing position and then step forward with the opposing legs.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Shoulders"],"popularity":0},{"id":180,"name":"Plate Thruster","equipment":"Plate","primaryMuscles":["Quads","Shoulders","Glutes"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-squat-thruster-front.mp4#t=0.1","howTo":"Start with the plate at chest height. Begin a squat. Make sure to hit parallel depth. On your way back up, use the momentum you generate with your legs to help push the plate into an overhead position. Let the plate return to chest height before initiating the next squat.","secondaryMuscles":["Shoulders"],"tertiaryMuscles":["Glutes"],"popularity":0},{"id":181,"name":"Dumbbell Overhead Squat","equipment":"Dumbbell","primaryMuscles":["Quads","Shoulders","Glutes"],"difficulty":"Advanced","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-overhead-squat-front.mp4#t=0.1","howTo":"Stand with your feet slightly wider than shoulder-width apart and hold two dumbbells overhead with both hands, using an overhand grip. Begin the squat by bending at the hips and knees, keeping your core tight and the dumbbells balanced overhead. Lower your body as far as you can while keeping the dumbbells overhead, then push back up to the starting position. Repeat for the desired number of repetitions, making sure to keep your back straight, chest lifted, and the dumbbells stable overhead throughout the entire movement.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Shoulders"],"popularity":1},{"id":182,"name":"Single Arm Overhead Squat","equipment":"Bodyweight","primaryMuscles":["Quads","Shoulders","Glutes"],"difficulty":"Advanced","grips":"Overhand","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-single-arm-overhead-squat-front.mp4#t=0.1","howTo":"Stand with your feet shoulder-width apart and a dumbbell in your right hand, extending it overhead. Inhale and begin to squat down, keeping the dumbbell overhead and your back straight. Go down as far as you can while still maintaining control, then exhale and return to standing position, keeping the dumbbell overhead. Repeat for desired reps and then switch to the other arm.","secondaryMuscles":["Shoulders"],"tertiaryMuscles":["Glutes"],"popularity":1},{"id":183,"name":"TRX Curtsy Lunge","equipment":"TRX","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-curtsy-lunge-front.mp4#t=0.1","howTo":"Stand facing away from the anchor point, holding onto the TRX handles with both hands. Step your left foot behind your right, crossing it behind your right leg, and lower yourself into a curtsy lunge. Push through your right foot to return to the starting position and repeat the movement with the other leg.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":184,"name":"TRX Jumping Squat","equipment":"TRX","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-jump-squat-front.mp4#t=0.1","howTo":"Stand facing the TRX straps and place your feet shoulder-width apart. Begin by lowering into a squat position by bending at the knees and hips, keeping your back straight and chest up. Explosively jump up off the ground, using your arms for momentum if desired. Land softly back in the squat position, making sure to absorb the impact with your legs.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":185,"name":"TRX Lateral Lunge","equipment":"TRX","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-lateral-lunge-front.mp4#t=0.1","howTo":"Grasp the TRX handles with both hands and extend your arms straight in front of you. Step laterally to one side, keeping your arms extended and your core engaged. Lower your body into a lunge position, keeping your front knee bent at a 90-degree angle and your back leg straight. Push off your front foot to return to the starting position, keeping your arms extended and your core engaged.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":186,"name":"TRX Reverse Lunge","equipment":"TRX","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-reverse-lunge-front.mp4#t=0.1","howTo":"Hold on to the TRX straps and step away until the strap is taut. Step backwards with one leg in to a lunge position and gently tap your knee to the floor. Lunge back to the starting position and repeat with the other leg.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":187,"name":"TRX Split Squat","equipment":"TRX","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-split-squat-front.mp4#t=0.1","howTo":"Hold the two TRX straps and step away until the straps are taut. Take a split stance. Bring your back knee to the floor and gently tap the floor. Use your arms and the TRX to help assist you getting back into the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":188,"name":"TRX Squat","equipment":"TRX","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-squat-front.mp4#t=0.1","howTo":"Hold the two TRX straps and lean away from the anchor point. Flex at the hips and knees in to a squat position. You can use your arms and the straps to assist you back into the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":1},{"id":189,"name":"Dumbbell Seated Shrug","equipment":"Dumbbell","primaryMuscles":["Traps"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-seated-shrug-front.mp4#t=0.1","howTo":"Sit on a bench with dumbbells in both hands, palms facing your body, back straight. Elevate your shoulders and hold the contracted position at the apex of the motion. Slowly lower your shoulders back to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":190,"name":"Smith Machine Standing Shrugs","equipment":"Machine","primaryMuscles":["Traps"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-standing-smith-machine-shrugs-front.mp4#t=0.1","howTo":"Place the bar on a lower rung so that when gripped your arms are fully extended and your back is straight. Grip at shoulder width, raise the bar with your shoulders and pause at the contracted position. Slowly lower the bar back to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":191,"name":"Kettlebell Shrug","equipment":"Kettlebell","primaryMuscles":["Traps"],"difficulty":"Beginner","grips":"Overhand","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-shrug-front.mp4#t=0.1","howTo":"Standing up straight with feet shoulder width apart. Holding the kettlebell in both hands in front of your pelvis, engage your shoulder blades, as if you are trying to touch them together. Release the shrug and repeat","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":192,"name":"Kettlebell Upright Row","equipment":"Kettlebell","primaryMuscles":["Traps"],"difficulty":"Beginner","grips":"Overhand","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-upright-row-front.mp4#t=0.1","howTo":"Stand with your feet shoulder width apart holding the kettlebell with both hands in front of your thighs. Bend forward at the hips bringing the kettlebell to the floor while you slightly bend your knees, keeping your back straight. Lift the kettlebell upwards towards your chest and lower - repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":193,"name":"Kettlebell Silverback Shrug","equipment":"Kettlebell","primaryMuscles":["Traps"],"difficulty":"Intermediate","grips":"Overhand","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-silverback-shrug-front.mp4#t=0.1","howTo":"Stand with your feet shoulder width apart holding the kettlebell with both hands in front of your thighs. Bend forward at the hips bringing the kettlebell to the floor while you slightly bend your knees, keeping your back straight. Holding the kettlebell in both hands engage your shoulder blades, as if you are trying to touch them together. Release the shrug.","secondaryMuscles":["Traps","Traps (mid-back)"],"tertiaryMuscles":null,"popularity":0},{"id":194,"name":"Traps Stretch Variation Three","equipment":"Stretch","primaryMuscles":["Traps"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-traps-stretch-variation-3-front.mp4#t=0.1","howTo":"Stand upright with your feet shoulder width apart. Nod your head forward, bringing your chin to your chest. You will feel the stretch across your neck.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":195,"name":"Traps Stretch Variation Two","equipment":"Stretch","primaryMuscles":["Traps"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-traps-stretch-variation-2-front.mp4#t=0.1","howTo":"Keeping your chest facing forward, turn your head 90 degrees to the left. Then return to centre point. Stand upright with your feet shoulder width apart. Repeat, turning your head in the other direction.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":196,"name":"Traps Stretch Variation One","equipment":"Stretch","primaryMuscles":["Traps"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-traps-stretch-variation-1-front.mp4#t=0.1","howTo":"Stand upright with your feet shoulder width apart. Place your left hand on your head and gently pull your head down towards your left shoulder. Then return to centre point. Repeat, using your right hand pulling towards your right shoulder.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":197,"name":"Elevated Pike Shoulder Shrug","equipment":"Bodyweight","primaryMuscles":["Traps","Shoulders"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-elevated-pike-shrug-front.mp4#t=0.1","howTo":"Use a bench or an object like a chair to elevate your feet. Slowly lower your body (scapula) while keeping your elbows locked (this is key) Slowly raise your body back to the start position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":198,"name":"Barbell Silverback Shrug","equipment":"Barbell","primaryMuscles":["Traps"],"difficulty":"Intermediate","grips":["Overhand,","Mixed"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-silverback-shrug-front.mp4#t=0.1","howTo":"Stand with your feet shoulder width apart holding the Barbell with both hands in front just past shoulder width. Bend forward at the hips with a slight bend in your knees, keeping your back straight. Engage your shoulder blades, as if you are trying to touch them together. Release the shrug.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":199,"name":"Cable 30 Degree Shrug","equipment":"Cable","primaryMuscles":["Traps"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-shrug-front.mp4#t=0.1","howTo":"Use a handle attachment on both sides of crossover. With cable attachment set all the way to the bottom. Grab both handles and make sure you are centered in the machine. Let your arms hang freely. Pull your shoulder blades up and in towards your ears. Let your shoulder blades depress back to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":200,"name":"Band Shrug","equipment":"Band","primaryMuscles":["Traps"],"difficulty":"Beginner","grips":"Underhand","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-shrug-front.mp4#t=0.1","howTo":"Place the band under your feet. Stand upright. Elevate your shoulder blades and then depress back to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":201,"name":"Dumbbell Shrug","equipment":"Dumbbell","primaryMuscles":["Traps"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-shrug-front_8g0TOxX.mp4#t=0.1","howTo":"Stand tall with two dumbbells. Pull your shoulder blades up. Give a one second squeeze at the top.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":202,"name":"Barbell Shrug","equipment":"Barbell","primaryMuscles":["Traps"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-shrug-front.mp4#t=0.1","howTo":"Start by standing with your feet about hip-width apart, with a barbell in front of you. Bend down and grab the barbell with an overhand grip, your hands slightly wider than shoulder-width apart. Keep your back straight and your shoulders down as you grip the bar. Stand up straight, lifting the barbell off the ground and pulling it toward your hips. Keep your elbows close to your body and your shoulders down as you do this. Once the barbell is at your hips, raise your shoulders as high as you can, holding the position for a moment.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":3},{"id":203,"name":"Dumbbell Laying 30 Degree Shrug","equipment":"Dumbbell","primaryMuscles":["Traps"],"difficulty":"Intermediate","grips":["Overhand,","Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-laying-30-degree-shrug-front.mp4#t=0.1","howTo":"Lay sideways on a bench letting your arm hang freely. Pull your shoulder blade and joint toward the ceiling.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":204,"name":"Plate Overhead Carry","equipment":"Plate","primaryMuscles":["Traps","Shoulders"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-overhead-carry-front.mp4#t=0.1","howTo":"Start by standing upright with your feet shoulder-width apart. Hold a single weight plate overhead with both hands, keeping your arms extended straight above your head. Begin walking forward, taking slow and steady steps while maintaining a straight line. Your focus should be on maintaining balance and control of the weight plate overhead. As you walk, continue to keep your arms extended and the weight plate overhead. Try to maintain good posture and avoid leaning forward or backward, as this could result in losing control of the weight plate. Continue walking for a set distance or for a certain amount of time, keeping your focus on proper form and technique. When finished, return to the starting position and repeat as desired.","secondaryMuscles":["Shoulders"],"tertiaryMuscles":null,"popularity":0},{"id":205,"name":"Plate Overhead Shrug","equipment":"Plate","primaryMuscles":["Traps"],"difficulty":"Advanced","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-overhead-shrug-front.mp4#t=0.1","howTo":"Stand tall with a weight plate overhead. Elevated and depress your scapula. Avoid leaning forward or backwards to keep pressure off of your lumbar spine.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":206,"name":"Dips narrow elbows","equipment":"Bodyweight","primaryMuscles":["Triceps"],"difficulty":"Advanced","grips":"Overhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-dips-front.mp4#t=0.1","howTo":"Hold your body at arms length above the equipment Inhale and slowly lower yourself downward. Keep your elbows close to your body and your torso upright. Exhale, and using your triceps raise your body back to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":207,"name":"Dumbbell Seated Overhead Tricep Extension","equipment":"Dumbbell","primaryMuscles":["Triceps"],"difficulty":"Intermediate","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-overhead-tricep-extension-front.mp4#t=0.1","howTo":"Sit on the bench and hold a dumbbell with both hands. Raise the dumbbell overhead at arms length, holding the weight up with the palms of your hands. Keep your elbows in while you lower the weight behind your head, your upper arms stationary. Raise the weight back to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":208,"name":"Machine Cable V Bar Push Downs","equipment":"Machine","primaryMuscles":["Triceps"],"difficulty":"Beginner","grips":"Overhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-push-downs-front.mp4#t=0.1","howTo":"Grip the pulley bar with palms facing down at shoulder width. Stand straight with a small forward incline. Keep your upper arms close to your body, and slowly bring the pulley bar down until your arms are fully extended. Pause when you are at the contracted position of the motion, then slowly raise the pulley bar back to the starting point.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":209,"name":"Bench Dips","equipment":"Bodyweight","primaryMuscles":["Triceps"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-tricep-dips-front.mp4#t=0.1","howTo":"Grip the edge of the bench with your hands, Keep your feet together and legs straight. Lower your body straight down. Slowly press back up to the starting point. TIP: Make this harder by raising your feet off the floor and adding weight.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":5},{"id":210,"name":"Barbell Laying Triceps Extensions","equipment":"Barbell","primaryMuscles":["Triceps"],"difficulty":"Intermediate","grips":"Overhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-laying-tricep-extensions-front.mp4#t=0.1","howTo":"Lay on a flat bench while holding a barbell with a shoulder-width grip. Fully extend your elbows until the barbell is directly over your chest. Begin to flex your elbows and allow the barbell to nearly touch your forehead. Extend your elbows back to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":211,"name":"Kettlebell Skull Crusher","equipment":"Kettlebell","primaryMuscles":["Triceps"],"difficulty":"Advanced","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-skullcrusher-front.mp4#t=0.1","howTo":"Lie on your back with knees in the air and soles of your feet flat on the floor. Hold the kettlebell in both hands directly above your chest. Keeping your upper arms in place, bend your elbows to slowly bring the kettlebell in front of your forehead. Return to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":212,"name":"Kettlebell Standing Tricep Extension","equipment":"Kettlebell","primaryMuscles":["Triceps"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-tricep-extension-front.mp4#t=0.1","howTo":"Stand with legs shoulder width apart. Hold the kettlebell in both hands behind your head. Straighten arms bringing kettlebell above your head. Return to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":213,"name":"Kettlebell Decline Skull Crusher","equipment":"Kettlebell","primaryMuscles":["Triceps"],"difficulty":"Advanced","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-decline-skull-crusher-front.mp4#t=0.1","howTo":"Lie on the floor with your upper back and soles of feet on the floor, knees bent, and pelvis and lower back suspended in the air. Hold the kettlebell in both hands directly above your chest. Keeping your upper arms in place, bend your elbows to bring the kettlebell to the floor above your head. Return the kettlebell to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":214,"name":"Kettlebell Tate Press","equipment":"Kettlebell","primaryMuscles":["Triceps"],"difficulty":"Intermediate","grips":"Underhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-tate-press-front.mp4#t=0.1","howTo":"Lie flat on your back. Keeping your arm straight, hold the kettlebell above your chest with your palm facing away from your body. Bend your arm, touching the kettlebell to the top of the shoulder opposite to the arm being worked. Return to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":215,"name":"Triceps Stretch Variation Three","equipment":"Stretch","primaryMuscles":["Triceps"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-triceps-stretch-variation-3-front.mp4#t=0.1","howTo":"Bend your left arm so your hand is at your shoulder, and hold your elbow with the opposite hand. Gently push on your elbow so it is raised by your head. Hold the stretch for a few seconds then repeat with the other arm.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":216,"name":"Triceps Stretch Variation Two","equipment":"Stretch","primaryMuscles":["Triceps"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-triceps-stretch-variation-2-front.mp4#t=0.1","howTo":"Hold a band so it is in line with your spine. Hold the top with your right hand and the bottom with your left. Keeping the top still, pull down on the band. Hold the stretch for a few seconds then repeat with the other arm.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":217,"name":"Triceps Stretch Variation One","equipment":"Stretch","primaryMuscles":["Triceps"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-triceps-stretch-variation-1-front.mp4#t=0.1","howTo":"Use the opposite hand to gently apply pressure to the elbow. Hold the stretch for a few seconds then repeat with the other arm. Raise your left arm above your head, and bend at the elbow so your hand is resting at the top of your back.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":218,"name":"Diamond Push Ups","equipment":"Bodyweight","primaryMuscles":["Triceps"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-diamond-pushup-front.mp4#t=0.1","howTo":"Position your index fingers and thumbs so they are touching, forming a diamond shape Use a standard push up position Lower your chest towards your hands, keep your elbows close to your body Stop just before your chest touches the floor, then push back up to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":2},{"id":219,"name":"Barbell Close Grip Bench Press","equipment":"Barbell","primaryMuscles":["Triceps"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-close-grip-bench-press-front.mp4#t=0.1","howTo":"Lay flat on the bench with your feet on the ground. With a narrow grip on the bar, straighten your arms Lower the bar to your lower-mid chest Slowly raise the bar until you\'ve locked your elbows.","secondaryMuscles":["Chest"],"tertiaryMuscles":null,"popularity":1},{"id":220,"name":"Cable Push Down","equipment":"Cable","primaryMuscles":["Triceps"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-pushdown-side.mp4#t=0.1","howTo":"You can use any attachment for this. The cable should be set all the way at the top of the machine. Make sure to keep your upper arm glued at your side. Extend your elbows until you feel your triceps contract.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":221,"name":"Cable Cross Pushdown","equipment":"Cable","primaryMuscles":["Triceps"],"difficulty":"Advanced","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-cross-push-down-front.mp4#t=0.1","howTo":"Either use two handles or no attachment at all. Both sides of the cable crossover should be set to the top. Stand in the center of the machine holding each Cable in the opposing hand. Your upper arm should be at a 45 degree angle with your torso. Extend your elbows until you feel a contraction and then return to the starting position","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":222,"name":"Cable Skullcrusher","equipment":"Cable","primaryMuscles":["Triceps"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-skullcrusher-side.mp4#t=0.1","howTo":"You can use a straight bar, rope, easy bar, or two handles. The cable should be set all the way to the top of the machine. Face away from the machine with your elbows up and the attachment just behind your head. Extend at the elbows until you feel a contraction in your triceps and then flex at the elbow back to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":223,"name":"Cable Overhead Tricep Extension","equipment":"Cable","primaryMuscles":["Triceps"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-overhead-tricep-extension-side.mp4#t=0.1","howTo":"You can use any attachment. The cable should be all the way to the bottom of the machine. Face away from the machine. Point your elbows straight up toward the ceiling. From there, extend your elbows until your fists are pointed straight toward the ceiling.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":224,"name":"Band Overhead Tricep Extension","equipment":"Band","primaryMuscles":["Triceps"],"difficulty":"Advanced","grips":"Overhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-overhead-tricep-extension-front.mp4#t=0.1","howTo":"Stand with one or both feet on band. Go up and over your head with the band to the starting position. Flex and extend your elbows.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":225,"name":"Band Pushdown","equipment":"Band","primaryMuscles":["Triceps"],"difficulty":"Beginner","grips":"Overhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-pushdown-front.mp4#t=0.1","howTo":"Place the band just above eye level. Take a few steps away until the band is taut. Push your hips back slightly. Extend and flex at the elbows.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":226,"name":"Band Skullcrusher","equipment":"Band","primaryMuscles":["Triceps"],"difficulty":"Advanced","grips":"Overhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-skullcrusher-front.mp4#t=0.1","howTo":"Stand facing away from a band which is anchored to a high point. Extend and flex your elbows, keeping them pointed forward.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":227,"name":"Dumbbell Skullcrusher","equipment":"Dumbbell","primaryMuscles":["Triceps"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-skullcrusher-front_hgKANkM.mp4#t=0.1","howTo":"Lay flat on the floor or a bench with your fists extended to the ceiling and a neutral grip. Break at the elbows until your fists are by your temples. Then extend your elbows and flex your triceps at the top.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":228,"name":"Barbell Skullcrusher","equipment":"Barbell","primaryMuscles":["Triceps"],"difficulty":"Intermediate","grips":"Overhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-skullcrusher-front.mp4#t=0.1","howTo":"Take a shoulder width grip. Break at the elbows. Try to keep your elbows tucked in. Don\'t let them flare out. Stop the bar a few inches from your forehead and extend your elbows back up.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":229,"name":"Barbell Overhead Tricep Extension","equipment":"Barbell","primaryMuscles":["Triceps"],"difficulty":"Advanced","grips":"Overhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-overhead-extension-front.mp4#t=0.1","howTo":"Be careful getting the bar into place overhead. Push your elbows forward while keeping your elbows tucked in. Look for what feels like a stretch in your triceps. Extend your elbows until your fists are pointed at the ceiling.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":230,"name":"Dumbbell Decline Skullcrusher","equipment":"Dumbbell","primaryMuscles":["Triceps"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-decline-skullcrusher-front.mp4#t=0.1","howTo":"Start by lying on a decline bench with a dumbbell in each hand. Hold the dumbbells above your chest with your arms extended and your palms facing each other. This is the starting position. Slowly lower the dumbbells towards your forehead by bending your elbows. Keep your upper arms stationary and only move your forearms. Once the dumbbells are close to your forehead, reverse the motion by extending your elbows and returning to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":231,"name":"Dumbbell Rolling Tricep Extension","equipment":"Dumbbell","primaryMuscles":["Triceps"],"difficulty":"Advanced","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-rolling-tricep-extension-front.mp4#t=0.1","howTo":"Lay flat on a bench with two dumbbells pointed toward the ceiling. Break at the elbows until your forearms touch your biceps, then flex at the shoulder joint bringing your upper arms to the sides of your head. Bring your elbows back up until they are pointed at the ceiling, then extend your elbows.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":232,"name":"Dumbbell Overhead Tricep Extension","equipment":"Dumbbell","primaryMuscles":["Triceps"],"difficulty":"Beginner","grips":["Underhand,","Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-overhead-tricep-extension-front_XDCPLIr.mp4#t=0.1","howTo":"Stand or sit with a dumbbell in your hands, arms extended straight above your head. Lower the dumbbell behind your head by bending at the elbows. Keep your elbows close to your head and shoulders relaxed. Push the dumbbell back up to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":233,"name":"Dumbbell Tricep Kickback","equipment":"Dumbbell","primaryMuscles":["Triceps"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-tricep-kickback-front.mp4#t=0.1","howTo":"Start by standing with your feet shoulder-width apart and holding a dumbbell in one hand. Bend at the waist and place your opposite hand on your knee for support. From this starting position, extend your arm backwards so that the dumbbell is behind your body. Make sure to keep your elbow close to your body and your core engaged throughout the movement.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":234,"name":"Plate Curl To Overhead Press To Tricep Extension","equipment":"Plate","primaryMuscles":["Biceps","Triceps","Shoulders"],"difficulty":"Advanced","grips":["Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-curl-to-overhead-press-to-tricep-extension-front_LMFCnKf.mp4#t=0.1","howTo":"Stand with feet shoulder-width apart and the plate in front of the torso, palms facing forward. Curl the plate up to the front of the shoulder while keeping the elbows close to the body. Rotate the palms to face forward and press the plate overhead, locking out the arms. Lower the plate back behind the head to the starting position of a tricep extension. Push the plate back up overhead, then lower it back to the starting position and repeat for desired reps.","secondaryMuscles":["Shoulders"],"tertiaryMuscles":null,"popularity":0},{"id":235,"name":"Plate Overhead Tricep Extension","equipment":"Plate","primaryMuscles":["Triceps"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-overhead-tricep-extension-front.mp4#t=0.1","howTo":"Stand or sit with a weight plate in your hands, arms extended straight above your head Lower the weight plate behind your head by bending at the elbows. Keep your elbows close to your head and shoulders relaxed. Push the weight plate back up to starting position, extending your arms fully.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":236,"name":"Band Rapunzel Pushdown","equipment":"Band","primaryMuscles":["Triceps"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-rapunzel-pushdown-front.mp4#t=0.1","howTo":"Anchor the band to a high point and face away. Hold the band with both hands, placing your hands shoulder-width apart and keeping your elbows close to your body. Slowly extend your arms downward, keeping your elbows close to your body. Push the band down as far as you can, feeling the contraction in your triceps.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":237,"name":"Plate Overhead Press To Tricep Extension","equipment":"Plate","primaryMuscles":["Triceps","Shoulders"],"difficulty":"Intermediate","grips":"Neutral","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-overhead-press-to-tricep-extension-front.mp4#t=0.1","howTo":"Brace your core and press the weight plate overhead until your arms are fully extended. Keep your shoulders down and back. While your arms are fully extended, lower the weight behind your head to perform the extension After completing the extension, lower the weight to your chest, and perform the overhead press. Repeat","secondaryMuscles":["Shoulders"],"tertiaryMuscles":null,"popularity":0},{"id":238,"name":"Band Single Arm Pushdown","equipment":"Band","primaryMuscles":["Triceps"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-single-arm-pushdown-front.mp4#t=0.1","howTo":"Stand with your feet shoulder-width apart and hold the band with your right hand, with your arm at your side. Flex and extend your elbow.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":239,"name":"Single Arm Rapunzel Pushdown","equipment":"Bodyweight","primaryMuscles":["Triceps"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-single-arm-rapunzel-pushdown-front.mp4#t=0.1","howTo":"Stand with a band anchored to a high point. Face away from the band. Hold the loop in one hand. Keep your elbow tucked in to your side. Extend your elbow. When you extend, don\'t let your upper arm raise. The band should land over your shoulder.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":240,"name":"Band Single Arm Skullcrusher","equipment":"Band","primaryMuscles":["Triceps"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-single-arm-skullcrusher-front.mp4#t=0.1","howTo":"Stand facing away from a band which is anchored to a high point. Keep your elbow pointed forward, and extend and flex your elbow.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":241,"name":"Dumbbell Single Arm Overhead Tricep Extension","equipment":"Dumbbell","primaryMuscles":["Triceps"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-single-arm-overhead-tricep-extension-front.mp4#t=0.1","howTo":"Stand tall with a single dumbbell extended overhead. Flex at the elbow letting the dumbbell travel behind your body. Try not to let your elbow flare outward.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":242,"name":"Dumbbell Tate Press","equipment":"Dumbbell","primaryMuscles":["Triceps"],"difficulty":"Intermediate","grips":"Overhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-tate-press-front.mp4#t=0.1","howTo":"Lay flat on a bench with two dumbbells extended toward the ceiling. Maintain an overhand grip. Flex at the elbows. The dumbbells will land on your upper chest/clavicle. Extend your elbows bringing the dumbbells back into their starting position. *Named after Dave Tate*","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":243,"name":"TRX Skullcrusher","equipment":"TRX","primaryMuscles":["Triceps"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-skullcrusher-front.mp4#t=0.1","howTo":"Hold the two TRX straps and lean forward. The straps should be over each shoulder. Keep your elbows tucked in and then flex and extend at the elbows.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":244,"name":"Dumbbell Lateral Raise","equipment":"Dumbbell","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":"Overhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-lateral-raise-front.mp4#t=0.1","howTo":"Stand up straight with dumbbells at either side, palms facing your hips. Raise your arms on either side with a slight bend in your elbow until they are parallel with the floor. Pause at the top of the motion. Slowly return your arms down to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":14},{"id":245,"name":"Dumbbell Rear Delt Fly","equipment":"Dumbbell","primaryMuscles":["Shoulders"],"difficulty":"Intermediate","grips":"Underhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-rear-delt-fly-front.mp4#t=0.1","howTo":"With dumbbells in either hand, bend your knees with your feet slightly bowed out. Arch your back above your knees, and start with the weights touching in front of your chest. With bent elbows, raise your arms up to shoulder level, pausing at the at the end of the motion. Slowly lower your arms back to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":2},{"id":246,"name":"Machine Face Pulls","equipment":"Machine","primaryMuscles":["Shoulders"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-machine-face-pull-front_i9CjsBg.mp4#t=0.1","howTo":"Facing the pulley, pull the weight towards you while keeping your arms parallel to the ground. Pull your hands back to both sides of your head and hold the position. Slowly return weight to starting position. Repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":247,"name":"Dumbbell Seated Overhead Press","equipment":"Dumbbell","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-seated-overhead-press-front.mp4#t=0.1","howTo":"Sit on a bench with back support. Raise the dumbbells to shoulder height with your palms forward. Raise the dumbbells upwards and pause at the contracted position. Lower the weights back to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":248,"name":"Dumbbell Front Raise","equipment":"Dumbbell","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-front-raise-front.mp4#t=0.1","howTo":"Grab two dumbbells while standing upright with the dumbbells at your side. Raise the two dumbbells with your elbows being fully extended until the dumbbells are eye level. Lower the weights in a controlled manner to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":3},{"id":249,"name":"Dumbbell Seated Rear Delt Fly","equipment":"Dumbbell","primaryMuscles":["Shoulders"],"difficulty":"Intermediate","grips":"Underhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-seated-rear-delt-fly-front.mp4#t=0.1","howTo":"With dumbbells in either hand, bend your knees with your feet slightly bowed out. Arch your back above your knees, and start with the weights touching in front of your chest. With bent elbows, raise your arms up to shoulder level, pausing at the at the end of the motion. Slowly lower your arms back to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":250,"name":"Kettlebell Rear Delt Row","equipment":"Kettlebell","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":"Overhand","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-rear-delt-row-front.mp4#t=0.1","howTo":"Stand with your feet shoulder width apart, holding the kettlebell with both hands in front of your thighs. Bend forward at the hips bringing the kettlebell to the floor while you slightly bend your knees, keeping your back straight. Lift the kettlebell upwards towards your upper chest and then lower the kettlebell- repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":251,"name":"Kettlebell Front Raise","equipment":"Kettlebell","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-frontraise-front.mp4#t=0.1","howTo":"Stand up straight with feet shoulder width apart, holding the kettlebell in front of your pelvis. Keeping arms straight, raise the kettlebell slightly higher than head level. Return to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":252,"name":"Kettlebell Single Arm Rear Delt Fly","equipment":"Kettlebell","primaryMuscles":["Shoulders"],"difficulty":"Intermediate","grips":"Underhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-single-arm-rear-delt-fly-front.mp4#t=0.1","howTo":"Stand with your feet shoulder width apart holding the kettlebell with both hands in front of your thighs. Bend forward at the hips bringing the kettlebell to the floor while you slightly bend your knees, keeping your back straight. Bring one arm behind you and rest this arm on your back. With the other arm, hold the kettlebell at arms length close to the floor. Swing the kettlebell out and up towards the side of your body and then return to centre. Repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":253,"name":"Kettlebell Long Lever Lateral Raise","equipment":"Kettlebell","primaryMuscles":["Shoulders"],"difficulty":"Intermediate","grips":"Overhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-long-lever-lateral-raise-front.mp4#t=0.1","howTo":"Stand with feet shoulder width apart holding a kettlebell with one hand at your side. Keeping your arm straight, swing the kettlebell up and out, away from your body to around head height, holding on to the kettlebell firmly so it does not change position in your hand. Return to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":254,"name":"Kettlebell Single Arm Lateral Raise","equipment":"Kettlebell","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":"Overhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-single-arm-lateral-raise-front.mp4#t=0.1","howTo":"Stand with feet shoulder width apart holding a kettlebell with one hand at your side. Keeping your arm straight, swing the kettlebell up and out, away from your body to around head height. Return to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":255,"name":"Shoulders Stretch Variation Four","equipment":"Stretch","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/female-shoulders-stretch-variation-4-front.mp4#t=0.1","howTo":"Stand with you feet shoulder width apart. Place one arm across the front of your chest at shoulder height, press the forearm of your other arm above the elbow, hooking the stretching arm with your hand. Press the arm until it is straight and rotate your upper torso to engage the stretch even deeper. Repeat with your other arm.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":256,"name":"Shoulders Stretch Variation Three","equipment":"Stretch","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-shoulders-stretch-variation-3-front.mp4#t=0.1","howTo":"Place the top of your hand into the small of your back, your arm at a 90 degree angle. Hold your elbow with the other arm, and slowly pull the arm forward until you feel your shoulder engaged in the stretch. Pause at the apex of the stretch and return to the starting position. Return to starting position, and repeat with your other arm.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":257,"name":"Shoulders Stretch Variation Two","equipment":"Stretch","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-shoulders-stretch-variation-2-front.mp4#t=0.1","howTo":"Start with your arms at either side. Begin by pushing your shoulders forward and in towards your chest. Repeat as necessary. Continue the circular motion with your shoulders, pinching up towards your ears, and then extending your chest outwards while you finish the motion.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":258,"name":"Shoulders Stretch Variation One","equipment":"Stretch","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-shoulders-stretch-variation-1-front.mp4#t=0.1","howTo":"Reach one arm behind your body, with your elbow pointing upward behind your head. Assist the stretch with your other hand on your elbow to engage your shoulder. Pause for a few seconds, then repeat the stretch with your other arm.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":259,"name":"Elevated Pike Press","equipment":"Bodyweight","primaryMuscles":["Traps","Shoulders"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-pike-pushup-front.mp4#t=0.1","howTo":"Use a bench or an object to elevate your feet. Lower your head towards the floor by bending your elbows Push through your hands and return to the starting pike position. Repeat","secondaryMuscles":["Traps"],"tertiaryMuscles":["Triceps"],"popularity":0},{"id":260,"name":"Cable Overhead Press","equipment":"Cable","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":"Underhand","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-overhead-press-front.mp4#t=0.1","howTo":"Use a handle attachment with the cable set to the bottom of the machine. Stand upright making sure to maintain a flat back. Your starting position will have your palms facing forward. Use both your elbows and shoulders to press the weight directly overhead.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":1},{"id":261,"name":"Cable Lateral Raise","equipment":"Cable","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-lateral-raise-front.mp4#t=0.1","howTo":"Use a handle attachment with the cable set all the way to the bottom of the machine. You should vertically abduct at the shoulder raising your arm straight out to the side. Raise until your arm is parallel with the ground and then back to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":4},{"id":262,"name":"Cable Rear Delt Fly","equipment":"Cable","primaryMuscles":["Shoulders"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-rear-delt-fly-front.mp4#t=0.1","howTo":"Use a handle attachment or no attachment at all. The cable should be set to the top. Walk a few steps away with the cable coming from the opposing side of the working arm. From there, your shoulders should horizontally abduct and adduct, while your elbows stay in a fixed position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":2},{"id":263,"name":"Cable Upright Row","equipment":"Cable","primaryMuscles":["Traps","Shoulders"],"difficulty":"Advanced","grips":["Underhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-upright-row-side.mp4#t=0.1","howTo":"Use a handle attachment with the cable set to the bottom of the machine. Pull your elbows straight up toward the ceiling until the attachment is just below your chin then extend until your elbows are fully extended.","secondaryMuscles":["Traps"],"tertiaryMuscles":null,"popularity":2},{"id":264,"name":"Band Face Pull","equipment":"Band","primaryMuscles":["Shoulders"],"difficulty":"Intermediate","grips":"Overhand","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-face-pull-front.mp4#t=0.1","howTo":"Anchor the band at eye level. Take a few steps away until the band is taut. Use an overhand grip with both hands. Pull the band to the bridge of your nose flaring your elbows out.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":265,"name":"Band Front Raise","equipment":"Band","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-front-raise-front.mp4#t=0.1","howTo":"Stand on the band with one or 2 feet depending on how heavy you want the band to be. With your elbows extended raise your fists straight up to the ceiling until they are at eye level.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":266,"name":"Band Lateral Raise","equipment":"Band","primaryMuscles":["Shoulders"],"difficulty":"Intermediate","grips":"Overhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-lateral-raise-front.mp4#t=0.1","howTo":"Grab the band at shoulder width. Raise your arms straight out to the side. The band should scrape against your shirt.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":267,"name":"Band Pull Apart","equipment":"Band","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-pull-apart-front.mp4#t=0.1","howTo":"Grab the band with a shoulder width grip. Point your arms straight in front of you. Retract your shoulder blades and shoulder joint until the band taps your chest.","secondaryMuscles":["Traps","Traps (mid-back)"],"tertiaryMuscles":null,"popularity":1},{"id":268,"name":"Band Single Arm Overhead Press","equipment":"Band","primaryMuscles":["Traps","Shoulders"],"difficulty":"Intermediate","grips":"Underhand","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-single-arm-overhead-press-front.mp4#t=0.1","howTo":"Loop the band under one of your feet. The other end of the bed should be in your hand between your thumb and pointer finger. Press the band straight up towards the ceiling. Until your elbow is fully extended.","secondaryMuscles":["Triceps"],"tertiaryMuscles":["Traps"],"popularity":0},{"id":269,"name":"Barbell Front Raise","equipment":"Barbell","primaryMuscles":["Shoulders"],"difficulty":"Intermediate","grips":"Overhand","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-front-raise-front.mp4#t=0.1","howTo":"Stand tall with an overhand grip on the barbell. Raise your arms until your fists are around eye level. Return to the start under control. This exercise is prone to using momentum when you begin to fatigue.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":3},{"id":270,"name":"Barbell Overhead Press","equipment":"Barbell","primaryMuscles":["Shoulders"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-overhead-press-front_wHKQjdY.mp4#t=0.1","howTo":"Take a roughly shoulder width grip. There should be a straight line from your elbow to fist (vertical forearms). Pull your chin back and press the weight toward the ceiling by extending at the elbow joint and flexing at the shoulder joint. Press until your elbows are extended and push your head forward slightly. Return to the start position with control. Pulling your chin back to allow the bar to pass your face safely.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":2},{"id":271,"name":"Barbell Upright Row","equipment":"Barbell","primaryMuscles":["Traps","Shoulders"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-upright-row-front.mp4#t=0.1","howTo":"Take a double overhand roughly shoulder width grip. Pull your elbows straight up the ceiling. Aim to get the bar to chin level or slightly higher.","secondaryMuscles":["Traps"],"tertiaryMuscles":null,"popularity":5},{"id":272,"name":"Dumbbell Rear Delt Row","equipment":"Dumbbell","primaryMuscles":["Shoulders"],"difficulty":"Advanced","grips":"Overhand","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-rear-delt-row-front.mp4#t=0.1","howTo":"Hinge forward at the hips while maintaining a flat back. Try to get your torso as close to parallel with the ground as your mobility will allow for. Let your arms hang in front of you. Pull your elbows back towards the ceiling while flaring your elbows outward.","secondaryMuscles":["Traps","Traps (mid-back)"],"tertiaryMuscles":null,"popularity":1},{"id":273,"name":"Barbell Z Press","equipment":"Barbell","primaryMuscles":["Traps","Triceps","Shoulders"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-z-press-front.mp4#t=0.1","howTo":"Begin by sitting on the ground with your legs extended and a barbell in your hands, with your palms facing forward and your elbows bent. Keeping your core engaged and your back straight, lift the barbell up from your chest and press it straight up above your head. Lower the barbell back down to your chest.","secondaryMuscles":["Traps"],"tertiaryMuscles":["Triceps"],"popularity":1},{"id":274,"name":"Dumbbell Bayesian Lateral Raise","equipment":"Dumbbell","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-bayesian-lateral-raise-front.mp4#t=0.1","howTo":"Lay on an incline bench and let your arms freely. Lateral raise your arms straight out to the side until your arms are about parallel with the ground.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":275,"name":"Dumbbell Laying Reverse Fly","equipment":"Dumbbell","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-laying-reverse-fly-front.mp4#t=0.1","howTo":"With dumbbells in either hand, lay on an incline bench that\'s at about 15-30 degrees. With bent elbows, raise your arms up to shoulder level, pausing at the at the end of the motion. Slowly lower your arms back to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":276,"name":"Dumbbell Laying Reverse Fly Internally Rotated","equipment":"Dumbbell","primaryMuscles":["Shoulders"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-laying-reverse-fly-internally-rotated-front.mp4#t=0.1","howTo":"With dumbbells in either hand and an overhand grip, lay on an incline bench that is roughly 15 - 30 degrees high. With bent elbows, raise your arms up to shoulder level, pausing at the at the end of the motion. Slowly lower your arms back to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":277,"name":"Dumbbell Neutral Seated Overhead Press","equipment":"Dumbbell","primaryMuscles":["Triceps","Shoulders"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-neutral-seated-overhead-press-front.mp4#t=0.1","howTo":"Sit on an upright bench , grasp a pair of dumbbells and hold them at shoulder level with your palms facing each other. Keep your elbows bent and close to your body. Slowly lower the dumbbells to your shoulder joint, keeping your elbows bent and close to your body. Once the dumbbells reach your chest, pause for a moment and then press them back up to the starting position. This variation is much easier on the shoulder joints.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":278,"name":"Dumbbell Seated Arnold Press","equipment":"Dumbbell","primaryMuscles":["Triceps","Shoulders"],"difficulty":"Intermediate","grips":["Rotating"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-seated-arnold-press-front.mp4#t=0.1","howTo":"Begin seated on an upright bench with your palms facing you. Begin pressing toward the ceiling. As you press, rotate your palms. As you extend your elbows fully your palms should be facing forward.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":279,"name":"Dumbbell Alternating Arnold Press","equipment":"Dumbbell","primaryMuscles":["Triceps","Shoulders"],"difficulty":"Advanced","grips":["Rotating"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-alternating-arnold-press-front.mp4#t=0.1","howTo":"Start in a standing position","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":280,"name":"Dumbbell Alternating Overhead Press","equipment":"Dumbbell","primaryMuscles":["Triceps","Shoulders"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-alternating-overhead-press-front.mp4#t=0.1","howTo":"Start with two dumbbells just above your shoulders. Press one dumbbell to the ceiling while keeping the other in place. Let the first dumbbell return to its starting position before pressing the other dumbbell.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":281,"name":"Dumbbell Arnold Press","equipment":"Dumbbell","primaryMuscles":["Shoulders"],"difficulty":"Intermediate","grips":["Rotating"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-arnold-press-front.mp4#t=0.1","howTo":"Stand with both palms facing you. Begin to press the dumbbells to the ceiling while rotating your palms. When you reach elbow extension, your palms should be facing forward.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":282,"name":"Dumbbell Neutral Alternating Overhead Press","equipment":"Dumbbell","primaryMuscles":["Triceps","Shoulders"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-neutral-alternating-overhead-press-front.mp4#t=0.1","howTo":"Start with two dumbbells near your shoulders with a neutral grip. Press one of the dumbbells toward the ceiling while keeping the other in position. Let the first dumbbell return to its starting position before pressing the other.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":283,"name":"Dumbbell Neutral Overhead Press","equipment":"Dumbbell","primaryMuscles":["Triceps","Shoulders"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-neutral-overhead-press-front.mp4#t=0.1","howTo":"Start with both dumbbells near your shoulders in a neutral grip. Press the dumbbells toward the ceiling. Make sure you don\'t arch your back as you fatigue.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":284,"name":"Dumbbell Overhead Press","equipment":"Dumbbell","primaryMuscles":["Triceps","Shoulders"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-overhead-press-front.mp4#t=0.1","howTo":"Start by standing with your feet shoulder-width apart and holding a dumbbell in each hand. Bring the dumbbells to your shoulders, with your palms facing forward and your elbows bent. From this starting position, extend your arms upwards so that the dumbbells are overhead. Make sure to keep your core engaged and your back straight throughout the movement.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":5},{"id":285,"name":"Dumbbell Push Press","equipment":"Dumbbell","primaryMuscles":["Triceps","Shoulders"],"difficulty":"Intermediate","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-push-press-front.mp4#t=0.1","howTo":"Start by standing with your feet shoulder-width apart and holding a dumbbell in each hand. From this starting position, dip your knees slightly and then quickly extend them as you press the dumbbells upwards. Make sure to keep your core engaged and your back straight throughout the movement. Slowly lower the dumbbells back down to the starting position, and repeat for the desired number of repetitions.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":2},{"id":286,"name":"Dumbbell Single Arm Arnold Press","equipment":"Dumbbell","primaryMuscles":["Triceps","Shoulders"],"difficulty":"Intermediate","grips":["Rotating"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-single-arm-arnold-press-front.mp4#t=0.1","howTo":"Start by standing with your feet shoulder-width apart and holding a dumbbell in one hand. Bring the dumbbell to your shoulder, with your palm facing you and your elbow bent. From this starting position, extend your arm upwards so that the dumbbell is directly above your head. As you extend your arm, rotate your palm to face away from your body.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":287,"name":"Dumbbell Single Arm Neutral Overhead Press","equipment":"Dumbbell","primaryMuscles":["Triceps","Shoulders"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-single-arm-neutral-overhead-press-front.mp4#t=0.1","howTo":"Start by standing with your feet shoulder-width apart and holding a dumbbell in one hand. Bring the dumbbell to your shoulder, with your palm facing your body and your elbow bent. From this starting position, press the dumbbell upwards so that it is directly above your shoulder.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":288,"name":"Dumbbell Single Arm Overhead Press","equipment":"Dumbbell","primaryMuscles":["Triceps","Shoulders"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-single-arm-overhead-press-front.mp4#t=0.1","howTo":"Start by standing with your feet shoulder-width apart and holding a dumbbell in one hand. Bring the dumbbell to your shoulder, with your palm facing forward and your elbow bent. From this starting position, extend your arm upwards so that the dumbbell is overhead. Make sure to keep your core engaged and your back straight throughout the movement.","secondaryMuscles":["Triceps"],"tertiaryMuscles":null,"popularity":0},{"id":289,"name":"Plate Car Driver","equipment":"Plate","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-car-driver-front.mp4#t=0.1","howTo":"Inhale and brace your abdominals Raise the arms vertically while keeping the elbows slightly bent Once the arms are parallel with the floor, rotate the plate clockwise and counterclockwise. Lower the plate back to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":290,"name":"Plate Front Raise","equipment":"Plate","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-front-raise-front.mp4#t=0.1","howTo":"Stand with feet shoulder-width apart and the plate in front of the torso, palms facing the thighs. Keeping the elbows slightly bent, lift the plate up to the front of the body. Raise the plate up until the arms are fully extended, maintaining control of the plate. Lower the plate back to the starting position and repeat for desired reps.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":291,"name":"Plate Halo","equipment":"Plate","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-halo-front.mp4#t=0.1","howTo":"Stand with feet shoulder-width apart and the plate held in front of your face with both hands, palms facing each other. Rotate the plate around the head, keeping the arms extended and moving the plate in a circular motion. Complete one full circle, then reverse the direction to complete another circle.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":292,"name":"Band High Face Pull","equipment":"Band","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-face-pull-front_Rw6dM9Q.mp4#t=0.1","howTo":"Start with a band anchored to a high point. Stagger your stance. Pull the band to the bridge of your nose.","secondaryMuscles":["Traps","Traps (mid-back)"],"tertiaryMuscles":null,"popularity":0},{"id":293,"name":"Band Low Lateral Raise","equipment":"Band","primaryMuscles":["Shoulders"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-low-lateral-raise-front.mp4#t=0.1","howTo":"Anchor a band to a low point and stand with the band crossing your body. While keeping your elbow mostly extended, lift your arm until it\'s parallel with the floor.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":294,"name":"Band Mid Lateral Raise","equipment":"Band","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-mid-lateral-raise-front.mp4#t=0.1","howTo":"Anchor a band to a point that is the same height as your fist when your arms are at your side and stand with the band crossing your body. While keeping your elbow mostly extended, lift your arm until it\'s parallel with the floor.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":295,"name":"Band Overhead Press","equipment":"Band","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-overhead-press-front.mp4#t=0.1","howTo":"Stand between the two anchored bands, grasp them with an overhand grip, and position the bands at shoulder level. Brace your core and push the bands overhead, fully extending your arms. Lower the bands back to shoulder level, keeping your core engaged and arms straight. Repeat for desired number of reps.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":296,"name":"Band Rear Delt Fly","equipment":"Band","primaryMuscles":["Shoulders"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-rear-delt-fly-front.mp4#t=0.1","howTo":"Start by standing between the two anchored bands with your feet shoulder-width apart and the bands positioned at a high point. Grasp the ends of each band with your hands, keeping your palms facing each other. Keeping your arms slightly bent and your back straight, slowly pull the bands away from your body until your arms are extended straight out to the sides. Hold for a second, then slowly release back to the starting position. Repeat for desired reps.","secondaryMuscles":["Traps","Traps (mid-back)"],"tertiaryMuscles":null,"popularity":0},{"id":297,"name":"Plate Full Lateral Raise","equipment":"Plate","primaryMuscles":["Shoulders"],"difficulty":"Intermediate","grips":["Rotating"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-full-lateral-raise-front.mp4#t=0.1","howTo":"Stand tall holding two plates at your side. Lateral raise the plates to your side and continue until the plates are pointed at the ceiling. Let your shoulder joint naturally rotate. At the bottom you should have a neutral or overhand grip. By the time the plates are overhead, your palms should be facing forward.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":298,"name":"Plate Internally Rotated Rear Delt Fly","equipment":"Plate","primaryMuscles":["Shoulders"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-internally-rotated-rear-delt-fly-front.mp4#t=0.1","howTo":"With plates in either hand, bend your knees with your feet slightly bowed out. Hinge forward with a flat back. Maintain an overhand grip and internally rotated shoulders. Raise your arms backward toward the ceiling while maintaining a light band in your elbows.","secondaryMuscles":["Traps"],"tertiaryMuscles":null,"popularity":0},{"id":299,"name":"Plate Lateral Raise","equipment":"Plate","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-lateral-raise-front.mp4#t=0.1","howTo":"Stand with feet shoulder-width apart and grip two plates in each hand at your sides. Keeping your arms straight, raise the plates out to your sides until they are in line with your shoulders. Lower the plates back to your sides with control. Repeat for desired number of reps.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":300,"name":"Plate Rear Delt Fly","equipment":"Plate","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-rear-delt-fly-front.mp4#t=0.1","howTo":"Keep your back straight and bend forward slightly at the waist. With arms extended, raise the weights out to your sides until they are in line with your shoulders. Pause briefly and then lower the weights back to the starting position.","secondaryMuscles":["Traps","Traps (mid-back)"],"tertiaryMuscles":null,"popularity":0},{"id":301,"name":"Plate Reach","equipment":"Plate","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-standing-reach-front.mp4#t=0.1","howTo":"Start in a standing position with a plate against your chest. Press the plate away from your body until your elbows are extended.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":302,"name":"Laying Lateral Raise","equipment":"Bodyweight","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Overhand,","Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-laying-lateral-raise-front.mp4#t=0.1","howTo":"Lay on your side on a bench or box. Place one hand on the floor and the other hand is holding the dumbbell. While keeping your elbow mostly extended, raise the dumbbell to the side. The end of the range of motion is when the dumbbell is pointed toward the ceiling. Make sure you don\'t flex and extend your elbow.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":303,"name":"Dumbbell Single Arm Upright Row","equipment":"Dumbbell","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-single-arm-upright-row-front.mp4#t=0.1","howTo":"Stand with your feet shoulder-width apart, holding a dumbbell in one hand with an overhand grip. Keep your back straight and chest lifted, engage your core to maintain balance. Begin the movement by lifting the dumbbell straight up towards your chin, keeping your elbow close to your body and the weight in line with your shoulder. Continue to lift the weight until it reaches the chin or neck level, keeping the elbow high and close to the body. Lower the weight back down to the starting position with control.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":304,"name":"Dumbbell Upright Row","equipment":"Dumbbell","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-upright-row-front.mp4#t=0.1","howTo":"Stand with your feet shoulder-width apart, holding 2 dumbbells in each hand. Keep your back straight and chest lifted, engage your core to maintain balance. Begin the movement by lifting the dumbbells straight up towards your chin, keeping your elbow close to your body and the weight in line with your shoulder. Continue to lift the weight until it reaches the chin or neck level, keeping the elbow high and close to the body.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":4},{"id":305,"name":"TRX I Raise","equipment":"TRX","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-I-raise-front.mp4#t=0.1","howTo":"Stand facing the TRX straps and hold onto the handles with an overhand grip, keeping your arms straight and hands slightly wider than shoulder-width apart. Keeping your core engaged, slowly raise your arms forward until they are overhead. Pause for a moment at the top of the movement, then slowly lower your arms back to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":306,"name":"TRX Rear Delt Fly","equipment":"TRX","primaryMuscles":["Shoulders"],"difficulty":"Intermediate","grips":["Overhand,","Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-rear-delt_fly-front.mp4#t=0.1","howTo":"Stand facing away from the TRX straps and grab the handles with both hands. Step forward so that your body is in a plank position, with your arms straight and your body in a straight line from your head to your heels. Keeping your arms straight, slowly lift your arms out to the side, keeping them at the same height as your shoulders. Your body should form a \\"T\\" shape.","secondaryMuscles":["Traps","Traps (mid-back)"],"tertiaryMuscles":null,"popularity":0},{"id":307,"name":"TRX Rear Delt Row","equipment":"TRX","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-rear-delt-row-front.mp4#t=0.1","howTo":"Stand facing away from the TRX straps and grab the handles with both hands. Step away so your body is leaning away from the anchor point. Flex your elbows and pull your elbows straight back behind your body. Make sure to keep your elbows flared outward.","secondaryMuscles":["Traps","Traps (mid-back)"],"tertiaryMuscles":null,"popularity":0},{"id":308,"name":"TRX W Raise","equipment":"TRX","primaryMuscles":["Shoulders"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-W-raise-front.mp4#t=0.1","howTo":"Hold the TRX straps and lean away from the anchor point. Pull your elbows back while externally rotating your shoulder joint. Your arms should make a W shape at the back portion of the exercise.","secondaryMuscles":["Traps","Traps (mid-back)"],"tertiaryMuscles":null,"popularity":0},{"id":309,"name":"TRX Y Raise","equipment":"TRX","primaryMuscles":["Traps","Shoulders"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-y-raise-front.mp4#t=0.1","howTo":"Hold the TRX straps and lean away from the anchor point until the straps are taut. Keep both elbows mostly extended and raise both arms out and upwards. You should make a Y shape with your arms during the back portion of the exercise.","secondaryMuscles":["Traps"],"tertiaryMuscles":["Traps","Traps (mid-back)"],"popularity":0},{"id":310,"name":"Plate Squat Hold Reach","equipment":"Plate","primaryMuscles":["Quads","Triceps","Shoulders","Glutes"],"difficulty":"Intermediate","grips":"Neutral","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-squat-hold-reach-front.mp4#t=0.1","howTo":"Hold the plate with both hands at chest height. Keeping your core tight and your chest up, squat down as low as you can go while keeping your feet flat on the ground. Hold the squat position and reach the plate forward, keeping your arms straight and your back straight. Return the plate to your chest while you hold the squat position and repeat reaching the plate in front of you","secondaryMuscles":["Quads","Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":311,"name":"Machine Pulldown","equipment":"Machine","primaryMuscles":["Lats"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-machine-pulldown-front.mp4#t=0.1","howTo":"Grip the bar with the palms facing forward, your hands need to be spaced out at a distance wider than shoulder width. As you have both arms extended in front of you holding the bar, bring your torso back around 30 degrees while sticking your chest out. Pull the bar down to about chin level or a little lower in a smooth movement whilst squeezing the shoulder blades together. After a second of squeezing, slowly raise the bar back to the starting position when your arms are fully extended.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":312,"name":"Machine Seated Cable Row","equipment":"Machine","primaryMuscles":["Lats"],"difficulty":"Beginner","grips":["Overhand,","Underhand,","Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-machine-seated-cable-row-front.mp4#t=0.1","howTo":"Sit with your back straight on the machine and grip the handles. Pull the handles back using your arms. Your legs and torso should be at a 90° angle. Push out your chest. Pull the handles towards your body until your hands are beside your abdomen.","secondaryMuscles":["Biceps"],"tertiaryMuscles":["Traps","Traps (mid-back)"],"popularity":0},{"id":313,"name":"Pull Ups","equipment":"Bodyweight","primaryMuscles":["Lats"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-pullup-front.mp4#t=0.1","howTo":"Grasp the bar with an overhand grip, arms and shoulders fully extended. Pull your body up until your chin is above the bar. Lower your body back to starting position.","secondaryMuscles":["Traps","Traps (mid-back)"],"tertiaryMuscles":["Biceps"],"popularity":30},{"id":314,"name":"Dumbbell Row Bilateral","equipment":"Dumbbell","primaryMuscles":["Lats"],"difficulty":"Intermediate","grips":"Overhand","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-row-bilateral-front.mp4#t=0.1","howTo":"Grab both dumbbells and hinge forward at the hips. Make sure you keep a flat back. The closer your torso is to parallel with the ground the longer the range of motion will be at your shoulder. The better the results you\'ll get from the exercise. Let your arms hang freely, and then pull your elbow joint straight back toward the ceiling.","secondaryMuscles":["Biceps"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":315,"name":"Barbell Bent Over Row","equipment":"Barbell","primaryMuscles":["Lats"],"difficulty":"Intermediate","grips":["Underhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-bent-over-row-front.mp4#t=0.1","howTo":"Grab a barbell with a shoulder width pronated or supinated grip. Bend forward at your hips while maintaining a flat back. Pull the weight toward your upper abdomen. Lower the weight in a controlled manner and repeat.","secondaryMuscles":["Biceps"],"tertiaryMuscles":["Forearms"],"popularity":5},{"id":316,"name":"Kettlebell Row","equipment":"Kettlebell","primaryMuscles":["Lats"],"difficulty":"Beginner","grips":"Overhand","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-row-front.mp4#t=0.1","howTo":"Stand with your feet shoulder width apart holding the kettlebell with both hands in front of your thighs. Bend forward at the hips bringing the kettlebell to the floor while you slightly bend your knees, keeping your back straight. Lift the kettlebell upwards towards your chest and lower - repeat.","secondaryMuscles":["Biceps"],"tertiaryMuscles":["Forearms"],"popularity":1},{"id":317,"name":"Kettlebell Shoulder Extension","equipment":"Kettlebell","primaryMuscles":["Lats"],"difficulty":"Intermediate","grips":"Overhand","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-shoulder-extension-front.mp4#t=0.1","howTo":"Stand with your feet shoulder width apart bending forward at the hips as far as comfortable. Place off-hand on the same side thigh for stability. Hold the kettlebell in one hand, straight armed and pointing towards the floor. Keeping your arm straight, swing the kettlebell behind you as far as comfortable. Return to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":318,"name":"Kettlebell Single Arm Row","equipment":"Kettlebell","primaryMuscles":["Lats"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-single-arm-row-front.mp4#t=0.1","howTo":"Stand with your feet shoulder width apart, shifting one foot behind you. Hold the kettlebell in the same hand as the leg shifted backwards. Bend forwards at the hips bringing the kettlebell to the floor while you slightly bend your knee, keeping your back straight. Lift the kettlebell upwards towards your chest and lower - repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":319,"name":"Kettlebell Pullover","equipment":"Kettlebell","primaryMuscles":["Lats"],"difficulty":"Advanced","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-pullover-front.mp4#t=0.1","howTo":"Rest your upper back on the bench and place soles of your feet firmly on the floor keeping torso and thighs suspended and parallel to the floor. Hold the kettlebell with both hands above your chest, keeping your arms straight. Keeping your arms straight, move the kettlebell in the direction of your head until your arms are parallel to the floor. Return to starting to position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":320,"name":"Lats Stretch Variation Three","equipment":"Stretch","primaryMuscles":["Lats"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-lats-stretch-variation-3-front.mp4#t=0.1","howTo":"Find a wall to lean against, lay your tricep against the wall with your hand behind your back. Slowly lean into the wall. Return to starting position, then switch sides.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":321,"name":"Lats Stretch Variation Two","equipment":"Stretch","primaryMuscles":["Lats"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-lats-stretch-variation-2-front.mp4#t=0.1","howTo":"Stand up right and raise your hand to a full stretch above your head. Slowly lean across your body and trace the opposite hand down your leg. Hold at the bottom of the stretch, return to starting position and then switch sides.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":322,"name":"Lats Stretch Variation One","equipment":"Stretch","primaryMuscles":["Lats"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-lats-stretch-variation-1-front.mp4#t=0.1","howTo":"Place both hands on the wall in front of you. Slowly lower your body until you feel the stretch. Hold at the bottom of the stretch, return to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":323,"name":"Inverted Row","equipment":"Bodyweight","primaryMuscles":["Lats","Forearms"],"difficulty":"Beginner","grips":["Overhand,","Underhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-reverse-row-front.mp4#t=0.1","howTo":"Lay underneath a fixed horizontal bar and grab the bar with a wide overhand grip. Pull your body straight up to the bar. Return to the starting position, your arms fully extended. Repeat.","secondaryMuscles":["Biceps"],"tertiaryMuscles":["Forearms"],"popularity":11},{"id":324,"name":"Cable Lat Prayer","equipment":"Cable","primaryMuscles":["Lats"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-lat-prayer-side.mp4#t=0.1","howTo":"You can use any attachment. Cable should be set all the way to the top of the machine. Grab your attachment and walk a few steps back. Push your butt back to where you are leaning forward. Your ears should be between your arms. Initiate the movement with your shoulders and not your elbows. As you flex at the shoulder joint push your hips forward until your hips meet the attachment.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":325,"name":"Cable Pullover","equipment":"Cable","primaryMuscles":["Lats"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-pullover-side.mp4#t=0.1","howTo":"You can use any attachment. Cable should be set all the way to the top of the machine. Grab your attachment and walk a few steps back. Push your butt back to where you are leaning forward somewhat. Initiate the movement with your shoulders and not your elbows. Imagine trying to pull the attachment through your thighs at the bottom.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":2},{"id":326,"name":"Cable Pull In","equipment":"Cable","primaryMuscles":["Lats"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-pull-in-front.mp4#t=0.1","howTo":"Use a handle attachment set all the way to the top of the cable crossover machine. Walk a few steps away from the cable machine. Face your body sideways. Face your palm up toward the ceiling. Then pull your elbow in toward your rib cage.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":327,"name":"Band Kneeling Single Arm Pulldown","equipment":"Band","primaryMuscles":["Biceps","Lats"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-kneeling-single-arm-pulldown-front.mp4#t=0.1","howTo":"Place the band at about eye level. Fall into a kneeling position. The knee that is on the ground should be the same side as the working arm. Stick your chest out. And then pull your elbow straight back. Flex your lats and then extend into the starting position.","secondaryMuscles":["Biceps"],"tertiaryMuscles":null,"popularity":0},{"id":328,"name":"Band Pullover","equipment":"Band","primaryMuscles":["Lats"],"difficulty":"Intermediate","grips":"Neutral","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-pull-over-front.mp4#t=0.1","howTo":"Place the band just above our level. Take a few steps away until the band is taut. Push your hips back slightly. Extend and flex at the shoulder joint.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":329,"name":"Band Row","equipment":"Band","primaryMuscles":["Lats"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-row-front.mp4#t=0.1","howTo":"Stand on your band with both feet. Hinge forward at the hips while keeping a flat back. Let your arms hang freely, then pull your elbows straight back toward the ceiling.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":330,"name":"Dumbbell Row Unilateral","equipment":"Dumbbell","primaryMuscles":["Lats","Forearms"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-row-unilateral-front.mp4#t=0.1","howTo":"Brace your off arm against something stable (bench, box). Stagger your stance so your leg on the side of your working arm is back. Try to get your torso to parallel with the ground. That will extend your range of motion. Let your arm hang freely and then pull your elbow back. Imagine you\'ve got a tennis ball in your armpit and squeeze it each rep.","secondaryMuscles":["Biceps"],"tertiaryMuscles":["Forearms"],"popularity":0},{"id":331,"name":"Barbell Landmine Row","equipment":"Barbell","primaryMuscles":["Biceps","Traps","Lats","Forearms","Traps (mid-back)"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-landmine-row-front.mp4#t=0.1","howTo":"Position a barbell in a landmine or corner of a room and stand facing it with your feet shoulder-width apart. Grasp the end of the barbell with a neutral grip, keeping your arms straight and your shoulders relaxed. Bend at the hips and knees to lower your torso until it is almost parallel to the ground. Pull the barbell towards your chest, squeezing your shoulder blades together as you row the weight up.","secondaryMuscles":["Biceps"],"tertiaryMuscles":["Forearms"],"popularity":0},{"id":332,"name":"Barbell Long Landmine Row","equipment":"Barbell","primaryMuscles":["Biceps","Lats","Forearms"],"difficulty":"Advanced","grips":["Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-long-landmine-row-front.mp4#t=0.1","howTo":"Position a barbell in a landmine or corner of a room and stand facing it with your feet shoulder-width apart. Grasp the end of the barbell with an overhand grip, keeping your arms straight and your shoulders relaxed. Bend at the hips and knees to lower your torso until it is almost parallel to the ground. Pull the barbell towards your chest, squeezing your shoulder blades together as you row the weight up.","secondaryMuscles":["Biceps"],"tertiaryMuscles":["Forearms"],"popularity":0},{"id":333,"name":"Barbell Meadows Row","equipment":"Barbell","primaryMuscles":["Biceps","Lats","Forearms"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-meadows-row-side.mp4#t=0.1","howTo":"Position a barbell in a landmine or corner of a room and stand facing sideways with a staggered stance and your feet shoulder-width apart. Grasp the end of the barbell with an overhand grip, keeping your arms straight and your shoulders relaxed. Bend at the hips and knees to lower your torso until it is almost parallel to the ground. Pull the barbell towards your chest, squeezing your shoulder blades together as you row the weight up. *Named after the late John Meadows","secondaryMuscles":["Biceps"],"tertiaryMuscles":["Forearms"],"popularity":0},{"id":334,"name":"Barbell Pronated Pendlay Row","equipment":"Barbell","primaryMuscles":["Biceps","Lats"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-pronated-pendlay-row-front.mp4#t=0.1","howTo":"Start hinged forward with a flat back and the plates resting on the floor. Make sure your elbows are fully extended. Pull the bar to your sternum. Return the plates back to the floor and let the bar come to a full dead stop. Then initiate the next rep.","secondaryMuscles":["Biceps"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":335,"name":"Barbell Pronated Row","equipment":"Barbell","primaryMuscles":["Biceps","Lats","Forearms"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-pronated-row-front.mp4#t=0.1","howTo":"Grab the barbell with an overhand grip. Hinge forward while keeping your back flat until your torso is about parallel with the ground. Let your arms hang freely. Pull the bar to your torso while tucking your elbows in slightly. Extend your elbows fully before initiating the next rep.","secondaryMuscles":["Biceps"],"tertiaryMuscles":["Forearms"],"popularity":0},{"id":336,"name":"Barbell Supinated Pendlay Row","equipment":"Barbell","primaryMuscles":["Biceps","Lats"],"difficulty":"Advanced","grips":["Underhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-supinated-pendlay-row-front.mp4#t=0.1","howTo":"Begin by standing in front of a barbell with your feet about hip-width apart and your palms facing towards your body. Bend at the hips and knees to grab the barbell with a pronated (overhand) grip, positioning the barbell about an inch away from your shins. Keeping your back straight and your core engaged, use your back muscles to lift the barbell straight up towards your chest. As the barbell reaches your chest, rotate your wrists so that your palms are facing towards your body (supinated grip), and then lower the barbell back to the starting position.","secondaryMuscles":["Biceps"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":337,"name":"Barbell Supinated Row","equipment":"Barbell","primaryMuscles":["Biceps","Lats"],"difficulty":"Advanced","grips":["Underhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-supinated-row-front.mp4#t=0.1","howTo":"Begin by standing in front of a barbell with your feet about hip-width apart. Bend at the hips and knees to grab the barbell with a supinated (underhand) grip, positioning the barbell about an inch away from your shins. Keeping your back straight and your core engaged, use your back muscles to lift the barbell straight up towards your chest. As the barbell reaches your chest, pause briefly, and then lower the barbell back to the starting position.","secondaryMuscles":["Biceps"],"tertiaryMuscles":null,"popularity":0},{"id":338,"name":"Dumbbell Pullover","equipment":"Dumbbell","primaryMuscles":["Lats"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-pullover-front.mp4#t=0.1","howTo":"Grab a dumbbell and hold with both hands. Point your dumbbell at the ceiling. Flex at the shoulder joint while keeping your elbows mostly extended. Flex until you feel a stretch in your lats then bring the dumbbell back to the ceiling.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":17},{"id":339,"name":"Dumbbell Alternating Pendlay Row","equipment":"Dumbbell","primaryMuscles":["Biceps","Lats"],"difficulty":"Advanced","grips":["Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-alternating-pendlay-row-front.mp4#t=0.1","howTo":"The dumbbells should be set on the ground. Hinge forward while keeping a flat back. Pull one elbow back toward the ceiling and then return the dumbbell to the ground softly. Then pull with the other arm.","secondaryMuscles":["Biceps"],"tertiaryMuscles":null,"popularity":0},{"id":340,"name":"Dumbbell Kneeling Single Arm Row","equipment":"Dumbbell","primaryMuscles":["Biceps","Lats"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-kneeling-single-arm-row-front.mp4#t=0.1","howTo":"Place one hand and one knee on a bench. Make sure you keep a flat back. Pull the dumbbell toward the ceiling. Make sure to avoid any jerking or rotating.","secondaryMuscles":["Biceps"],"tertiaryMuscles":null,"popularity":0},{"id":341,"name":"Dumbbell Laying Incline Row","equipment":"Dumbbell","primaryMuscles":["Biceps","Lats"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-laying-incline-row-front.mp4#t=0.1","howTo":"Lay on an incline bench that is between 30-45 degrees high. Let your arms hang freely. Pull your elbows straight back toward the ceiling.","secondaryMuscles":["Biceps"],"tertiaryMuscles":null,"popularity":0},{"id":342,"name":"Dumbbell Pendlay Row","equipment":"Dumbbell","primaryMuscles":["Biceps","Lats"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-pendlay-row-front.mp4#t=0.1","howTo":"The dumbbells should be placed on the floor. Hinge forward with a flat back and grab the dumbbells. Pull both dumbbells back and your elbows toward the ceiling. Return the dumbbells back to the floor softly on each rep.","secondaryMuscles":["Biceps"],"tertiaryMuscles":null,"popularity":0},{"id":343,"name":"Dumbbell Renegade Row","equipment":"Dumbbell","primaryMuscles":["Lats"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-renegade-row-front.mp4#t=0.1","howTo":"Start by getting into a plank position with a dumbbell in each hand. Your feet should be shoulder-width apart and your hands should be placed on the dumbbells, with your palms facing each other. From this starting position, row one dumbbell up towards your chest, keeping your elbow close to your body and your core engaged. Slowly lower the dumbbell back down to the starting position, and repeat on the other side. Make sure to keep your body straight and your hips level throughout the movement.","secondaryMuscles":["Abdominals"],"tertiaryMuscles":null,"popularity":1},{"id":344,"name":"Dumbbell Shoulder Extension","equipment":"Dumbbell","primaryMuscles":["Lats"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-shoulder-extension-front.mp4#t=0.1","howTo":"Start by hinging over with your feet shoulder-width apart and holding a dumbbell in each hand. Bring the dumbbells to your sides, with your palms facing forward and your elbows slightly bent. Make sure to keep your core engaged and your back straight throughout the movement.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":345,"name":"Dumbbell Single Arm Row","equipment":"Dumbbell","primaryMuscles":["Biceps","Lats"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-single-arm-row-front.mp4#t=0.1","howTo":"Make sure to keep your elbow close to your body and your core engaged throughout the movement. Start by standing in front of a flat bench with your feet shoulder-width apart and holding a dumbbell in one hand. Place your other hand on the bench for support, and bend at the waist so that your chest is parallel to the ground. From this starting position, row the dumbbell up towards your chest, squeezing your shoulder blade together as you do so.","secondaryMuscles":["Biceps"],"tertiaryMuscles":null,"popularity":1},{"id":346,"name":"Dumbbell Single Arm Row Knee","equipment":"Dumbbell","primaryMuscles":["Biceps","Lats"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-single-arm-row-knee-front.mp4#t=0.1","howTo":"Start by placing your elbow on one knee. Hold a dumbbell in your other hand, with your palm facing inwards towards your body. From this starting position, row the dumbbell up towards your chest, keeping your elbow close to your body and your core engaged.","secondaryMuscles":["Biceps"],"tertiaryMuscles":null,"popularity":0},{"id":347,"name":"Plate Alternating Deadstop Row","equipment":"Plate","primaryMuscles":["Lats"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/female-plate-alternating-deadstop-row-front.mp4#t=0.1","howTo":"Stand with your feet shoulder width apart. Hold each plate to the side of you. Bend forward at the hips bringing the plates to the floor while you slightly bend your knees, keeping your back straight. One at a time, lift the plate up. Return the plate to the floor and do the other side.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":348,"name":"Plate Glute Bridge to Pullover","equipment":"Plate","primaryMuscles":["Lats","Glutes"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-glute-bridge-pullover-front.mp4#t=0.1","howTo":"Lay flat on the ground with a plate on your chest. Push your hips up toward the ceiling and maintain that extended position. Extend your elbows mostly, break at the shoulder joint while maintaining hip extension and the slight bend in your elbows. Let the plate tap the floor (or get close) and then pull the plate back into the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":null,"popularity":0},{"id":349,"name":"Lawnmower Row","equipment":"Bodyweight","primaryMuscles":["Biceps","Lats"],"difficulty":"Intermediate","grips":["Rotating"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-bench-lawnmower-row-front.mp4#t=0.1","howTo":"Stand with feet staggered and one hand on a bench/box. Hold a dumbbell in the opposing hand. Hinge forward at the hips, keeping the back flat, and eyes facing forward. The weight should hang directly below the shoulders. Start with an overhand grip, as you pull rotate the dumbbell. When your upper arm reaches your side your palm should be facing forward.","secondaryMuscles":["Biceps"],"tertiaryMuscles":null,"popularity":0},{"id":350,"name":"Dumbbell Knee Lawnmower Row","equipment":"Dumbbell","primaryMuscles":["Biceps","Lats"],"difficulty":"Intermediate","grips":["Rotating"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-knee-lawnmower-row-front.mp4#t=0.1","howTo":"Stand with feet staggered and one hand on your knee. Hold a dumbbell in the opposing hand. Hinge forward at the hips, keeping the back flat, and eyes facing forward. The weight should hang directly below the shoulders. Start with an overhand grip, as you pull rotate the dumbbell. When your upper arm reaches your side your palm should be facing forward.","secondaryMuscles":["Biceps"],"tertiaryMuscles":null,"popularity":0},{"id":351,"name":"Dumbbell Supinated Row","equipment":"Dumbbell","primaryMuscles":["Biceps","Lats"],"difficulty":"Beginner","grips":["Underhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-supinated-row-front.mp4#t=0.1","howTo":"Grab both dumbbells and hinge forward at the hips. Make sure you keep a flat back. The closer your torso is to parallel with the ground the longer the range of motion will be at your shoulder. The better the results you\'ll get from the exercise. Let your arms hang freely, maintain an underhand grip, and then pull your elbow joint straight back toward the ceiling.","secondaryMuscles":["Biceps"],"tertiaryMuscles":null,"popularity":0},{"id":352,"name":"TRX Rotating Row","equipment":"TRX","primaryMuscles":["Biceps","Lats"],"difficulty":"Beginner","grips":["Rotating"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-rotating-row-front.mp4#t=0.1","howTo":"Grab the TRX straps and lean away from the anchor point until the strap is taut. Start with an overhand grip. Pull your elbows back and rotate your grip. By the time your elbows reach your side, your palms should be facing upwards.","secondaryMuscles":["Biceps"],"tertiaryMuscles":null,"popularity":0},{"id":353,"name":"TRX Single Arm row","equipment":"TRX","primaryMuscles":["Lats"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-single-arm-row-front.mp4#t=0.1","howTo":"Hold the TRX strap with one hand. Lean back until the strap is taut. Fully extend your elbow. Pull your elbow behind the body. Make sure to avoid twisting. Try to keep your shoulders even.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":354,"name":"Chin Ups","equipment":"Bodyweight","primaryMuscles":["Biceps","Lats","Forearms"],"difficulty":"Intermediate","grips":["Underhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-chinup-front.mp4#t=0.1","howTo":"Grab the bar shoulder width apart with a supinated grip (palms facing you) With your body hanging and arms fully extended, pull yourself up until your chin is past the bar. Slowly return to starting position. Repeat.","secondaryMuscles":["Biceps"],"tertiaryMuscles":["Forearms"],"popularity":6},{"id":355,"name":"Barbell Stiff Leg Deadlifts","equipment":"Barbell","primaryMuscles":["Hamstrings"],"difficulty":"Intermediate","grips":["Overhand,","Mixed"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-stiff-leg-deadlift-front.mp4#t=0.1","howTo":"Stand with a barbell at your shins with your feet shoulder width apart. Bend forward at your hips and keep your knees as fully extended as possible. Grab the barbell and then extend your hips while maintaining a straight back. From the standing position, lower the weight in a controlled manner. You can either lower the weight to the floor or before you touch the floor, depending on your mobility.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":356,"name":"Machine Hamstring Curl","equipment":"Machine","primaryMuscles":["Hamstrings"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-machine-hamstring-curl-front.mp4#t=0.1","howTo":"Lay down on the machine, placing your legs beneath the padded lever. Position your legs so that the padded lever is below your calve muscles. Support yourself by grabbing the side handles of the machine, and slowly raise the weight with your legs, toes pointed straight. Pause at the apex of the motion, then slowly return to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":357,"name":"Ball Hamstring Curl","equipment":"Bodyweight","primaryMuscles":["Hamstrings"],"difficulty":"Intermediate","grips":"Neutral","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/female-ball-hamstring-curls-front.mp4#t=0.1","howTo":"Lay on your back with a stability ball underneath your feet. Fully extend your knees and hips simultaneously. Flex your knees while keeping your hips extended. Flex your hamstrings and then return to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":358,"name":"Kettlebell Deadlift","equipment":"Kettlebell","primaryMuscles":["Hamstrings"],"difficulty":"Beginner","grips":"Overhand","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-deadlift-front.mp4#t=0.1","howTo":"Stand with your feet shoulder width apart holding the kettlebell with both hands in front of your thighs. Bend forward at the hips bringing the kettlebell to the floor while you slightly bend your knees, keeping your back straight. Return to standing position and repeat.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":3},{"id":359,"name":"Kettlebell Swing","equipment":"Kettlebell","primaryMuscles":["Hamstrings"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-swing-front.mp4#t=0.1","howTo":"Stand with your feet slightly wider than shoulder width apart holding the kettlebell between your legs, with your knees slightly bent. Keeping your back straight, swing the kettlebell upwards until the kettlebell is level with your chest and carefully lower. Repeat","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":25},{"id":360,"name":"Kettlebell Single Leg Deadlift","equipment":"Kettlebell","primaryMuscles":["Hamstrings"],"difficulty":"Advanced","grips":"Overhand","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-single-leg-deadlift-front.mp4#t=0.1","howTo":"Stand with your feet shoulder width apart, lifting one foot off the floor behind you. Hold the kettlebell in the same arm as the lifted leg. Bend forward at the hips bringing the kettlebell to the floor while you extend your lifted leg behind you, keeping your back straight - holding out your arm to the side for balance. Return to the upright position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":361,"name":"Kettlebell Staggered Deadlift","equipment":"Kettlebell","primaryMuscles":["Hamstrings"],"difficulty":"Beginner","grips":"Overhand","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-staggered-deadlift-front.mp4#t=0.1","howTo":"Stand with your feet shoulder width apart, shifting one foot behind you. Hold the kettlebell in both hands in front of your thighs. Bend forward at the hips bringing the kettlebell to the floor while you slightly bend your knees and keep your back straight. Return to the upright position and repeat.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":362,"name":"Hamstrings Stretch Variation Four","equipment":"Stretch","primaryMuscles":["Hamstrings"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-hamstring-stretch-variation-4-front.mp4#t=0.1","howTo":"Sit on the floor with your legs out in front of you. Reach forward to try and touch your toes. Reach as far forward as you can go. Hold the stretch for a few seconds then return to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":363,"name":"Hamstrings Stretch Variation Three","equipment":"Stretch","primaryMuscles":["Hamstrings"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-hamstrings-stretch-variation-3-front.mp4#t=0.1","howTo":"Sit on the floor with one leg outstretched and the other bent at the knee, foot resting on the opposite inner thigh. Reach forward to touch the toes of the outstretched leg. Hold the stretch for a few seconds then return to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":364,"name":"Hamstrings Stretch Variation Two","equipment":"Stretch","primaryMuscles":["Hamstrings"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-hamstrings-stretch-variation-2-front.mp4#t=0.1","howTo":"Bend your rear leg as much as you can, keeping the front leg straight. Hold the stretch for a few seconds then return to starting position. Stand with one foot in front of the other.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":365,"name":"Hamstrings Stretch Variation One","equipment":"Stretch","primaryMuscles":["Hamstrings"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-hamstrings-stretch-variation-1-front.mp4#t=0.1","howTo":"Lie down with your legs reaching up the wall. your bum should be slightly off the floor. Bend one leg and leave the other outstretched. Push your thigh towards the wall. Hold the stretch for a few seconds then return to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":366,"name":"Good Mornings","equipment":"Bodyweight","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-good-mornings-front.mp4#t=0.1","howTo":"Stand with your feet a little past shoulder width apart with a slight bend at your knee. Place your hands behind the back of your head. Keeping your back straight, rotate your hips to bring your shoulders down towards the floor. Stop when your chest is parallel with the floor.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":9},{"id":367,"name":"Kickbacks","equipment":"Bodyweight","primaryMuscles":["Hamstrings"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-glute-kickback-front.mp4#t=0.1","howTo":"Get down on all fours and position your hands under your shoulders and your knees under your hips. Kick back with one leg and squeeze your glutes. Slowly return to starting position by bending your knee and lowering your leg. Switch Legs. Repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":9},{"id":368,"name":"Single Legged Romanian Deadlifts","equipment":"Bodyweight","primaryMuscles":["Hamstrings"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-single-leg-romainian-deadlift-front_vNNJCFg.mp4#t=0.1","howTo":"Stand with your feet shoulder-width apart and knees slightly bent and raise one leg. Without changing the bend in your knee, bend at your hips, and lower your torso until it\'s almost parallel to the floor. Tense your glutes and then bring yourself back to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":369,"name":"Nordic Hamstring Curl","equipment":"Bodyweight","primaryMuscles":["Hamstrings"],"difficulty":"Advanced","grips":["None"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-nordic-hamstring-curl-front.mp4#t=0.1","howTo":"Go to your knees and ask someone to hold your ankles. Put your hands in front of you With a slight bend in your knees slowly bring your body to the ground (slower is better) Push up and reset to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":370,"name":"Cable Romanian Deadlift","equipment":"Cable","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-romanian-deadlift-side.mp4#t=0.1","howTo":"Start with a straight bar or ez bar attachment set to the bottom of the machine. Squat the weight up into a standing position and walk a few steps back Push your butt back to initiate the movement and then push your butt forward until you\'re back in a standing position. To protect yourself from injury, always maintain a flat back on any exercise.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":1},{"id":371,"name":"Cable Single Leg Deadlift","equipment":"Cable","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-single-leg-romanian-deadlift-side.mp4#t=0.1","howTo":"Start with a straight bar or easy bar attachment. Squat the weight up into a standing position and walk a few steps back. Push your butt back to initiate the movement while lifting one of your legs.\\nThen push your butt forward until you\'re back in a standing position. Compete your given amount of reps, then switch to opposite leg. To protect yourself from injury, always maintain a flat back.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":372,"name":"Cable Pull Through","equipment":"Cable","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-pull-through-side.mp4#t=0.1","howTo":"This exercise works best with a rope attachment but can be done with anything. The attachment should be set to the bottom of the machine. Face away from the cable machine, straddle the cable itself, and grab the attachment.\\nWalk a few steps away. Break at the hips while maintaining a flat back and mostly extended knees. Push hips forward until you are back in a standing position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":3},{"id":373,"name":"Cable Hamstring Curl","equipment":"Cable","primaryMuscles":["Hamstrings"],"difficulty":"Advanced","grips":"Neutral","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-hamstring-curl-side.mp4#t=0.1","howTo":"Use an ankle attachment with the cable set all the way to the bottom of the machine. Stand upright or try bending slightly forward. Flex at the knee and pull your ankle straight back.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":374,"name":"Band Good Morning","equipment":"Band","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-good-morning-front_8qJRfbm.mp4#t=0.1","howTo":"Anchor the band at hip level. Take a few steps away until the band is taut. Push your hips back while keeping your back flat until you feel a stretch in your hamstrings.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":375,"name":"Band Pullthrough","equipment":"Band","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Beginner","grips":"Overhand","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-pull-through-front.mp4#t=0.1","howTo":"Anchor the band to the lowest point possible. Straddle the band and then grab with both hands. Take a few steps away until the band is taut. Push your butt back until you feel a stretch in your hamstrings. Then extend the hips back into the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":376,"name":"Band Romanian Deadlift","equipment":"Band","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Intermediate","grips":"Neutral","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-romanian-deadlift-front.mp4#t=0.1","howTo":"Stand on your band with both feet. Hinge forward at the hips while keeping a flat back. Hinge until you feel a stretch in your hamstrings. Push your hips back forward until you are in a standing position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":377,"name":"Dumbbell Goblet Good Morning","equipment":"Dumbbell","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Advanced","grips":["Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-goblet-good-morning-front.mp4#t=0.1","howTo":"Hold the dumbbell in a goblet position. With your elbows directly under your fists. Push your hips back while leaving your knees MOSTLY extended. You should feel a stretch in your hamstrings. When you feel the stretch push your hips forward until you\'re back in a standing position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":378,"name":"Dumbbell Romanian Deadlift","equipment":"Dumbbell","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Intermediate","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-romanian-deadlift-front.mp4#t=0.1","howTo":"Stand with a shoulder width stance. Push your butt back while leaving your knees MOSTLY extended. You should feel a stretch in your hamstrings. When you feel the stretch, push your hips forward to complete the rep. Do not push your hips all the way forward. This will hyperextend your spine. Just go to a normal standing position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":3},{"id":379,"name":"Barbell High Bar Good Morning","equipment":"Barbell","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Advanced","grips":"Overhand","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-highbar-good-morning-front.mp4#t=0.1","howTo":"Place the bar on your traps. You may need a pad so the bar doesn\'t dig into your cervical spine. Push your hips straight back. Your knees should stay MOSTLY extended (think soft knees). Also make sure to Look for what feels like a stretch in your hamstrings. The stretch feeling means you\'re likely nearing the end of your Range of Motion without rounding your spine. When you feel the stretch push your hips forward until you\'re in a standing position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":380,"name":"Barbell Low Bar Good Morning","equipment":"Barbell","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-low-bar-good-morning-front.mp4#t=0.1","howTo":"Place the bar between your traps and rear delts. Pull your shoulder blades back to give the bar a shelf to sit on. Push your hips back until you feel a stretch in your hamstrings. This means you\'re nearing the end of your Range of Motion with out rounding your spine. When you feel the stretch push your hips forward until you\'e in a standing position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":381,"name":"Barbell Staggered Deadlift","equipment":"Barbell","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Advanced","grips":"Overhand","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-staggered-deadlift-front.mp4#t=0.1","howTo":"Place one foot behind. You should only be on your toes on that back foot. Your front foot should be planted flat the entire time. Bend your back knee and push your hips back. Look for a stretch in your front hamstring. When you feel the stretch, push your hips forward again until you\'re back in a standing position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":382,"name":"Barbell Single Leg Deadlift","equipment":"Barbell","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Advanced","grips":"Overhand","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-single-leg-deadlift-front.mp4#t=0.1","howTo":"Start by pushing your hips straight back and extending your non-working leg behind you. It is ok to touch your other foot back to the ground each rep. Leave your knee mostly extended. Look for a stretch in your hamstring. When you feel the stretch, push your hips forward until you\'re back in a standing position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":383,"name":"Barbell Romanian Deadlift","equipment":"Barbell","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Intermediate","grips":"Overhand","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-romanian-deadlift-front.mp4#t=0.1","howTo":"Take a shoulder width, double overhand or mixed grip. Push your hips back while leaving your knees mostly extended. Look for a stretch in your hamstrings. When you feel the stretch, push your hips forward until you\'re back in a standing position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":1},{"id":384,"name":"Kettlebell Goblet Good Morning","equipment":"Kettlebell","primaryMuscles":["Hamstrings"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-goblet-good-morning-front.mp4#t=0.1","howTo":"Stand with your feet shoulder width apart holding the kettlebell with both hands in front of your chest. Bend forward at the hips keeping your back and knees straight and the kettlebell close to your chest. Return to standing position and thrust your pelvis forward.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":385,"name":"Barbell Snatch Grip Deadlift","equipment":"Barbell","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Advanced","grips":"Overhand","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-snatch-grip-deadlift-front.mp4#t=0.1","howTo":"Start by standing with your feet about hip-width apart, with your toes pointed slightly outward. Place a barbell on the floor in front of you, with the weight plates on either side. Make sure that the bar is directly in line with your feet. Bend down and grab the barbell with an overhand grip, your hands much wider than shoulder-width apart. Keep your back straight and your shoulders down as you grip the bar. Stand up straight, lifting the barbell off the ground and pulling it toward your hips. Keep your elbows close to your body and your shoulders down as you do this. Slowly lower the barbell back to the ground, making sure to keep your back straight and your shoulders down throughout the movement.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":386,"name":"Barbell Snatch Grip Romanian Deadlift","equipment":"Barbell","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Advanced","grips":["Overhand,","Mixed"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-snatch-grip-romanian-deadlift-front.mp4#t=0.1","howTo":"Start by standing with your feet about hip-width apart. The bar should be in a rack or box so it\'s lifted off the ground. Grab the barbell with an overhand grip, your hands should be much wider than shoulder-width apart. Hing forward at the hips keeping your knees mostly extended. Hinge until you feel a stretch in your hamstrings. When you feel the stretch, push your hips forward until you are back in a standing position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":387,"name":"Barbell Zercher Good Morning","equipment":"Barbell","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Advanced","grips":["None"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-zercher-good-morning-front.mp4#t=0.1","howTo":"Begin by standing with your feet about hip-width apart and holding a barbell in the crook of your elbows, with your palms facing towards your body. Keeping your core engaged and your back straight, bend at the hips and lower your torso forward until it is nearly parallel to the ground. Push through your heels to extend your hips and raise your body back to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":388,"name":"Dumbbell Leg Curl","equipment":"Dumbbell","primaryMuscles":["Hamstrings"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-leg-curl-front.mp4#t=0.1","howTo":"Lay flat on a bench with a dumbbell between your feet. Flex your knees and raise the dumbbell until the soles of your shoes are pointed at the ceiling.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":389,"name":"Dumbbell Single Leg Single Arm Deadlift","equipment":"Dumbbell","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Advanced","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-single-leg-single-arm-deadlift-front.mp4#t=0.1","howTo":"Start by standing on one leg with a dumbbell in one hand. Slowly bend at the hips and lower the dumbbell towards the ground while extending your free leg behind you. Keep your core engaged and your back straight as you lower the weight. Once the dumbbell is close to the ground, push through your heel to return to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":390,"name":"Dumbbell Single Leg Stiff Leg Deadlift","equipment":"Dumbbell","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Intermediate","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-single-leg-stiff-leg-deadlift-front.mp4#t=0.1","howTo":"Start by standing on one leg with your feet shoulder-width apart and holding two dumbbells. From this starting position, hinge at the hips to lower the dumbbell towards the ground, keeping your back straight and your core engaged. Once you feel a stretch in your hamstring, slowly return to the starting position. Make sure to keep your standing leg slightly bent and avoid rounding your back as you lower the dumbbell.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":391,"name":"Dumbbell Staggered Deadlift","equipment":"Dumbbell","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Intermediate","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-staggered-deadlift-front.mp4#t=0.1","howTo":"Start by standing with your feet shoulder-width apart and holding a dumbbell in each hand. Place one foot slightly behind the other, with the heel of your back foot elevated on a step or weight plate. From this starting position, bend at the hips and knees to lower the dumbbells towards the ground, keeping your back straight and your core engaged. Once the dumbbells are below your knees, drive through your heels to stand back up to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":392,"name":"Dumbbell Swing","equipment":"Dumbbell","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Beginner","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-swing-front.mp4#t=0.1","howTo":"Start by standing with your feet shoulder-width apart and holding a dumbbell in both hands. Bend your knees slightly and hinge at the hips to swing the dumbbell between your legs. From this starting position, explosively extend your hips and swing the dumbbell up to chest height. Allow the momentum of the swing to carry the dumbbell back down between your legs, and then repeat the movement for the desired number of repetitions.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":2},{"id":393,"name":"Plate Single Leg Pinch Grip Deadlift","equipment":"Plate","primaryMuscles":["Hamstrings","Glutes","Forearms"],"difficulty":"Intermediate","grips":["Pinch","Grip"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-single-leg-pinch-grip-deadlift-front.mp4#t=0.1","howTo":"Stand with your feet shoulder-width apart and facing forwards. Grip the sides of a weight plate with your palms facing down. Balance on one foot, as you raise the weight keep your arms and back straight, while you bring your other foot back towards the ground Keep four raised leg straight and in alignment with your back as you lower the plate back down to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":394,"name":"Plate Single Leg Deadlift","equipment":"Plate","primaryMuscles":["Quads","Hamstrings","Glutes"],"difficulty":"Advanced","grips":"Neutral","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-single-leg-deadlift-front.mp4#t=0.1","howTo":"Engage your core and straighten your legs to lift the plate off the ground. Stand on one leg, keeping the other leg off the ground, while holding the plate in front of your body. Keep your back straight and maintain a neutral head position while looking straight ahead. Lower the plate back down to the ground while keeping your balance on one leg.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":395,"name":"Band Leg Curl","equipment":"Band","primaryMuscles":["Hamstrings"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-leg-curl-front.mp4#t=0.1","howTo":"Loop the band around a sturdy anchor point such as a weightlifting rack or a door handle. Lie on your back with your heels placed inside the band. Make sure the band is centered under your heels and your feet are hip-width apart. Using your hamstrings, curl your heels towards your glutes while keeping your hips on the ground.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":396,"name":"Plate Staggered Deadlift","equipment":"Plate","primaryMuscles":["Hamstrings","Glutes"],"difficulty":"Advanced","grips":["Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-staggered-deadlift-front.mp4#t=0.1","howTo":"Start by standing with your feet shoulder-width apart and holding a weight plate. Place one foot slightly behind the other, with the heel of your back foot elevated. From this starting position, bend at the hips and knees to lower the plate towards the ground, keeping your back straight and your core engaged. Once the plate is below your knees, drive through your heels to stand back up to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":397,"name":"Plate Staggered Pinch Grip Deadlift","equipment":"Plate","primaryMuscles":["Hamstrings","Glutes","Forearms"],"difficulty":"Advanced","grips":["Pinch","Grip"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-staggered-pinch-grip-deadlift-front.mp4#t=0.1","howTo":"Start by standing with your feet shoulder-width apart and holding two plates with a pinch grip. Place one foot slightly behind the other, with the heel of your back foot elevated. From this starting position, bend at the hips and knees to lower the plates towards the ground, keeping your back straight and your core engaged.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":398,"name":"TRX Hamstring Curl","equipment":"TRX","primaryMuscles":["Hamstrings"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-hamstring-curl-front.mp4#t=0.1","howTo":"Start by facing the TRX straps and positioning yourself in a push-up position with your hands on the ground and your feet in the TRX foot cradles. Keeping your core engaged and body in a straight line, bend your knees and bring your heels towards your glutes. Pause for a moment at the top of the movement, then slowly lower your legs back to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":399,"name":"Plate Good Morning","equipment":"Plate","primaryMuscles":["Hamstrings"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-good-morning-front.mp4#t=0.1","howTo":"Stand with feet hip-width apart, the plate held behind the neck and the knees slightly bent. Bend forward at the hips, keeping the back straight, until the torso is parallel to the floor. Push through the hips to return to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":400,"name":"Plate Good Morning Anterior","equipment":"Plate","primaryMuscles":["Hamstrings"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-good-morning-anterior-front.mp4#t=0.1","howTo":"Stand with feet hip-width apart, the plate held in front of you, and the knees slightly bent. Bend forward at the hips, keeping the back straight, until the torso is parallel to the floor. Push through the hips to return to the starting position.","secondaryMuscles":["Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":401,"name":"Glute Bridge","equipment":"Bodyweight","primaryMuscles":["Glutes"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-glute-bridge-front.mp4#t=0.1","howTo":"Lie down with your knees bent and your feet flat on the floor. Push your hips up so that your butt is elevated and your back straight. Tense your glutes and raise your hips towards the ceiling. Once you are at the highest point you can manage, hold the position for a few seconds, and then slowly return to the starting position","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":14},{"id":402,"name":"Barbell Hip Thrust","equipment":"Barbell","primaryMuscles":["Glutes"],"difficulty":"Advanced","grips":["Overhand,","Underhand,","Mixed"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-hip-thrust-front.mp4#t=0.1","howTo":"Sit on the ground with a bench behind you. Have the barbell over your legs just above your hips. Lean back against the bench so that your shoulders are resting upon it, stretch your arms out to either side using the bench as support. Raise the weight by driving through your feet and extending your hips upwards. Support the weight with your shoulders and feet. Slowly extend as far as you can, and then slowly return to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":6},{"id":403,"name":"Single Leg Glute Bridge","equipment":"Bodyweight","primaryMuscles":["Glutes"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-single-leg-glute-bridge-front.mp4#t=0.1","howTo":"Lie down with one knee bent and and one with a slight bend. Push your hips up, so that your butt is elevated and your back straight. Tense your glutes and raise your hips towards the ceiling. Once you are at the highest point you can manage, hold the position for a few seconds, and then slowly return to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":2},{"id":404,"name":"Kettlebell Glute Bridge","equipment":"Kettlebell","primaryMuscles":["Glutes"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-glute-bridge-front.mp4#t=0.1","howTo":"Laying on the floor with your knees bent and feet firmly on the floor, rest the kettlebell on your pelvis. Pushing through the legs and keeping the core muscles engaged, raise your pelvis off the floor until your stomach, pelvis and thighs make a straight line. Slowly lower to the ground to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":405,"name":"Kettlebell Single Leg Glute Bridge","equipment":"Kettlebell","primaryMuscles":["Glutes"],"difficulty":"Intermediate","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-single-leg-glute-bridge-front.mp4#t=0.1","howTo":"Laying on the floor with one knee bent with the foot firmly on the floor and one leg extended, rest the kettlebell on your pelvis. Pushing through the bent leg and keeping the core muscles engaged, raise your pelvis and the extended leg off the floor until your stomach, pelvis and thighs make a straight line. Slowly lower to the ground to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":406,"name":"Kettlebell Hip Thrust","equipment":"Kettlebell","primaryMuscles":["Glutes"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-hip-thrust-front.mp4#t=0.1","howTo":"Sitting on the floor with your knees bent and feet planted firmly on the floor, lean your back against the bench. Resting the kettlebell on your pelvis, raise your pelvis until your stomach, pelvis and thighs are in line. Slowly lower until you are in the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":407,"name":"Kettlebell Single Leg Hip Thrust","equipment":"Kettlebell","primaryMuscles":["Glutes"],"difficulty":"Intermediate","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-single-leg-hip-thrust-front.mp4#t=0.1","howTo":"Sitting on the floor with one knee bent with the foot firmly on the floor and one leg extended, lean your back against the bench. Resting the kettlebell on your pelvis, raise your pelvis until your stomach, pelvis and thighs are in line. Slowly lower until you are in the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":408,"name":"Glutes Stretch Variation Three","equipment":"Stretch","primaryMuscles":["Glutes"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-glutes-stretch-variation-3-front.mp4#t=0.1","howTo":"Lay flat and bring your left leg to 90 degrees. Hold your left leg with both hands and slowly rotate your hips to the right hand side. Hold at the peak of the stretch, then slowly return to starting position. Switch sides and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":409,"name":"Glutes Stretch Variation Two","equipment":"Stretch","primaryMuscles":["Glutes"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-glutes-stretch-variation-2-front.mp4#t=0.1","howTo":"Sit on the ground and lay one leg flat and the other over the top. Hold your leg with the same side arm and slowly rotate your hips and back. Hold at the peak of the stretch, then slowly return to starting position. Switch sides and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":410,"name":"Glutes Stretch Variation One","equipment":"Stretch","primaryMuscles":["Glutes"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-glutes-stretch-variation-1-front.mp4#t=0.1","howTo":"On your front, place one leg forward and then stretch out the same side arm across the mat/floor. Fully extend your leg and arm. Hold at the peak of the stretch, then slowly return to starting position. Switch sides and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":411,"name":"Cable Hip Abduction","equipment":"Cable","primaryMuscles":["Glutes"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-hip-abduction-front.mp4#t=0.1","howTo":"Use an ankle attachment. Cable should be set all the way to the bottom. Face sideways with the ankle attachment on your outside leg. Walk a few steps away. Abduct at the hips and raise your leg out to the side. Return to the starting position and stop just short of your foot touching back to the ground (to keep tension on the muscle).","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":412,"name":"Cable Glute Kickback","equipment":"Cable","primaryMuscles":["Glutes"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-glute-kickbacks-front.mp4#t=0.1","howTo":"Use an ankle attachment. The cable should be set to the bottom of the crossover machine. Push your ankle straight back, extending at the hip. Hold for a one count when you feel a contraction in your glutes. Then flex at the hips until you are back into your original position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":413,"name":"Band Glute Kickback","equipment":"Band","primaryMuscles":["Glutes"],"difficulty":"Intermediate","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-kickback-front.mp4#t=0.1","howTo":"Get into a quadruped position. Loop the band around both of your wrists and one of your feet. Extend your knee and hip straight back until you feel like contraction in the glutes. Flex at the knee until back in the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":414,"name":"Dumbbell Hip Thrust","equipment":"Dumbbell","primaryMuscles":["Glutes"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-hip-thrust-front.mp4#t=0.1","howTo":"Place your shoulder blades against a box or bench that won\'t move. Both your feet should be planted and your heels should not come off the floor. Point your toes forward. Break at the hips. Seek the longest range of motion possible. Focus on the top end of the movement. Push your hips as high as possible on each rep.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":415,"name":"Dumbbell Glute Bridge","equipment":"Dumbbell","primaryMuscles":["Quads","Hamstrings","Glutes"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-glute-bridge-front.mp4#t=0.1","howTo":"Lay flat on the ground with both feet planted. Make sure you keep your heels glued to the floor. Place the dumbbell on your hips. Push your hips toward the ceiling until you feel your glutes contract. Then return to the floor.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":416,"name":"Barbell Sumo Deadlift","equipment":"Barbell","primaryMuscles":["Quads","Glutes"],"difficulty":"Intermediate","grips":"Overhand","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-sumo-deadlift-front.mp4#t=0.1","howTo":"Stance width can vary with a sumo DL. Some prefer toes near the plates. Others prefer a more narrow stance to get more drive off the floor. Make sure your arms are inside your legs. The bar should be just over your mid-foot. Flatten your back and push your heels into the floor. Try to extend your knees and hips simultaneously.","secondaryMuscles":["Quads"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":417,"name":"Barbell Glute Bridge","equipment":"Barbell","primaryMuscles":["Glutes"],"difficulty":"Beginner","grips":["Overhand,","Mixed"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-glute-bridge-front.mp4#t=0.1","howTo":"Lie on your back on the floor with your knees bent and your feet flat on the ground. Place a barbell across your hips and grasp it with both hands. Keeping your arms straight, push through your heels to lift your hips off the ground and raise the barbell. Hold the bridge position for a moment, then slowly lower your hips back to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":418,"name":"Dumbbell Figure Four Glute Bridge","equipment":"Dumbbell","primaryMuscles":["Glutes"],"difficulty":"Intermediate","grips":["None"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-figure-four-glute-bridge-front.mp4#t=0.1","howTo":"Lay flat on the ground with one leg crossed over the other and your heel planted on the ground. Push your hips toward the ceiling and hold for a second.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":419,"name":"Dumbbell Figure Four Hip Thrust","equipment":"Dumbbell","primaryMuscles":["Glutes"],"difficulty":"Intermediate","grips":["None"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-figure-four-hip-thrust-front.mp4#t=0.1","howTo":"Put your shoulder blades on a bench and cross one leg over the other. Start with your hips up. Drop your hips and then push your hips up toward the ceiling.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":420,"name":"Dumbbell Single Leg Glute Bridge","equipment":"Dumbbell","primaryMuscles":["Glutes"],"difficulty":"Intermediate","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-single-leg-glute-bridge-front.mp4#t=0.1","howTo":"Start by lying on your back with your feet flat on the ground and a dumbbell on your hips. Lift one leg off the ground and engage your glutes to raise your hips up towards the ceiling. From this starting position, slowly lower your hips back down to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":421,"name":"Dumbbell Single Leg Hip Thrust","equipment":"Dumbbell","primaryMuscles":["Glutes"],"difficulty":"Beginner","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-single-leg-hip-thrust-front.mp4#t=0.1","howTo":"Start by lying on a bench with your feet flat on the ground and a dumbbell on your hips. Lift one leg off the ground and engage your glutes to raise your hips up towards the ceiling. From this starting position, slowly lower your hips back down to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":422,"name":"Dumbbell Staggered Glute Bridge","equipment":"Dumbbell","primaryMuscles":["Glutes"],"difficulty":"Beginner","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-staggered-glute-bridge-front.mp4#t=0.1","howTo":"Start by lying on your back with your feet on the ground and a dumbbell in each hand. Place one foot on the ground and the other slightly in front, with your knees bent. From this starting position, raise your hips up off the ground by pushing through your heels and squeezing your glutes.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":423,"name":"Dumbbell Staggered Hip thrust","equipment":"Dumbbell","primaryMuscles":["Glutes"],"difficulty":"Beginner","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-staggered-hip-thrust-front.mp4#t=0.1","howTo":"Start by lying on your back on a bench with your feet on the ground and a dumbbell on your hips. Place one foot on the ground and the other slightly in front, with your knees bent. From this starting position, raise your hips up off the ground by pushing through your heels and squeezing your glutes.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":424,"name":"Plate Clean And Press","equipment":"Plate","primaryMuscles":["Shoulders","Glutes"],"difficulty":"Intermediate","grips":"Neutral","mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-clean-and-press-front.mp4#t=0.1","howTo":"Stand with feet shoulder-width apart and the plate in front of the feet. Bend the knees and hips to pick up the plate, keeping the back straight and core engaged. Stand up, lock the hips and legs, and press the plate overhead with straight arms. Lower the plate back to the starting position, keeping control of it, and repeat for desired reps.","secondaryMuscles":["Shoulders"],"tertiaryMuscles":null,"popularity":0},{"id":425,"name":"Plate Clean","equipment":"Plate","primaryMuscles":["Glutes"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-clean-front.mp4#t=0.1","howTo":"Stand with feet shoulder-width apart and the plate in front of the feet. Bend the knees and hips to pick up the plate, keeping the back straight and core engaged. Stand up while pulling the plate towards the chest. Keep shoulder level while keeping the elbows high and in front of the plate.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":426,"name":"Band Hip Abduction","equipment":"Band","primaryMuscles":["Glutes"],"difficulty":"Intermediate","grips":["None"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-hip-abduction-front.mp4#t=0.1","howTo":"Attach the band around your ankle. Stand with feet hip-width apart, feet facing forward, and hands on hips. Lift your right leg away from your body to the side, keeping your knee straight. This is your starting position. Maintaining proper form, move your right leg as far to the side as you can, keeping your left leg planted firmly on the ground. Hold for a second and then return your right leg to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":427,"name":"Band Hip Adduction","equipment":"Band","primaryMuscles":["Glutes"],"difficulty":"Intermediate","grips":["None"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-hip-adduction-front.mp4#t=0.1","howTo":"Attach a band to a stable anchor point, such as a door handle or post. Stand with feet shoulder-width apart and place the band around your ankles. Keeping your feet together, move your legs out to the sides and then back to the midline of your body. Repeat for the desired number of repetitions.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":428,"name":"Plate Squat Hold","equipment":"Plate","primaryMuscles":["Quads","Glutes"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-squat-hold-front_LrtgCLV.mp4#t=0.1","howTo":"Start by standing with your feet shoulder-width apart, with a weight plate held in both hands at chest height. Lower your body by bending your knees and hips, keeping your back straight and your weight in your heels. Go down until your thighs are parallel to the floor, then pause for a moment. Hold the squat position for the desired amount of time, keeping the weight plate steady and your core engaged.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":429,"name":"Barbell Feet Elevated Figure Four Glute Bridge","equipment":"Barbell","primaryMuscles":["Glutes"],"difficulty":"Intermediate","grips":["Overhand,","Mixed"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-feet-elevated-figure-four-glute-bridge-front.mp4#t=0.1","howTo":"Start by lying flat on your back with your feet resting on top of a box, the barbell placed over your hips, and cross one leg over the other. Push through your heels and raise your hips towards the ceiling, keeping your feet flat on the box. Engage your glutes at the top of the movement, pause briefly and then lower your hips back down to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":430,"name":"Barbell Feet Elevated Glute Bridge","equipment":"Barbell","primaryMuscles":["Glutes"],"difficulty":"Intermediate","grips":["Overhand,","Mixed"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-feet-elevated-glute-bridge-front.mp4#t=0.1","howTo":"Start by lying flat on your back with your feet resting on top of a box, the barbell placed over your hips. Push through your heels and raise your hips towards the ceiling, keeping your feet flat on the box. Engage your glutes at the top of the movement, pause briefly and then lower your hips back down to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":431,"name":"Barbell Feet Elevated Single Leg Glute Bridge","equipment":"Barbell","primaryMuscles":["Glutes"],"difficulty":"Advanced","grips":["Overhand,","Mixed"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-feet-elevated-single-leg-glute-bridge-front.mp4#t=0.1","howTo":"Start by lying flat on your back with your feet resting on top of a box, the barbell placed over your hips. Raise one leg up and off the box. Push through your heels and raise your hips towards the ceiling, keeping your feet flat on the box. Engage your glutes at the top of the movement, pause briefly and then lower your hips back down to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":432,"name":"Barbell Feet Elevated Staggered Glute Bridge","equipment":"Barbell","primaryMuscles":["Glutes"],"difficulty":"Intermediate","grips":["Overhand,","Mixed"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-feet-elevated-staggered-glute-bridge-front.mp4#t=0.1","howTo":"Start by lying flat on your back with your feet resting on top of a box, the barbell placed over your hips. Place one foot about 6-9 inches in front of the other. Push through your heels and raise your hips towards the ceiling, keeping your feet flat on the box. Engage your glutes at the top of the movement, pause briefly and then lower your hips back down to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":433,"name":"Bodyweight Feet Elevated Figure Four Glute Bridge","equipment":"Bodyweight","primaryMuscles":["Glutes"],"difficulty":"Intermediate","grips":["None"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-feet-elevated-figure-four-glute-bridge-front.mp4#t=0.1","howTo":"Start by lying on your back with your knees bent and feet on top of a sturdy box, bench or elevated surface. Drive through your heels to lift your hips off the floor, making sure to keep your feet and knees pointing forward.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":434,"name":"Bodyweight Feet Elevated Glute Bridge","equipment":"Bodyweight","primaryMuscles":["Glutes"],"difficulty":"Beginner","grips":["None"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-feet-elevated-glute-bridge-front.mp4#t=0.1","howTo":"Start by lying on your back with your knees bent and feet on top of a sturdy box, bench or elevated surface. Drive through your heels to lift your hips off the floor, making sure to keep your feet and knees pointing forward.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":435,"name":"Bodyweight Feet Elevated Single Leg Glute Bridge","equipment":"Bodyweight","primaryMuscles":["Glutes"],"difficulty":"Advanced","grips":["None"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-feet-elevated-single-leg-glute-bridge-front.mp4#t=0.1","howTo":"Start by lying on your back with your knees bent and feet on top of a sturdy box, bench or elevated surface. Lift one leg off the box. Drive through your heel to lift your hips off the floor, making sure to keep your feet and knees pointing forward.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":436,"name":"Bodyweight Feet Elevated Staggered Glute Bridge","equipment":"Bodyweight","primaryMuscles":["Glutes"],"difficulty":"Intermediate","grips":["None"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-feet-elevated-staggered-glute-bridge-front.mp4#t=0.1","howTo":"Start by lying on your back with your knees bent and feet in a staggered position on the box. Drive through your heels to lift your hips off the floor, making sure to keep your feet and knees pointing forward.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":437,"name":"Dumbbell Feet Elevated Figure Four Glute Bridge","equipment":"Dumbbell","primaryMuscles":["Glutes"],"difficulty":"Beginner","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-feet-elevated-figure-four-glute-bridge-front.mp4#t=0.1","howTo":"Start by lying flat on your back with your feet resting on top of a box, the dumbbell placed over your hips, and cross one leg over the other. Push through your heels and raise your hips towards the ceiling, keeping your feet flat on the box. Engage your glutes at the top of the movement, pause briefly and then lower your hips back down to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":438,"name":"Dumbbell Feet Elevated Glute Bridge","equipment":"Dumbbell","primaryMuscles":["Glutes"],"difficulty":"Beginner","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-feet-elevated-glute-bridge-front.mp4#t=0.1","howTo":"Start by lying on your back with your knees bent and feet on top of a sturdy box, bench or elevated surface. Place a dumbbell over your hips. Drive through your heels to lift your hips off the floor, making sure to keep your feet and knees pointing forward.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":439,"name":"Dumbbell Feet Elevated Single Leg Glute Bridge","equipment":"Dumbbell","primaryMuscles":["Glutes"],"difficulty":"Advanced","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-feet-elevated-single-leg-glute-bridge-front.mp4#t=0.1","howTo":"Start by lying flat on your back with your feet resting on top of a box, the dumbbell placed over your hips. Raise one leg up and off the box. Push through your heels and raise your hips towards the ceiling, keeping your feet flat on the box. Engage your glutes at the top of the movement, pause briefly and then lower your hips back down to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":440,"name":"Dumbbell Feet Elevated Staggered Glute Bridge","equipment":"Dumbbell","primaryMuscles":["Glutes"],"difficulty":"Intermediate","grips":["Overhand,","Neutral"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-feet-elevated-staggered-glute-bridge-front.mp4#t=0.1","howTo":"Start by lying on your back with your knees bent and feet in a staggered position on the box. Drive through your heels to lift your hips off the floor, making sure to keep your feet and knees pointing forward.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":441,"name":"Dumbbell Standing Hip Abduction","equipment":"Dumbbell","primaryMuscles":["Glutes"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-standing-hip-abduction-front.mp4#t=0.1","howTo":"Stand with a dumbbell held on the side of your leg. Raise that leg laterally as high as your hip range of motion allows for.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":442,"name":"TRX Glute Bridge","equipment":"TRX","primaryMuscles":["Glutes"],"difficulty":"Beginner","grips":["None"],"mechanic":"Compound","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-glute-bridge-front.mp4#t=0.1","howTo":"Lie on your back with your feet in the foot cradles of the TRX straps, with your knees bent and feet flat on the ground. Place your arms by your sides with your palms facing down. Drive your hips up towards the ceiling, squeezing your glutes and hamstrings at the top of the movement.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":443,"name":"Barbell Deadlift","equipment":"Barbell","primaryMuscles":["Traps","Glutes","Lower back","Traps (mid-back)"],"difficulty":"Advanced","grips":["Overhand,","Mixed"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-deadlift-front.mp4#t=0.1","howTo":"Stand with your mid-foot under the bar and grip the bar with your hands, about a shoulder width apart. Bend your knees, then lift the bar by straightening your back. It is important to keep your back straight. Stand to your full height and hold. Lower the bar to the floor by bending your knees and keeping your back straight.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":5},{"id":444,"name":"Barbell Behind The Back Wrist Curl","equipment":"Barbell","primaryMuscles":["Forearms"],"difficulty":"Intermediate","grips":"Underhand","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-behind-the-back-wrist-curl-front.mp4#t=0.1","howTo":"Stand straight and hold the barbell behind you using a pronated grip with your hands and feet shoulder-width apart. Slowly curl your wrists in a semi-circular motion upwards. Hold the barbell at the apex of the motion and then slowly lower the barbell back down to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":445,"name":"Dumbbell Wrist Curl","equipment":"Dumbbell","primaryMuscles":["Forearms"],"difficulty":"Beginner","grips":["Underhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-wrist-curl-front.mp4#t=0.1","howTo":"Grip the dumbbell with your palm facing upwards with your forearm rested against the bench. Slowly curl your wrist upwards in a semicircular motion. Return to starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":446,"name":"Barbell Wrist Curl","equipment":"Barbell","primaryMuscles":["Forearms"],"difficulty":"Beginner","grips":"Underhand","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-wrist-curl-front_j9uRhfT.mp4#t=0.1","howTo":"Grab a straight bar with a supinated (underhand) grip. Kneel down next to a flat bench and place your forearms on the bench with your wrists just off the bench. Let the barbell pull down on your wrists until they are extended. Curl the barbell until your wrists are fully flexed. Lower in a controlled manner and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":2},{"id":447,"name":"Kettlebell Farmers Carry","equipment":"Kettlebell","primaryMuscles":["Forearms"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-farmers-carry-front.mp4#t=0.1","howTo":"Standing straight with a kettlebell in one hand, lift the knee of one leg off the floor to knee height. Bring the leg back to standing and repeat with the other leg, keeping the kettlebell on the same side. Repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":448,"name":"Kettlebell Wrist Extension","equipment":"Kettlebell","primaryMuscles":["Forearms"],"difficulty":"Beginner","grips":"Overhand","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-wrist-extension-front.mp4#t=0.1","howTo":"Stand up straight with a kettlebell in both hands in front of your pelvis, with your forearms facing inwards. Flex your wrist upwards until wrists are fully extended. Lower to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":449,"name":"Kettlebell Wrist Curl","equipment":"Kettlebell","primaryMuscles":["Forearms"],"difficulty":"Beginner","grips":"Underhand","mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-wrist-curl-front.mp4#t=0.1","howTo":"Stand up straight with a kettlebell in both hands in front of your pelvis, with your forearms facing outwards. Flex your wrist towards your body until the kettlebell is level with your stomach. Lower to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":450,"name":"Forearms Stretch Variation Four","equipment":"Stretch","primaryMuscles":["Forearms"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-forearms-stretch-variation-4-front.mp4#t=0.1","howTo":"Raise your arm to shoulder height at 90 degrees to your body. Press lightly on your hand and push towards you. Rotate the arm across your body. Switch sides and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":451,"name":"Forearms Stretch Variation Three","equipment":"Stretch","primaryMuscles":["Forearms"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-forearms-stretch-variation-3-front.mp4#t=0.1","howTo":"Place your hands together. Rotate your arms and hands 180 degrees. Hold at the peak of the stretch. Return to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":452,"name":"Forearms Stretch Variation Two","equipment":"Stretch","primaryMuscles":["Forearms"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-forearms-stretch-variation-2-front.mp4#t=0.1","howTo":"Place your hand against a wall, palms facing upward, with finger tips touching. Hold at the peak of the stretch. Return to starting position. Slowly lean into your palm.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":453,"name":"Forearms Stretch Variation One","equipment":"Stretch","primaryMuscles":["Forearms"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-forearms-stretch-variation-1-front.mp4#t=0.1","howTo":"Place your palm flush against the wall. Take one step forward and straighten your arm slowly to extend your bicep. Hold at the peak of the stretch. Return to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":454,"name":"Cable Wrist Curl","equipment":"Cable","primaryMuscles":["Forearms"],"difficulty":"Intermediate","grips":["Underhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-wrist-curl-side.mp4#t=0.1","howTo":"Use a handle attachment. The cable should be set all the way to the bottom of the machine. Face away from the cable machine. Stagger your stance so you have a better base of support. Start with your elbow at a 90° angle with your palm facing up. Flex and extend at the wrist.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":455,"name":"Cable Wrist Extension","equipment":"Cable","primaryMuscles":["Forearms"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-wrist-curl-side.mp4#t=0.1","howTo":"Use a handle attachment. The cable should be set all the way to the bottom of the machine. Face away from the cable machine. Stagger your stance so you have a better base of support. Start with your elbow at a 90 degree angle with your palm facing down. Flex and extend at the wrist.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":456,"name":"Dumbbell Wrist Extension","equipment":"Dumbbell","primaryMuscles":["Forearms"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-wrist-extension-front.mp4#t=0.1","howTo":"Grab two dumbbells with an overhand grip and lay your forearms across your knees. Let your wrists flex fully, then extend your wrists.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":457,"name":"Plate Pinch Grip Side Bend","equipment":"Plate","primaryMuscles":["Forearms"],"difficulty":"Beginner","grips":["Pinch","Grip"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-pinch-grip-side-bend-front.mp4#t=0.1","howTo":"Stand straight with the plate held at your side Keep your hips and shoulders facing forward, bend to one side slowly Return to the upright position. Switch hands and repeat","secondaryMuscles":["Obliques"],"tertiaryMuscles":null,"popularity":0},{"id":458,"name":"Plate Pinch Grip Farmer\'s Carry","equipment":"Plate","primaryMuscles":["Forearms"],"difficulty":"Intermediate","grips":["Pinch","Grip"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-pinch-grip-farmers-carry-front.mp4#t=0.1","howTo":"Stand tall holding two plates in each hand with a pinch grip. Walk for the desired distance or time.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":459,"name":"Plate Pinch Grip Deadlift","equipment":"Plate","primaryMuscles":["Lats","Forearms"],"difficulty":"Intermediate","grips":["Pinch","Grip"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-pinch-grip-deadlift-front.mp4#t=0.1","howTo":"Stand facing the plate with your feet shoulder-width apart and the plate positioned between your feet. Bend down and grasp the plate from the top edges with both hands, making sure your thumbs and fingers are evenly spaced. Keep your back straight, chest up and core engaged, and stand up with the plate, keeping it close to your body. Lower the plate back down to the ground, keeping control and maintaining good posture.","secondaryMuscles":["Hamstrings","Glutes"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":460,"name":"Plate Pinch Grip Row","equipment":"Plate","primaryMuscles":["Biceps","Lats","Forearms"],"difficulty":"Intermediate","grips":["Pinch","Grip"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-pinch-grip-row-front.mp4#t=0.1","howTo":"Make sure to keep your elbow close to your body and your core engaged throughout the movement. Bend forward at your hips while maintaining a flat back. Pull the plate toward your upper abdomen. Lower the weight in a controlled manner and repeat.","secondaryMuscles":["Lats"],"tertiaryMuscles":["Biceps"],"popularity":0},{"id":461,"name":"Machine Standing Calf Raises","equipment":"Machine","primaryMuscles":["Calves"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-machine-standing-calf-raises-front.mp4#t=0.1","howTo":"Adjust the machine in accordance with your height and place your shoulders underneath the padded lever. The balls of your feet should be supporting your weight on the calve block, your heels extending off of it. Extend your heels upwards while keeping your knees stationary, and pause at the contracted position. Slowly return to the starting position. Repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":462,"name":"Machine Seated Calf Raises","equipment":"Machine","primaryMuscles":["Calves"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-machine-seated-calf-raise-front.mp4#t=0.1","howTo":"Get comfortable on the machine, then place your lower thighs beneath the padded lever. Place your toes and the balls of your feet onto the foot supports. Prevent the weight from slipping forward by gripping the handles, and release the safety bar. Lower the weight until your calves are extended. Push your heels up to lift the padded lever and hold the contracted position, then slowly lower back down to the starting position. Repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":463,"name":"Kettlebell Single Leg Calf Raise","equipment":"Kettlebell","primaryMuscles":["Calves"],"difficulty":"Beginner","grips":["Overhand,","Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-single-leg-calf-raises-front.mp4#t=0.1","howTo":"Standing straight with a kettlebell in one hand, lift the same foot as the side without the kettlebell off the floor. Raise your heel upwards while keeping your knees stationary. Pause when your heels are fully extended and then slowly return to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":464,"name":"Kettlebell Calf Raise","equipment":"Kettlebell","primaryMuscles":["Calves"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-calf-raises-front.mp4#t=0.1","howTo":"Standing straight with a kettlebell in each hand, raise your heels upwards while keeping your knees stationary. Pause when your heels are fully extended and then slowly return to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":465,"name":"Kettlebell Seated Calf Raise","equipment":"Kettlebell","primaryMuscles":["Calves"],"difficulty":"Beginner","grips":["Overhand,","Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-seated-calf-raises-front.mp4#t=0.1","howTo":"Sitting comfortably on a chair with your core stomach muscles engaged, place your feet on the floor. Place the kettlebell on your legs, just above the knees and raise your heels upwards off the floor. Pause when your heels are fully extended and then slowly return to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":466,"name":"Calves Stretch Variation Three","equipment":"Stretch","primaryMuscles":["Calves"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-calves-stretch-variation-3-front.mp4#t=0.1","howTo":"Balance the balls of your feet on the platform, leaning forward to use the wall to assist with balance. Engage your calves so that your feet are flat before beginning the stretch. Lower the heels of your feet towards the ground and pause, then push through the balls of your feet like you are standing tip toe, pausing at the apex of the stretch. Repeat as necessary.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":467,"name":"Calves Stretch Variation Two","equipment":"Stretch","primaryMuscles":["Calves"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-calves-stretch-variation-2-front.mp4#t=0.1","howTo":"With both feet flat on the ground, place one leg in front of your shoulder, your other leg should mirror this position behind your other shoulder. In the starting position both of your knees should be straight. Place the palms of your hands against the wall at shoulder height in front of you, lean towards the wall and bend your front leg at the knee while keeping your back leg straight. Pause at the apex of the stretch and return to the starting position. Switch the position of your legs and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":468,"name":"Calves Stretch Variation One","equipment":"Stretch","primaryMuscles":["Calves"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-calves-stretch-variation-1-front.mp4#t=0.1","howTo":"Place the ball of your foot against the wall with your heel on the ground. Place your hands on the wall in front of your shoulders. Keeping your knee straight, slowly lean towards the wall, pause for a few seconds when you feel the stretch extending through your calf muscle. Return to the starting position, and repeat the stretch with your other leg.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":469,"name":"Tip Toe Walking","equipment":"Bodyweight","primaryMuscles":["Calves"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-tip-toe-walking-front.mp4#t=0.1","howTo":"Point your toes into the floor. Slowly walk forwards and backward Keep your heels in the air as long as possible while walking. It may be beneficial to do this last at the end of your workout.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":470,"name":"Calf Raises","equipment":"Bodyweight","primaryMuscles":["Calves"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-calve-raise-front.mp4#t=0.1","howTo":"Balance on the balls of your feet on the platform or plates, leaning forward to use the wall to assist with balance. Lower the heels of your feet towards the ground and pause, then push through the balls of your feet like you are standing tip toe, pausing at the apex of the motion. Repeat as necessary.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":25},{"id":471,"name":"Walking Calf Raises","equipment":"Bodyweight","primaryMuscles":["Calves"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-calve-raise-walk-front.mp4#t=0.1","howTo":"Walk forward and push your toe into the ground Lift you heel off the ground each step and tense your calf muscle Repeat on each leg and walk forward slowly","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":472,"name":"Barbell Calf Raises","equipment":"Barbell","primaryMuscles":["Calves"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-calve-raise-front.mp4#t=0.1","howTo":"Place the bar on your back Start with feet flat on the ground Extend your heels upwards while keeping your knees stationary, and pause at the contracted position. Slowly return to the starting position. Repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":473,"name":"Cable Calve Raise","equipment":"Cable","primaryMuscles":["Calves"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-calve-raise-front.mp4#t=0.1","howTo":"Use a straight bar or ez bar attachment with the cable set all the way to the bottom. Walk a few steps back. Pull your heels straight up until you feel a contraction in your calves and then back to original position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":474,"name":"Band Calf Raise","equipment":"Band","primaryMuscles":["Calves"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-calve-raise-front.mp4#t=0.1","howTo":"Attach band to a low anchor point. Take a few steps away until the band is taut. Lean back slightly. Raise your heels straight up and down","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":475,"name":"Dumbbell Calf Raise","equipment":"Dumbbell","primaryMuscles":["Calves"],"difficulty":"Beginner","grips":["Overhand,","Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-calf-raise-front.mp4#t=0.1","howTo":"Stand tall with your feet on the ground. You can put the the balls of your feet on top of a plate to extend the range of motion. Imagine you have a string attached to your heels and pull your heels up toward the ceiling.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":476,"name":"Barbell Calf Jump","equipment":"Barbell","primaryMuscles":["Calves"],"difficulty":"Advanced","grips":["None"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-calf-jump-front.mp4#t=0.1","howTo":"Stand with your feet shoulder-width apart and your knees slightly bent. Shift your weight onto the balls of your feet and raise stay flat footed. Using your calf muscles, mimic a jumping motion but don\'t leave the floor. Explode onto your tip toes and hold for a second. Bring your heels back to the floor then initiate the next rep.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":477,"name":"Barbell Seated Calf Raise","equipment":"Barbell","primaryMuscles":["Calves"],"difficulty":"Beginner","grips":["Overhand,","Underhand,","Mixed"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-seated-calf-raise-front.mp4#t=0.1","howTo":"Start by sitting on a bench with a barbell resting on your knees. Your feet should be flat on the ground, about hip-width apart. Place your hands on the barbell for support, and lift your heels off the ground. Hold this position for a moment, then slowly lower your heels back to the ground.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":478,"name":"Barbell Toes Up Calf Raise","equipment":"Barbell","primaryMuscles":["Calves"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-toes-up-calf-raise-front.mp4#t=0.1","howTo":"Begin by standing on a raised surface (such as a step or box) with the balls of your feet on the edge of the surface and your heels hanging off. Hold a barbell across your upper back and shoulders, using an overhand grip. Keeping your core engaged and your back straight, push through the balls of your feet to raise your heels up as high as you can. Lower your heels back down to the starting position, allowing your calves to stretch.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":479,"name":"Dumbbell Seated Calf Raise","equipment":"Dumbbell","primaryMuscles":["Calves"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-seated-calf-raise-front.mp4#t=0.1","howTo":"Start by sitting on a bench with your feet shoulder-width apart and a dumbbell in each hand placed on each leg. From this starting position, raise your heels as high as you can by pushing up through your toes. Slowly lower your heels back down to the starting position, and repeat for the desired number of repetitions.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":480,"name":"TRX Calf Raise","equipment":"TRX","primaryMuscles":["Calves"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-calf-raise-front.mp4#t=0.1","howTo":"Hold the TRX straps under your arms and the handles in your armpits. Lean forward against the straps. Keep your body straight and initiate the calf raise by raising your heels off the ground.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":481,"name":"Crunches","equipment":"Bodyweight","primaryMuscles":["Abdominals"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-crunch-front.mp4#t=0.1","howTo":"Lay flat on your back with your knees bent and your feet flat on the ground, about a foot from your lower back. Place your fingertips on your temples with your palms facing out. Draw your belly into the base of your spine to engage the muscles, then raise your head and shoulders off the floor. Return to starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":45},{"id":482,"name":"Laying Leg Raises","equipment":"Bodyweight","primaryMuscles":["Abdominals"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-leg-raises-front.mp4#t=0.1","howTo":"Lay on your back with your arms palms down on either side. Keep your legs together and as straight as possible. Slowly raise your legs to a 90° angle, pause at this position, or as high as you can reach your legs, and then slowly lower your legs back down. Duration of these movements should be slow so that you do not utilize momentum, enabling you to get the most out of the exercise.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":483,"name":"Machine Roll Outs","equipment":"Machine","primaryMuscles":["Abdominals"],"difficulty":"Intermediate","grips":"Overhand","mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-machine-roll-outs-front.mp4#t=0.1","howTo":"Hold the Ab Roller with both hands and kneel on the floor with your feet up and crossed. Slowly roll the ab roller straight forward, stretching your body into a straight position. After a pause at the stretched position, start pulling yourself back to the starting position. This should be a slow and controlled movement.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":484,"name":"Kettlebell Situp","equipment":"Kettlebell","primaryMuscles":["Abdominals"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-situp-front.mp4#t=0.1","howTo":"Lay flat on your back with straight legs and hold the kettle bell above your chest at arms length. Draw your belly into the base of your spine to engage the muscles, then raise your head and shoulders off the floor with the kettlebell raised at arms length above your chest. Return to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":485,"name":"Abdominals Stretch Variation Four","equipment":"Stretch","primaryMuscles":["Abdominals"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-abdominals-stretch-variation-4-front.mp4#t=0.1","howTo":"Lay on a ball or a Bosu ball with your feet firmly planted on the floor. Lean all the way back until you feel a stretch in your abdomen. Crunch upwards and hold for a 1-2 count. Slowly return to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":486,"name":"Abdominals Stretch Variation Two","equipment":"Stretch","primaryMuscles":["Abdominals","Obliques"],"difficulty":"Beginner","grips":["None"],"mechanic":"Compound","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-abdominals-stretch-variation-2-front.mp4#t=0.1","howTo":"Stand upright. Reach with both hands upwards until you can interlock your fingers. With your hands above your head, lean back until a stretch is felt in the abdominals.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":487,"name":"Abdominals Stretch Variation One","equipment":"Stretch","primaryMuscles":["Abdominals"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-abdominals-stretch-variation-1-front.mp4#t=0.1","howTo":"Lay on your stomach on the floor with your forearms flat on the ground. Extend your elbows and push your upper body upwards. Push your upper body upwards until you feel a stretch in your abs, then return to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":488,"name":"Forearm Plank","equipment":"Bodyweight","primaryMuscles":["Abdominals"],"difficulty":"Beginner","grips":["Overhand,","Neutral"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-forearm-plank-front.mp4#t=0.1","howTo":"Place forearms on the ground with your elbows bent at a 90° angle aligned beneath your shoulders, with your arms parallel at shoulder-width. Your feet should be together, with only your toes touching the floor. Lift your belly off the floor and form a straight line from your heels to the crown of your head and hold.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":489,"name":"Hanging Knee Raises","equipment":"Bodyweight","primaryMuscles":["Abdominals"],"difficulty":"Beginner","grips":["Overhand,","Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-hanging-knee-raises-front.mp4#t=0.1","howTo":"Grab the bar and hang, your body still and your legs straight. Slowly draw your knees up to your chest Once you have raised your knees as high as possible, lower your legs and repeat. Duration of these movements should be slow so that you do not utilize momentum, enabling you to get the most out of the exercise. Duration of these movements should be slow so that you do not utilize momentum, enabling you to get the most out of the exercise.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":3},{"id":490,"name":"Barbell Roll Outs","equipment":"Barbell","primaryMuscles":["Abdominals"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-rollout-front.mp4#t=0.1","howTo":"Hold the Barbell with both hands and kneel on the floor with your feet up Slowly roll the Barbell straight forward, stretching your body into a straight position. After a pause at the stretched position, start pulling yourself back to the starting position. This should be a slow and controlled movement.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":491,"name":"Cable Standing Crunch","equipment":"Cable","primaryMuscles":["Abdominals"],"difficulty":"Advanced","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-standing-crunch-front.mp4#t=0.1","howTo":"Use a double handle attachment and set the cable all the way to the top. Face away from the cable tower and walk a few steps forward. Push your hips back, and flex your abs. Return to the starting standing position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":492,"name":"Cable Kneeling Crunch","equipment":"Cable","primaryMuscles":["Abdominals"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-kneeling-crunch-front.mp4#t=0.1","howTo":"Use a double handle attachment and set the cable all the way to the top. Walk a few steps forward then fall into a kneeling position. Push your hips back and flex your abs, then push hips forward until in the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":493,"name":"Band Crunch","equipment":"Band","primaryMuscles":["Abdominals"],"difficulty":"Intermediate","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-crunch-front.mp4#t=0.1","howTo":"Place the band at the highest anchor point you have available. Grab both ends of the band and fall into a kneeling position. Push your hips back flexing at the spine. Squeeze your abs and then extend at the hips and spine back to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":494,"name":"Dumbbell Situp","equipment":"Dumbbell","primaryMuscles":["Abdominals"],"difficulty":"Intermediate","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-situp-front.mp4#t=0.1","howTo":"Lay flat on the ground with your spine neutral. Extend you arms so your fists are pointed at the ceiling. Sit-up by flexing your abs. Continue to reach for the ceiling for the entire rep.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":495,"name":"Dumbbell Plank Pullthrough","equipment":"Dumbbell","primaryMuscles":["Abdominals"],"difficulty":"Intermediate","grips":"Neutral","mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-plank-pullthrough-front.mp4#t=0.1","howTo":"Get into a plank position. Either from your knees or toes. Start with the DB by your right hand. Reach with your left and pull the dumbbell to your left arm. Then repeat with the right.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":496,"name":"Barbell Situp","equipment":"Barbell","primaryMuscles":["Abdominals"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-situp-front.mp4#t=0.1","howTo":"Hold the bar with a slightly wider than shoulder width grip. Push the bar up toward the ceiling and maintain that elbow extension. Flex your abs and sit-up. Aim to get your torso vertical while maintaining the barbell overhead.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":497,"name":"Long Lever Plank","equipment":"Bodyweight","primaryMuscles":["Abdominals"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-long-lever-plank-front.mp4#t=0.1","howTo":"Start in a hand plank position and walk your hands further out until your ears are between your biceps. Hold in this position for the allotted amount of time. Make sure you keep a flat back for the whole set.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":498,"name":"Hand Plank","equipment":"Bodyweight","primaryMuscles":["Abdominals"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-hand-plank-side.mp4#t=0.1","howTo":"Start in a kneeling position with your hands planted on the ground. Pick your knees up off the ground. Hold in this position with a flat back.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":499,"name":"Hollow Hold","equipment":"Bodyweight","primaryMuscles":["Abdominals"],"difficulty":"Advanced","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-hollow-hold-front.mp4#t=0.1","howTo":"Lay flat on the ground with your arms extended over head. Pick your upper back and your legs off the ground. Your body should be in a banana shape. Hold in this position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":500,"name":"Dumbbell Hollow Hold","equipment":"Dumbbell","primaryMuscles":["Abdominals"],"difficulty":"Advanced","grips":["Overhand,","Neutral"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-hollow-hold-front.mp4#t=0.1","howTo":"Lay flat on the ground with a dumbbell overhead. Pull your upper back and legs off the ground. Make a banana shape with your body. The dumbbell should be held in your hands and your ears should be between your biceps.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":501,"name":"Mountain Climber","equipment":"Bodyweight","primaryMuscles":["Abdominals"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-mountain-climber-front.mp4#t=0.1","howTo":"To perform a bodyweight mountain climber, start in a plank position with your hands placed directly under your shoulders. Bring your right knee towards your chest, keeping your foot close to your hand. Quickly switch legs, bringing your left knee towards your chest. Continue this movement, alternating legs, at a quick pace for a set amount of time or repetitions.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":4},{"id":502,"name":"Plate Situp","equipment":"Plate","primaryMuscles":["Abdominals"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-situp-front.mp4#t=0.1","howTo":"Start by lying on your back on a mat with your legs bent and feet flat on the ground. Hold a weight plate over your head with both hands, making sure to keep your arms straight. Engage your core and use your abdominal muscles to sit up, keeping the weight plate towards the ceiling.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":503,"name":"Weighted Forearm Plank","equipment":"Bodyweight","primaryMuscles":["Abdominals"],"difficulty":"Intermediate","grips":["None"],"mechanic":"Compound","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-weighted-forearm-plank-front.mp4#t=0.1","howTo":"Get into a kneeling position with both forearms pressed into the ground. Place a weight plate on your back (or have a partner do it for you). Hold the plank for the allotted amount of time.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":504,"name":"Weighted Hand Plank","equipment":"Bodyweight","primaryMuscles":["Abdominals"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-weighted-hand-plank-front.mp4#t=0.1","howTo":"Start in a kneeling position with your hands planted on the ground. Place a weight plate on your back or have a friend do it for you. Pick your knees up off the ground. Hold in this position with a flat back.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":505,"name":"Plate Hollow Hold","equipment":"Plate","primaryMuscles":["Abdominals"],"difficulty":"Advanced","grips":["Neutral"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-weighted-hollow-hold-front.mp4#t=0.1","howTo":"Lay flat on the ground with your arms extended over head holding a weight plate. Pick your upper back and your legs off the ground. Your body should be in a banana shape.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":506,"name":"Dumbbell Crunch","equipment":"Dumbbell","primaryMuscles":["Abdominals"],"difficulty":"Intermediate","grips":["Underhand"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-crunch-front.mp4#t=0.1","howTo":"Start by lying flat on your back with your feet flat on the floor and your knees bent. Hold a dumbbell over your clavicle. Engage your core muscles and lift your torso off the floor until your shoulders are a few inches off the ground. Lower yourself back down to the starting position, but avoid resting completely on the floor between reps.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":507,"name":"Plank IYTW","equipment":"Bodyweight","primaryMuscles":["Shoulders","Abdominals"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-plank-iytw-front.mp4#t=0.1","howTo":"Start in a plank position. Hold one dumbbell. Raise the dumbbell straight out in front of you (I), at a 45 degree angle (Y), out to the side (T), and then bend at the elbow while raising (W). Going through IYTW counts as one rep. Make sure to keep your hips stable. If you\'re unable to, try performing this exercise from the knees.","secondaryMuscles":["Shoulders"],"tertiaryMuscles":null,"popularity":0},{"id":508,"name":"Dumbbell Suitcase Crunch","equipment":"Dumbbell","primaryMuscles":["Abdominals"],"difficulty":"Advanced","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-suitcase-crunch-front.mp4#t=0.1","howTo":"Lay flat on the ground with a dumbbell. Point the soles of your shoes at the ceiling as well as the dumbbell. Reach for your feet with the dumbbell before bringing your spine back to the floor.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":509,"name":"TRX Ab Rollout","equipment":"TRX","primaryMuscles":["Lats","Abdominals"],"difficulty":"Advanced","grips":["Overhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-ab-rollout-front.mp4#t=0.1","howTo":"Grasp the TRX handles with both hands, keeping your arms extended and your shoulders away from your ears. Keep your abs engaged, roll forward onto your toes, and extend your arms in front of you. Slowly lower your body down to the ground, keeping your arms straight and your abs engaged. When your head gets between your arms, pause for a moment and then use your abs to pull your body back up to the starting position.","secondaryMuscles":["Lats"],"tertiaryMuscles":["Lower back"],"popularity":0},{"id":510,"name":"TRX Forearm Plank","equipment":"TRX","primaryMuscles":["Abdominals"],"difficulty":"Beginner","grips":["Neutral,","None"],"mechanic":"Compound","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-forearm-plank-front.mp4#t=0.1","howTo":"Lie face down on the ground and place your forearms on the ground directly under your shoulders. With your feet in the stirrups, kick both feet into the TRX straps and hold the handles above your head. Tighten your abs, glutes, and legs to form a straight line from your head to your feet.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":511,"name":"TRX Hand Plank","equipment":"TRX","primaryMuscles":["Abdominals"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-hand-plank-front.mp4#t=0.1","howTo":"Start by facing away from the TRX straps and placing your feet in the TRX handles with your palms on the ground. Lift your knees off the ground to begin the set. Engage your core and maintain this position for the desired amount of time, holding a steady plank.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":512,"name":"TRX Kneeling Ab Rollout","equipment":"TRX","primaryMuscles":["Lats","Abdominals"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-kneeling-body-saw-front.mp4#t=0.1","howTo":"Begin in a kneeling position with the TRX straps adjusted to mid-calf length. Grasp the TRX handles with both hands, keeping your arms extended and your shoulders away from your ears. Keep your abs engaged, roll forward onto your toes, and extend your arms in front of you. Slowly lower your body down to the ground, keeping your arms straight and your abs engaged.","secondaryMuscles":["Lats"],"tertiaryMuscles":null,"popularity":0},{"id":513,"name":"TRX Knee Tuck","equipment":"TRX","primaryMuscles":["Abdominals"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-knee-tuck-front.mp4#t=0.1","howTo":"Place your feet in the TRX stirrups and get in to a hand plank position. Pull your knees to your chest and flex your abs.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":514,"name":"TRX Mountain Climber","equipment":"TRX","primaryMuscles":["Abdominals"],"difficulty":"Beginner","grips":["None"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-mountain-climber-front.mp4#t=0.1","howTo":"Start in a plank position with the TRX straps adjusted to mid-calf length. Place your feet in the TRX stirrups. Keep your abs engaged, and bring one knee towards your chest while keeping the other leg extended behind you. Switch legs, bringing the opposite knee towards your chest while keeping your abs engaged and your back straight.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":515,"name":"TRX Pike","equipment":"TRX","primaryMuscles":["Abdominals"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-pike-front.mp4#t=0.1","howTo":"Place your feet in the stirrups and get in to a plank position. Pull your hips straight up toward the ceiling. Lower your hips until you\'re back in a plank position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":516,"name":"Machine 45 Degree Back Extension","equipment":"Machine","primaryMuscles":["Lower back"],"difficulty":"Intermediate","grips":["None"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-machine-back-extension-front.mp4#t=0.1","howTo":"Position your thighs on the padding and hook your feet on the platform supports. Keeping your back straight, slowly bend at your waist until your legs and back are at a 45° angle. Slowly raise your body to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":517,"name":"Lower back Stretch Variation Four","equipment":"Stretch","primaryMuscles":["Lower back"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-lower-back-stretch-variation-4-front.mp4#t=0.1","howTo":"Lay flat against the ground with your knees at an angle and your feet flat against the floor. Grab your legs just below the knees, and pull your legs towards your chest. Pause at the apex of the stretch, then return to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":518,"name":"Lower back Stretch Variation Three","equipment":"Stretch","primaryMuscles":["Lower back"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-lower-back-stretch-variation-3-front.mp4#t=0.1","howTo":"Lay on your back with your arms at either side. Raise your knees so that they are pointing straight towards the ceiling. Keeping your legs pressed together, rotate your hips to either side. Repeat this motion as necessary.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":519,"name":"Lower back Stretch Variation Two","equipment":"Stretch","primaryMuscles":["Lower back"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-lower-back-stretch-variation-2-front.mp4#t=0.1","howTo":"Lay flat on the floor with your arms at either side. With one leg, hook one foot under the joint of your other leg. Rotate your hips so that your knees are pointing sideways, keeping your hooked leg flat against the floor. Pause at the apex of the stretch and repeat with your other leg.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":520,"name":"Lower back Stretch Variation One","equipment":"Stretch","primaryMuscles":["Lower back"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-lower-back-stretch-variation-1-front.mp4#t=0.1","howTo":"Sit on the floor with the tops of your feet pointed and flat on the ground. Move your arms out in front of you in the diving position, placing your palms flat against the ground. With your arms fully extended, rest your buttocks on the heels of your feet, you can crawl your hands forward to extend the stretch if need be. Hold the extended position for a few seconds, and return to starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":521,"name":"Supermans","equipment":"Bodyweight","primaryMuscles":["Lower back"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-superman-front.mp4#t=0.1","howTo":"Lie face down on the floor with your arms fully extended in front of you. Simultaneously raise your arms, legs and chest off of the floor and hold the position. Slowly lower your arms, legs and chest back to the starting position. Repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":3},{"id":522,"name":"Plate Deadlift","equipment":"Plate","primaryMuscles":["Lower back"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-deadlift-front_u46uJRs.mp4#t=0.1","howTo":"Stand with feet hip-width apart, the plate in front of the feet, and the knees slightly bent. Bend the hips and knees to grip the plate with palms facing the body. Keeping the back straight, stand up while lifting the plate off the ground. Return the plate back to the starting position by bending the hips and knees, keeping control of the plate.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":523,"name":"Dumbbell Superman","equipment":"Dumbbell","primaryMuscles":["Lower back"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-superman-front.mp4#t=0.1","howTo":"Lay flat on the ground on your stomach with your arms extended overhead. Hold a dumbbell with a neutral grip. Lift your legs and chest off the ground simultaneously and hold for a 1 count at the top. Relax your lower back and lower your legs and chest back to the floor.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":524,"name":"Kettlebell Incline Shrug","equipment":"Kettlebell","primaryMuscles":["Traps","Traps (mid-back)"],"difficulty":"Intermediate","grips":["Overhand"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-incline-shrug-front.mp4#t=0.1","howTo":"Leaning across the back section of the bench, with feet firmly on the floor and with arms hanging to the sides. Holding the kettlebell in both hands engage your shoulder blades, as if you are trying to touch them together. Release the shrug.","secondaryMuscles":["Traps"],"tertiaryMuscles":null,"popularity":0},{"id":525,"name":"Traps mid back Stretch Variation Two","equipment":"Stretch","primaryMuscles":["Traps","Traps (mid-back)"],"difficulty":"Beginner","grips":["None"],"mechanic":"Compound","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-traps-mid-back-stretch-variation-2-front.mp4#t=0.1","howTo":"Sit on the ground and lay one leg flat and the other over the top. Hold your leg with the same side arm and slowly rotate your hips and back. Hold at the peak of the stretch, then slowly return to starting position. Switch sides and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":526,"name":"Traps mid back Stretch Variation One","equipment":"Stretch","primaryMuscles":["Traps","Traps (mid-back)"],"difficulty":"Beginner","grips":["None"],"mechanic":"Compound","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-traps-mid-back-stretch-variation-1-front.mp4#t=0.1","howTo":"Repeat with your other arm. Stand up with your feet shoulder width apart. Place one arm across the front of your chest at shoulder height, press the forearm of your other arm above the elbow, hooking the stretching arm with your hand. Press the arm until it is straight and rotate your upper torso to engage the stretch even deeper.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":527,"name":"Cable Silverback Shrug","equipment":"Cable","primaryMuscles":["Traps","Traps (mid-back)"],"difficulty":"Beginner","grips":["Overhand"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-silverback-shrug-side.mp4#t=0.1","howTo":"Use a bar attachment. Cable should be set all the way to the bottom. Stand up with the attachment in hand, walk a couple of steps back make sure you are standing upright and not leaning backwards. Retract your shoulder blades and then protract to return to the starting position.","secondaryMuscles":["Traps"],"tertiaryMuscles":null,"popularity":0},{"id":528,"name":"Dumbbell Laying Silverback Shrug","equipment":"Dumbbell","primaryMuscles":["Traps","Traps (mid-back)"],"difficulty":"Intermediate","grips":["Overhand,","Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-laying-silverback-shrug-front.mp4#t=0.1","howTo":"Lay on an incline bench with your arms hanging freely. Pull your shoulder blades back toward the ceiling.","secondaryMuscles":["Traps"],"tertiaryMuscles":null,"popularity":0},{"id":529,"name":"Dumbbell Silverback Shrug","equipment":"Dumbbell","primaryMuscles":["Traps","Traps (mid-back)"],"difficulty":"Intermediate","grips":"Overhand","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-silverback-shrug-front.mp4#t=0.1","howTo":"Hinge forward slightly at the hips. Make sure to keep a flat back. Let your arms hang in front of you. Let your scapula protract, and then retract them. Imagine you have a pencil in your mid-back and squeeze it between your shoulder blades.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":530,"name":"Band Horizontal Shrug","equipment":"Band","primaryMuscles":["Traps","Shoulders","Traps (mid-back)"],"difficulty":"Advanced","grips":"Overhand","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-horizontal-shrug-front.mp4#t=0.1","howTo":"Anchor the band at shoulder height. Take a few steps away until the band is taut. Retract your shoulder blades straight back in schools. Then protract to the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":531,"name":"Barbell Landmine Side Bend","equipment":"Barbell","primaryMuscles":["Obliques"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-landmine-side-bend-front.mp4#t=0.1","howTo":"Stand straight and hold the end of the Barbell Keep your hips and shoulders facing forward, bend to one side slowly Return to the upright position. Switch hands and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":532,"name":"Dumbbell Wood Chopper","equipment":"Dumbbell","primaryMuscles":["Obliques"],"difficulty":"Advanced","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-wood-chopper-front.mp4#t=0.1","howTo":"Stand with a shoulder width stance. Begin with the dumbbell near one of your quads. Rotate at your upper spine to engage the obliques. You can pivot your back foot to keep from generating too much torque at the knee.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":533,"name":"Kettlebell Wood Chopper","equipment":"Kettlebell","primaryMuscles":["Obliques"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-wood-chopper-front.mp4#t=0.1","howTo":"Stand with feet slightly wider than shoulder width apart and hold the kettle bell with both hands against your hip. Keeping your arms straight, swing the kettlebell upwards and across your body towards your shoulder, raising the kettlebell to head height rotating your hips as you do so. Return to the starting position and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":534,"name":"Cable Wood Chopper","equipment":"Cable","primaryMuscles":["Obliques"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-woodchopper-front.mp4#t=0.1","howTo":"Set the cable at about nipple level. Use a handle attachment. Face sideways, then rotate your torso with your arms extended against the resistance. After completing your given number of reps, face the opposite direction and repeat.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":535,"name":"Band Wood Chopper","equipment":"Band","primaryMuscles":["Obliques"],"difficulty":"Advanced","grips":"Neutral","mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-wood-chopper-front.mp4#t=0.1","howTo":"Set the band at chest level. Face sideways, then rotate your torso with your arms extended against the resistance.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":536,"name":"Dumbbell Russian Twist","equipment":"Dumbbell","primaryMuscles":["Abdominals","Obliques"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-russian-twist-front.mp4#t=0.1","howTo":"Sit on the floor and flex your knees and hips to a 90 degree angle. Your feet should be hovering off the ground. (If that\'s too hard start with heels on the floor) Rotate your upper spine to engage your obliques.","secondaryMuscles":["Abdominals"],"tertiaryMuscles":null,"popularity":0},{"id":537,"name":"Kettlebell Russian Twist","equipment":"Kettlebell","primaryMuscles":["Abdominals","Obliques"],"difficulty":"Beginner","grips":"Neutral","mechanic":"Compound","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-russian-twist-front.mp4#t=0.1","howTo":"Sit on the floor with your legs bent, knees together and feet raised slightly off the floor. Starting on one side and sitting up straight with your core muscles engaged, lift the kettlebell off the floor with both hands and bring it across your body to the other side, rotating your chest towards the floor as you do so. Tap the kettlebell lightly on the floor and bring the kettlebell back across your body to the starting position, rotating your chest towards the floor. Repeat, keeping the legs bent and feet raised throughout the exercise.","secondaryMuscles":["Abdominals"],"tertiaryMuscles":null,"popularity":1},{"id":538,"name":"Band Pallof Press","equipment":"Band","primaryMuscles":["Obliques"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-band-paloff-press-front.mp4#t=0.1","howTo":"Place the band at an anchor point that is shoulder height. Take a few steps away until the band is taut. Start with your fingers interlocked around the band and your fists connected to your chest. Extend at the elbows pressing the band away from your body until your elbows are fully extended.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":539,"name":"Kettlebell Windmill","equipment":"Kettlebell","primaryMuscles":["Abdominals","Obliques"],"difficulty":"Advanced","grips":["Overhand,","Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-kettlebell-windmill-front.mp4#t=0.1","howTo":"Stand with feet slightly wider than shoulder width apart. Hold the kettlebell in one hand and extend your arm above your head. Keeping your legs straight and the kettlebell above your head, lower the relaxed arm towards the ground, twisting your body towards the side of the raised arm. Return to the starting potion, tilt your pelvis forward and repeat.","secondaryMuscles":["Abdominals"],"tertiaryMuscles":null,"popularity":3},{"id":540,"name":"Cable Pallof Press","equipment":"Cable","primaryMuscles":["Obliques"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-cable-paloff-press-side.mp4#t=0.1","howTo":"Use a handle attachment, set the cable at nipple level, walk a few steps away, and face sideways. Start with both hands on the handle and your fists against your chest. Press the handle forward until your elbows are fully extended, then pull the handle back to your chest.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":541,"name":"Abdominals Stretch Variation Three","equipment":"Stretch","primaryMuscles":["Abdominals","Obliques"],"difficulty":"Beginner","grips":["None"],"mechanic":"Compound","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-abdominals-stretch-variation-3-front.mp4#t=0.1","howTo":"Reach up with your left arm and then lean slowly to the right. Lean until a stretch is felt in the obliques. Stand upright. After completing the desired amount of reps with the left arm, switch to the right arm and lean to the left.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":542,"name":"Bodyweight Russian Twist","equipment":"Bodyweight","primaryMuscles":["Abdominals","Obliques"],"difficulty":"Intermediate","grips":["None"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-russian-twist-front.mp4#t=0.1","howTo":"Hover your heels just off the ground. Stick your chest out and maintain a flat back. Make all the movement happen at your mid and upper spine. Point your chest to the left, then rotate at the spine until your chest is pointed right.","secondaryMuscles":["Abdominals"],"tertiaryMuscles":null,"popularity":0},{"id":543,"name":"Side Plank Up Down","equipment":"Bodyweight","primaryMuscles":["Obliques"],"difficulty":"Intermediate","grips":["None"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-side-plank-up-down-front.mp4#t=0.1","howTo":"Start with your elbow and hip on the ground. Either neutral fist or flat hand on the ground. Begin in a side plank position, and then drop your hips to the floor. Pull your hips back to the ceiling to finish the rep.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":544,"name":"Side Plank Reach Through","equipment":"Bodyweight","primaryMuscles":["Obliques"],"difficulty":"Advanced","grips":["None"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-side-plank-reach-through-front.mp4#t=0.1","howTo":"Begin in an elbow side plank position. Reach for the ceiling with your off hand. Rotate at the mid and upper spine and reach through the open space between the floor and your torso. Reach backwards, and then rotate back into the starting position.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":545,"name":"Elbow Side Plank","equipment":"Bodyweight","primaryMuscles":["Obliques"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-elbow-side-plank-front.mp4#t=0.1","howTo":"Press your elbow into the floor. Pick your hips up off the ground and maintain this position for the allotted amount of time. Make sure you don\'t let your chest fall forward or backward.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":546,"name":"Hand Side Plank","equipment":"Bodyweight","primaryMuscles":["Obliques"],"difficulty":"Intermediate","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-bodyweight-hand-side-plank-front.mp4#t=0.1","howTo":"Press your hand into the ground and pick up your hip off the ground. Open your chest and maintain this position for the allotted amount of time.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":547,"name":"Barbell Suitcase Deadlift","equipment":"Barbell","primaryMuscles":["Hamstrings","Glutes","Obliques"],"difficulty":"Advanced","grips":"Underhand","mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-barbell-suitcase-deadlift-front.mp4#t=0.1","howTo":"Begin by standing with your feet hip-width apart and holding a barbell at one side of your body, with your palms facing your thighs. Keeping your core engaged and your back straight, bend at the hips and knees to lower the barbell down towards the ground. As the barbell reaches the ground, use your legs and glutes to push through your heels and extend your hips and knees to raise your body back to the starting position. Repeat the movement for the desired number of reps, then switch sides and repeat the exercise with the barbell on the opposite side of your body.","secondaryMuscles":["Lower back"],"tertiaryMuscles":["Forearms"],"popularity":1},{"id":548,"name":"Dumbbell Half Kneeling Wood Chopper","equipment":"Dumbbell","primaryMuscles":["Abdominals","Obliques"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-half-kneeling-wood-chopper-front.mp4#t=0.1","howTo":"Take a half kneeling position. Start with the dumbbell by your knee on the side of the kneeling leg. Rotate at the upper spine, holding the dumbbell away from your body with nearly extended elbows.","secondaryMuscles":["Abdominals"],"tertiaryMuscles":null,"popularity":0},{"id":549,"name":"Dumbbell Kneeling Wood Chopper","equipment":"Dumbbell","primaryMuscles":["Obliques"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-kneeling-wood-chopper-front.mp4#t=0.1","howTo":"Start in a kneeling position with your shoulder blades pulled back. The dumbbell should begin by one of your hips. Rotate at the spine and bring the dumbbell from your hip, 180 degrees around your body. The dumbbell should land at eye level.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":550,"name":"Dumbbell Overhead Side Bend","equipment":"Dumbbell","primaryMuscles":["Obliques"],"difficulty":"Advanced","grips":["Overhand,","Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-overhead-side-bend-front.mp4#t=0.1","howTo":"Start by standing with your feet shoulder-width apart and holding a dumbbell overhead. From this starting position, bend to the side as far as you can while keeping your feet planted and your core engaged.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":551,"name":"Dumbbell Side Plank Up Down","equipment":"Dumbbell","primaryMuscles":["Obliques"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Push","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-side-plank-up-down-front.mp4#t=0.1","howTo":"Start by lying on your side with your feet stacked on top of each other and a dumbbell on your hip. Place your bottom elbow on the ground beneath your shoulder and engage your core to raise your hips off the ground. Your hips will do all the moving. Think, \\"hips up, hips down.\\"","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":552,"name":"Dumbbell Hand Side Plank","equipment":"Dumbbell","primaryMuscles":["Obliques"],"difficulty":"Intermediate","grips":["Overhand,","Neutral"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-weighted-hand-side-plank-front.mp4#t=0.1","howTo":"Start by lying on your side with your feet stacked on top of each other and a dumbbell on your hip. Place your bottom hand on the ground beneath your shoulder and engage your core to raise your hips off the ground. From this starting position, hold the side plank position for the desired amount of time, making sure to keep your body straight and your hips level.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":553,"name":"Dumbbell Elbow Side Plank","equipment":"Dumbbell","primaryMuscles":["Obliques"],"difficulty":"Beginner","grips":["None"],"mechanic":"Isolation","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-weighted-side-plank-front.mp4#t=0.1","howTo":"Press your elbow into the floor, holding a dumbbell on your hip. Pick your hips up off the ground and maintain this position for the allotted amount of time.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":554,"name":"Plate Russian Twist","equipment":"Plate","primaryMuscles":["Abdominals","Obliques"],"difficulty":"Intermediate","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-russian-twist-front.mp4#t=0.1","howTo":"Start by sitting on the floor with your knees bent and feet flat on the ground Engage your core muscles by pulling your belly button toward your spine. Slowly twist your upper body to the right, keeping your feet flat on the ground and your back straight. Hold for a second and then twist to the left, holding for another second.","secondaryMuscles":["Abdominals"],"tertiaryMuscles":null,"popularity":0},{"id":555,"name":"Plate Standing Twist","equipment":"Plate","primaryMuscles":["Obliques"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-standing-twist-front.mp4#t=0.1","howTo":"Stand with a plate extended away from your body. Elbows mostly extended. Rotate at the upper spine while keeping your lumbar spine in a neutral position. Do not let the plate go behind your body.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":556,"name":"Plate Wood Chopper","equipment":"Plate","primaryMuscles":["Obliques"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-plate-woodchopper-front.mp4#t=0.1","howTo":"Stand with a shoulder width stance. Begin with the plate near one of your quads. Rotate at your upper spine to engage the obliques. You can pivot your back foot to keep from generating too much torque at the knee.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":557,"name":"Dumbbell Long Lever Russian Twist","equipment":"Dumbbell","primaryMuscles":["Obliques"],"difficulty":"Advanced","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-long-lever-russian-twist-front.mp4#t=0.1","howTo":"Start by sitting on the floor with your knees bent and feet flat on the ground. Hold a dumbbell in both hands with your arms extended straight in front of you. Twist your torso to the right, bringing the dumbbell towards the ground, then return to the center. Repeat on the left side, twisting to the left and bringing the dumbbell towards the ground. Continue this twisting motion, alternating sides, for the desired number of repetitions. Keep your core engaged and avoid swinging your arms to generate momentum.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":558,"name":"Dumbbell Side Bend","equipment":"Dumbbell","primaryMuscles":["Obliques"],"difficulty":"Beginner","grips":["Neutral"],"mechanic":"Isolation","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-dumbbell-side-bend-front.mp4#t=0.1","howTo":"Stand with feet hip-width apart and place your right hand on the right hip. Hold a dumbbell with the left hand. Bend at the hips to the side. Make sure you don\'t start to lean forward to try and force a longer range of motion.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":1},{"id":559,"name":"TRX Forearm Side Plank","equipment":"TRX","primaryMuscles":["Obliques"],"difficulty":"Intermediate","grips":["Neutral,","None"],"mechanic":"Compound","force":"Hold","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-forearm-side-plank-front.mp4#t=0.1","howTo":"Lie on your side with your legs straight and your feet resting in the TRX foot cradles. Prop yourself up on your forearm and engage your core to maintain a straight line from your head to your feet.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0},{"id":560,"name":"TRX Oblique Crunch","equipment":"TRX","primaryMuscles":["Obliques"],"difficulty":"Intermediate","grips":["None"],"mechanic":"Compound","force":"Pull","video":"https://musclewiki.com/media/uploads/videos/branded/male-trx-oblique-crunch-front.mp4#t=0.1","howTo":"Place your feet in the TRX stirrups and get in to a hand plank position. Pull both knees to your right elbow. Extend your legs back to the starting position, then pull both knees to the left elbow.","secondaryMuscles":null,"tertiaryMuscles":null,"popularity":0}]');

